-- Poems batch 136
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e340dea8-13da-4084-82a7-10e4d851de88','聞西省賞酴醿芍藥戲成小詩奉簡泰之侍講舍人年兄并以丁香橄欖百枚助筵却求殘花數枝  其四','周必大','宋','宋诗','song-poetry','','[]','從來引玉即拋磚，自筆囊空百不堪。',32,'全唐诗/poet.song.143000.json','["從來引玉即拋磚，自筆囊空百不堪。", "頼得酒酣須茗飲，聊將青子助回甘。"]'),
('089ccfd0-3744-47a3-a6a2-e2b1f690792e','新鎮江通判蔡挽詞','周必大','宋','宋诗','song-poetry','','[]','計相聲名久不磨，慶餘豐報屬君多。',64,'全唐诗/poet.song.143000.json','["計相聲名久不磨，慶餘豐報屬君多。", "原鴒重遇非常主，庭鯉仍收最上科。", "但使家聲常燀赫，不辭官路獨蹉跎。", "仁人天豈惜眉壽，自要曾孫同逝波。"]'),
('a3f0d9c8-2383-4472-b16f-b8218bf895f5','次韻閻刑部才元楊梅','周必大','宋','宋诗','song-poetry','','[]','炎官傘照濤江紅，五月獻果明光宮。',96,'全唐诗/poet.song.143000.json','["炎官傘照濤江紅，五月獻果明光宮。", "越人一枝古所重，蜀無他楊譜則同。", "玄珠更將赤水浴，流火呈祥復王屋。", "不伴長安黑彈丸，殺吏驚人寒起粟。", "新詩字字含芳鮮，大書遺我敦同年。", "請君速訪天竺老，食白追繼仇池仙。"]'),
('46d4c3e2-0488-46a8-875a-4bab3daeb6f8','六曹長貳觀潮予以入直不預晡時大雷雨走筆戲蔡子平','周必大','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','雷轟萬鼓勒潮回，無復亭前雪作堆。',32,'全唐诗/poet.song.143000.json','["雷轟萬鼓勒潮回，無復亭前雪作堆。", "應爲尚書慳且澀，盲風怪雨一時來。"]'),
('e1865a68-2721-41e8-8767-30e46c687743','走筆答程泰之以簡問蓮社事','周必大','宋','宋诗','song-poetry','','[]','杏壇儼雅猶難考，蓮社荒唐孰肯知。',32,'全唐诗/poet.song.143000.json','["杏壇儼雅猶難考，蓮社荒唐孰肯知。", "好把鍾山爲儆鑑，瞿聃留作晚年師。"]'),
('751b8fc4-42ca-49d7-931e-e525fca7d7a8','次韻天官韓尚書七月十八日風雨中觀潮予內直不赴  其一','周必大','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','禁直惟聞漏鼓催，潮聲遥聽訝蛟雷。',32,'全唐诗/poet.song.143000.json','["禁直惟聞漏鼓催，潮聲遥聽訝蛟雷。", "忽傳傑句天邊得，如對洪濤海上來。"]'),
('e9ba5307-b7cf-41ea-acab-fb9885fd594b','次韻天官韓尚書七月十八日風雨中觀潮予內直不赴  其二','周必大','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','大筆真能挾風雨，小才何敢助涓埃。',32,'全唐诗/poet.song.143000.json','["大筆真能挾風雨，小才何敢助涓埃。", "古今奇觀須秋半，好約重銜伯雅杯。"]'),
('b8f863c5-5a25-4ba3-a4c5-858df8d9031f','程泰之下直某偶被宣鎖相遇于途既到玉堂讀所留佳句次韻爲謝','周必大','宋','宋诗','song-poetry','','[]','天街並踏軟紅塵，飛鞚交馳駭徼巡。',64,'全唐诗/poet.song.143000.json','["天街並踏軟紅塵，飛鞚交馳駭徼巡。", "椒殿敢期當制草，槐庭元擬用儒真。", "鬻方偶免冬龜手，適市深慚旦攫人。", "早夜祝公登相位，重霑潤筆乃無貧。"]'),
('0888b423-209f-4097-8183-4d8cc368c18f','慶東宮生辰二十韻','周必大','宋','宋诗','song-poetry','','[]','二聖仁無敵，元良敬有加。',240,'全唐诗/poet.song.143000.json','["二聖仁無敵，元良敬有加。", "一丁昌火運，三合聚皇家。", "帝子初朱芾，天孫更綠車。", "東儲今啟誦，重慶昔勛華。", "異表溫而厲，英辭正且葩。", "日三朝蠖濩，明兩照幽遐。", "周鮑吾何嗜，齊蒿爾自邪。", "金昭全粹質，玉裕絕纖瑕。", "唐範刊譌謬，丘經辨等差。", "處心宗淡泊，論樂鄙淫哇。", "摛藻書盈軸，穿楊箭列靫。", "共知文武備，頻拜聖神嘉。", "盤露清承掌，窗風冷度紗。", "佳辰蓂四葉，樂歲粟千秅。", "呈瑞芝生草，延年菊試花。", "震維春不老，鶴禁壽無涯。", "喜氣均三殿，恩頒出正衙。", "流香傳御酒，七寶簇宮茶。", "飣坐麟爲脯，堆盤棗勝瓜。", "子生同九月，魯國謾多誇。"]'),
('782d8a44-e80b-4e4d-a189-6b78f130eff6','洪景嚴樞密挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','兩制摛文壓縉紳，三吳耀武見經綸。',64,'全唐诗/poet.song.143000.json','["兩制摛文壓縉紳，三吳耀武見經綸。", "橋留震澤居無擾，舟濟滄溟捷有神。", "宥府嘉猷推乃后，陪都遺愛紀斯民。", "多才多藝無多壽，此理憑誰問大鈞。"]'),
('97048ae4-3710-4775-b121-c3c1857c5de0','洪景嚴樞密挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','召試曾叨對巨題，代言今忝繼前規。',64,'全唐诗/poet.song.143000.json','["召試曾叨對巨題，代言今忝繼前規。", "豐鍾霜響人何在，瓦釜雷鳴愧可知。", "滕駟啟城嗟有日，徐鷄醊酒恨無期。", "玉堂頼有綸章在，時展前篇慰所思。"]'),
('b5afb0f7-e23b-479b-8b2d-7712b0467015','送蔡迨赴桂陽令','周必大','宋','宋诗','song-poetry','','[]','工部詩題滿劍川，儀曹文筆照湖南。',160,'全唐诗/poet.song.143000.json','["工部詩題滿劍川，儀曹文筆照湖南。", "身行蜀棧曾幽討，舟掛吳帆又飽參。", "睎驥有心真自得，拔茅無術定誰慙。", "金蘭正好追英彥，蒲穀翻令試子男。", "縣古荒祠憐義帝，地靈勝槩憶蘇躭。", "冰臺小試醫民瘼，帛幅高張律吏貪。", "衛颯化行先禮教，茨充美政是耕蠶。", "故家遺俗今無幾，往行前言孰可談。", "鴻鴈峯高書莫繫，驪駒歌闋酒空酣。", "伊予已卜江湖隠，靈壽何時寄草菴。"]'),
('a8a9a920-c59e-4fac-8c4a-5719e749a1cc','丁酉二月二十日同部中諸公遊下竺御園坐枕流亭觀放閘桃花數萬點隨流而下繼至集芳亦禁峑也海棠滿山郁李遶檻殆不類人間世明日入部而桃花數枝伶俜窗外未時內直則海棠郁李各一株方開遂賦二絕句  其一','周必大','宋','宋诗','song-poetry','','[]','萬點紅隨雪浪翻，恍疑身到武陵源。',32,'全唐诗/poet.song.143000.json','["萬點紅隨雪浪翻，恍疑身到武陵源。", "歸來上界多官府，人與殘花兩不言。"]'),
('b9cdb9fa-adc8-40f8-9d7c-6f500276d4e9','丁酉二月二十日同部中諸公遊下竺御園坐枕流亭觀放閘桃花數萬點隨流而下繼至集芳亦禁峑也海棠滿山郁李遶檻殆不類人間世明日入部而桃花數枝伶俜窗外未時內直則海棠郁李各一株方開遂賦二絕句  其二','周必大','宋','宋诗','song-poetry','','[]','清勝堂前花萬重，玉堂署裏兩芳叢。',32,'全唐诗/poet.song.143000.json','["清勝堂前花萬重，玉堂署裏兩芳叢。", "應憐寓直清無侶，聊伴衰翁宿禁中。"]'),
('35717fdc-ff21-4f7c-9d92-491d5b8d1e5f','魯季欽敷文挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','競爽雲間陸，同升天上張。',48,'全唐诗/poet.song.143000.json','["競爽雲間陸，同升天上張。", "東堂聯折桂，南省繼含香。", "風月三千首，金絲十二行。", "初終全五福，似續付諸郎。"]'),
('8b193ecb-8923-46e8-a8fe-64accf83143d','魯季欽敷文挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','自摻江南袂，思公歲月徂。',48,'全唐诗/poet.song.143000.json','["自摻江南袂，思公歲月徂。", "書來懷棣萼，老去重葭莩。", "東粵仍閩粵，當湖遂鏡湖。", "堂成隨一相，浮世竟何須。"]'),
('a59ed029-6134-4469-81ac-47a359e8b311','宣州蔡子平尚書淑人居氏挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','八座夫人貴，三刀刺史榮。',48,'全唐诗/poet.song.143000.json','["八座夫人貴，三刀刺史榮。", "共深偕老慶，忽寄悼亡聲。", "寂寞閨門政，凄凉兒女情。", "親交猶雪涕，况乃謝宣城。"]'),
('7c570447-fa38-43fa-82d2-af1f3809be8b','宣州蔡子平尚書淑人居氏挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','鵷綴聞相藻，鴒原忝附葭。',48,'全唐诗/poet.song.143000.json','["鵷綴聞相藻，鴒原忝附葭。", "至今思並舍，晚歲擬通家。", "只道身長健，那知生有涯。", "挽謳無好語，聊雜壠頭笳。"]'),
('789729a1-a5ac-48d2-8d84-6577194963c4','東宮出示和御製秋懷詩恭和二首  其一','周必大','宋','宋诗','song-poetry','','[]','沛宮歌風雲，威德加四海。',72,'全唐诗/poet.song.143000.json','["沛宮歌風雲，威德加四海。", "雄詞照千古，編簡亦光彩。", "惟皇與同符，興寄秋序改。", "宸章振遠響，寂寞喑衆籟。", "有如凉飈來，殘暑去安在。", "願言掃氛曀，廓廓天宇大。"]'),
('8ad7f37a-244a-4ca0-a714-6d88eaf73a65','東宮出示和御製秋懷詩恭和二首  其二','周必大','宋','宋诗','song-poetry','','[]','寒露零太空，清詩出少海。',72,'全唐诗/poet.song.143000.json','["寒露零太空，清詩出少海。", "昭融備萬象，衆目眩符彩。", "二南可無愧，一字不容改。", "金聲玉振之，遼邈慶霄籟。", "毫芒落人間，神物護在在。", "惟慙小儒懵，未易識其大。"]'),
('8b40af0e-b536-4ad7-a80f-79c2919e9c4c','兵部宋尚書挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','北客今無幾，公才合奮飛。',48,'全唐诗/poet.song.143000.json','["北客今無幾，公才合奮飛。", "再期騫禁密，仍世攝途歸。", "星動尚書履，霜留御史威。", "桑榆初未逼，何乃露先晞。"]'),
('663a8830-233c-4c80-a961-8e0fb4254936','兵部宋尚書挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','識面嗟雖晚，論心樂未央。',48,'全唐诗/poet.song.143000.json','["識面嗟雖晚，論心樂未央。", "經帷叨並席，官舍許連牆。", "俶訝親鍼石，俄驚授印章。", "梅花佳句在，無復鐵心腸。"]'),
('1206c299-9452-4a66-8b70-7598c1f16420','中奉大夫直徽猷閣致仕邵及之挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','廉甚仍知止，高風似孔戣。',48,'全唐诗/poet.song.143000.json','["廉甚仍知止，高風似孔戣。", "北歸垂橐日，南省掛冠時。", "清白傳諸子，安閑閲十期。", "今誰主文字，好繼退之碑。"]'),
('47bee31f-9b81-4760-bfe2-f8ec69d65df9','中奉大夫直徽猷閣致仕邵及之挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','不殖千金産，惟求十畝園。',48,'全唐诗/poet.song.143000.json','["不殖千金産，惟求十畝園。", "湖山堆几席，花木報寒暄。", "曾是尊前客，常思醉後言。", "懷賢空有淚，無路灑新原。"]'),
('3f0e78c3-7ba5-41a7-a2a7-f06b000b76ca','走筆次李仁甫夜直觀月韻二首  其一','周必大','宋','宋诗','song-poetry','','[]','殿中延拜二卿真，腰下初橫寶带新。',32,'全唐诗/poet.song.143000.json','["殿中延拜二卿真，腰下初橫寶带新。", "便有堂封佳讖兆，移庖恰趁謝恩人。"]'),
('8ff00f5c-7e10-4216-985e-39890562928a','走筆次李仁甫夜直觀月韻二首  其二','周必大','宋','宋诗','song-poetry','','[]','玉堂清冷寐難頻，月姊高寒遠莫親。',32,'全唐诗/poet.song.143000.json','["玉堂清冷寐難頻，月姊高寒遠莫親。", "伴直徑須呼苦酒，不應覓句調他人。"]'),
('77d81aca-9e8e-421f-94bb-2bd4df522b9d','臣恭和御製晚秋曲宴近體詩一首繕寫投進冒瀆天威臣無任戰懼俟罪之至','周必大','宋','宋诗','song-poetry','','[]','宸遊不爲菊叢生，觀宴元因穀順成。',64,'全唐诗/poet.song.143000.json','["宸遊不爲菊叢生，觀宴元因穀順成。", "閣御芙蓉稱曼壽，殿開選德奏和聲。", "玉觴未飲心先醉，寶墨遥瞻眼倍明。", "身在金坡空感遇，論思深愧策平平。"]'),
('6aa818c7-84c1-40fd-af5d-8933ea3f02c1','李仁甫賦詩送其子塾下第歸次韻爲贈','周必大','宋','宋诗','song-poetry','','[]','餘力猶能誦稗官，奧篇隠帙復何難。',64,'全唐诗/poet.song.143000.json','["餘力猶能誦稗官，奧篇隠帙復何難。", "求賢正市千金駿，當賦終徵百羽摶。", "喚渡吳江秋水漲，解鞍蜀道雪山寒。", "歸來趁賀郎罷相，東閣重尋一笑歡。"]'),
('26c44009-2a4f-4a65-8eec-2d6ec326462c','慶東宮生辰四首  其一','周必大','宋','宋诗','song-poetry','','[]','太陽象真主，陽月應誕期。',48,'全唐诗/poet.song.143000.json','["太陽象真主，陽月應誕期。", "少陽比儲君，生近重陽時。", "明兩蓋自然，何待卦畫知。", "形容謾辭費，詠取重光詩。"]'),
('908f6e54-db66-4828-b230-3c625ca9e07c','慶東宮生辰四首  其二','周必大','宋','宋诗','song-poetry','','[]','崔豹稱明君，如月有規輪。',48,'全唐诗/poet.song.143000.json','["崔豹稱明君，如月有規輪。", "戴暠論副德，桂滿自長春。", "况乃秋夜永，萬里無纖塵。", "願歌重輪句，照耀率土濱。"]'),
('1d595b16-5d2a-4844-b0f6-b249e1e5436e','慶東宮生辰四首  其三','周必大','宋','宋诗','song-poetry','','[]','季秋日在房，房心乃明堂。',48,'全唐诗/poet.song.143000.json','["季秋日在房，房心乃明堂。", "煌煌心前星，于茲侍天王。", "休符協上象，九月誕元良。", "太史言有證，重暉照無疆。"]'),
('d1d6e1f7-4141-4cbd-962d-fe7bf3233bbb','慶東宮生辰四首  其四','周必大','宋','宋诗','song-poetry','','[]','舊聞西北海，巍然峙瑶山。',48,'全唐诗/poet.song.143000.json','["舊聞西北海，巍然峙瑶山。", "高辛賢太子，制樂山之間。", "坐閲幾春秋，不老常朱顔。", "至今重其潤，恩波浹人寰。"]'),
('a65fe35f-4ac6-45d1-93a3-3620ef72a9d7','送喻宮教良能出倅會稽','周必大','宋','宋诗','song-poetry','','[]','拾遺羈旅鑑湖秋，太史崎嶇禹穴游。',64,'全唐诗/poet.song.143000.json','["拾遺羈旅鑑湖秋，太史崎嶇禹穴游。", "只駕貳車良自足，更營三釜復何求。", "千山徧踏詩才冨，萬壑臨觀史筆遒。", "稍待政成歸魏闕，便從麟閣上螭頭。"]'),
('fae3181c-d8bc-4749-ad5b-164755aab48b','恭和御製賜史浩古詩','周必大','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','粵從三代還，歲月過千𥜥。',288,'全唐诗/poet.song.143000.json','["粵從三代還，歲月過千𥜥。", "時豈無賢君，道未契宸旨。", "煌煌唐太宗，勳業在所喜。", "寇攘既掃除，蠻貊畢至止。", "循良布郡邑，惠政寬獄市。", "忠賢儼班聯，切諫柅浮靡。", "關輔羅府兵，巖穴聘奇士。", "民生覆盂安，國勢泰山倚。", "皇心期過之，風下九萬里。", "忠厚培本根，文物粲華蕊。", "淳熙視貞觀，何啻相表裏。", "屬車尚濤江，列障隔淮水。", "蠢茲獯鬻氏，作我太清滓。", "坐令營屯衆，久費糗糧峙。", "中原厭狼貪，諸將空虎視。", "安得貫砮楛，來貢尺有咫。", "六合混一家，耕桑盛生齒。", "願言講治道，先務當有幾。", "欲仁斯仁至，患在未舉趾。", "而况前史中，遺事可尋理。", "衛英爪與牙，王魏目兼耳。", "處中頼房杜，虛受忘彼此。", "不聞國異政，但見車同軌。", "孰云古道難，僉曰今王是。"]'),
('0beddc1c-1772-4a5c-9ad6-ea2b1a81c127','靖州張推官庭傑挽詞','周必大','宋','宋诗','song-poetry','','[]','青綬當年謾佩緺，力將儒素換豪華。',64,'全唐诗/poet.song.143000.json','["青綬當年謾佩緺，力將儒素換豪華。", "篋中深貯先賢傳，門外常停長者車。", "有子菑畬在經訓，平生痼疾是烟霞。", "花橋卜築花山殯，太息中吳好事家。"]'),
('c9739a6e-e8d5-47c0-aada-d25bce1ac168','端明尚書汪聖錫挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','性與天真合，心惟聖處求。',48,'全唐诗/poet.song.143000.json','["性與天真合，心惟聖處求。", "有書皆默記，無事不冥搜。", "相業期黄髮，祠官恃黑頭。", "爲霖幾人望，誰料倏成休。"]'),
('d996443d-3a4c-4573-bfd2-297abbe13edc','端明尚書汪聖錫挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','刻意追元祐，斯文未喪予。',48,'全唐诗/poet.song.143000.json','["刻意追元祐，斯文未喪予。", "前生陳正字，今代傅中書。", "太末分携晚，東膠覿面初。", "追思二十載，痛哭淚盈裾。"]'),
('36f7d10a-27ba-44b3-93e9-dabbd6faac83','秋官少常伯失杯復得乃好客之報來詩誤認天意遂欲因噎廢食走筆次韻發笑','周必大','宋','宋诗','song-poetry','','[]','郭釜知藏幾百杯，韋籯何止一尊罍。',64,'全唐诗/poet.song.143000.json','["郭釜知藏幾百杯，韋籯何止一尊罍。", "冶金太盛應須躍，塞馬重歸豈是災。", "車到門前如可却，客來梁上若爲回。", "遂疑同舍真疎矣，明與劉叉亦壯哉。"]'),
('b07e0fe4-c722-4ff8-bac9-b4fc6e572fbe','次韻陳叔晉舍人殿試筆記','周必大','宋','宋诗','song-poetry','','[]','帝垂清問切恢圖，士貢昌言敢導諛。',160,'全唐诗/poet.song.143000.json','["帝垂清問切恢圖，士貢昌言敢導諛。", "高下共知歸至鑑，考評聊許備先驅。", "四帷迥隔心常渴，三榻橫連體叵舒。", "烏府凜然賢執法，紫垣籍甚古通儒。", "墨朱同異容兼採，等級從違得細書。", "尚醖時頒缸面酒，大官日饌腹前臚。", "天香漫炷薰常歇，貢茗虛霑樣頓殊。", "晨壁摇風愁幕冷，夜窗透月喜簾疎。", "九賓屈指臚連句，千慮傾心智與愚。", "會待詔恩三日沐，湖山尋勝任舟輿。"]'),
('49dc81f8-c47b-4a03-857f-1e97e61e7775','胡邦衡端明用癸巳舊韻寵賜佳篇輒續貂爲不一之賀','周必大','宋','宋诗','song-poetry','','[]','閏六還同載誕辰，壽川方至浩無津。',64,'全唐诗/poet.song.143000.json','["閏六還同載誕辰，壽川方至浩無津。", "位虛左轄民瞻舊，職視西樞睿眷新。", "玉果又霑湯餠客，銀環仍進雪膚人。", "風流富貴誰能並，未害先生道德淳。"]'),
('929be582-5ae0-423c-81d1-055fe431d3e8','中元日以春花數種送閻才元左司閻賦二絕句次韻  其一','周必大','宋','宋诗','song-poetry','','[]','韓郎牡丹迹已久，殷七杜鵑名謾新。',32,'全唐诗/poet.song.143000.json','["韓郎牡丹迹已久，殷七杜鵑名謾新。", "何似熙熙行闕裏，花隨和氣四時春。"]'),
('282dd703-1686-403d-b802-9c07579ac745','中元日以春花數種送閻才元左司閻賦二絕句次韻  其二','周必大','宋','宋诗','song-poetry','','[]','早歲聯名向千佛，如今接武事承華。',32,'全唐诗/poet.song.143000.json','["早歲聯名向千佛，如今接武事承華。", "何時誤入長春苑，盡看先生解語花。"]'),
('e0ac0695-b65c-4036-be55-f46ea5228e5f','送石似之倉部出倅漳州','周必大','宋','宋诗','song-poetry','','[]','半刺臨漳郡，榮歸總不如。',48,'全唐诗/poet.song.143000.json','["半刺臨漳郡，榮歸總不如。", "棠陰三世舊，梓里數程餘。", "野老談遺愛，儒先叩異書。", "依烏带東壁，從此照閩墟。"]'),
('4c019d15-426a-40a8-94b6-36bc447a599b','送陸務觀赴七閩提舉常平茶事  其一','周必大','宋','宋诗','song-poetry','','[]','漢皇親召賈生還，京路爭看北海賢。',32,'全唐诗/poet.song.143000.json','["漢皇親召賈生還，京路爭看北海賢。", "却畏神仙足官府，便思風采爍雲烟。"]'),
('05d7a24b-c192-4c99-94d6-74f210949fea','送陸務觀赴七閩提舉常平茶事  其二','周必大','宋','宋诗','song-poetry','','[]','暮年桑苧毀茶經，應爲征行不到閩。',32,'全唐诗/poet.song.143000.json','["暮年桑苧毀茶經，應爲征行不到閩。", "今有雲孫持使節，好因貢焙祀茶神。"]'),
('9e2d439d-23c7-495f-8638-61ac74905277','送陸務觀赴七閩提舉常平茶事  其三','周必大','宋','宋诗','song-poetry','','[]','鸞棲枳棘已多年，父老猶傳主簿賢。',32,'全唐诗/poet.song.143000.json','["鸞棲枳棘已多年，父老猶傳主簿賢。", "扶杖喜迎新使者，赤帷何惜與高褰。"]'),
('8407f6eb-4d20-47ec-8dea-22f87031e7b8','送陸務觀赴七閩提舉常平茶事  其四','周必大','宋','宋诗','song-poetry','','[]','疲駑久倦直明光，風味常思十八娘。',32,'全唐诗/poet.song.143000.json','["疲駑久倦直明光，風味常思十八娘。", "擬請一麾依故舊，得無公道學蘇章。"]'),
('b7042684-722e-4784-b292-f97b9586e28a','淮東兵馬鈐轄趙公挽詞','周必大','宋','宋诗','song-poetry','','[]','籍甚宣王七世孫，麟題信厚典型存。',64,'全唐诗/poet.song.143000.json','["籍甚宣王七世孫，麟題信厚典型存。", "青雲事業成難弟，黄甲科名付後昆。", "炊臼方悲鸞鏡舞，奠楹俄掩毳衣璊。", "翩翩雙旐餘杭路，細雨西風總斷魂。"]'),
('908f8c45-94ee-48fe-a87d-b814901e2630','恭和御製幸秘書省詩二首  其一','周必大','宋','宋诗','song-poetry','','[]','羣玉西崑富典章，二星東壁粲輝光。',64,'全唐诗/poet.song.143000.json','["羣玉西崑富典章，二星東壁粲輝光。", "秋花迎杖千叢麗，法曲傳觴九奏長。", "虎將縱觀修舊事，豸冠陪侍仰明王。", "政修即是攘夷策，玁狁殘祆豈足囊。"]'),
('9856f9dc-e03e-4db1-bbaa-3ee44f7322c1','恭和御製幸秘書省詩二首  其二','周必大','宋','宋诗','song-poetry','','[]','蟠木離奇愧豫章，幾年封植荷恩光。',64,'全唐诗/poet.song.143000.json','["蟠木離奇愧豫章，幾年封植荷恩光。", "石渠久綴英髦後，金鎖深慚學識長。", "御墨奎文瞻列聖，雷尊篆鼎備三王。", "願言作德酬榮遇，寧復矜才似智囊。"]'),
('4663416c-3a99-4c2a-97c3-807cecc696e1','再用邦衡韻贊其閒居之樂且致思歸之意','周必大','宋','宋诗','song-poetry','','[]','一別龍門不計春，思公夢渡太臯津。',64,'全唐诗/poet.song.143000.json','["一別龍門不計春，思公夢渡太臯津。", "遥知綠野朱顔好，應笑紅塵白髮新。", "午茗親烹留上客，夜棋酣戰調佳人。", "道腴有味詩彌勝，何止冰凝與蜜淳。"]'),
('62446d19-3817-46ef-ae04-134e51ce934a','送胡子遠出守漢州分韻得萬字','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三釜貴及親，萬戶豈吾願。',120,'全唐诗/poet.song.143000.json','["三釜貴及親，萬戶豈吾願。", "君今二千石，榮祿尚何論。", "而况蜀漢間，相望兩宿頓。", "鹿轓從版輿，鳩杖雜戟鐏。", "斑衣父老誇，晝錦士夫勸。", "遥知四境內，和氣銷愁恨。", "却應念主恩，未遽忘一飯。", "試於溫凊餘，款款話繾綣。", "仍談西湖勝，幸及老人健。", "相將下三峽，看復摶九萬。"]'),
('52b583bc-676a-451e-826e-ea90dc5cee38','進謝御書古詩','周必大','宋','宋诗','song-poetry','','[]','允文元祐詞臣軾，勁節名章世無敵。',160,'全唐诗/poet.song.143000.json','["允文元祐詞臣軾，勁節名章世無敵。", "御前曾賜紫薇詩，袖裏驪珠光的爍。", "小臣謬直白玉堂，也紆皇眷摛雲章。", "雲章元是七德舞，字字筆法超鍾王。", "兩朝相望九十祀，長慶集中偏屬意。", "咸池日照草木光，天門龍躍魚蝦悸。", "我皇英銳真太宗，文武神聖功德隆。", "黄鉞指期擒頡利，捷書先獻大安宮。", "元和學士白居易，臣非其才私有志。", "願隨班賀四海清，續唐之歌誇萬世。"]'),
('d1721f06-2f70-4a96-b3f4-36ca94510f8e','劉諫議挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','早習唐蕡策，中爲漢輔官。',48,'全唐诗/poet.song.143000.json','["早習唐蕡策，中爲漢輔官。", "伏蒲頻盡節，當宁極隆寬。", "身荷甘泉橐，家仍陋巷簞。", "清名垂宇宙，猶足障狂瀾。"]'),
('4855d2a7-f012-4e1a-b6b0-395ebc7ff2ee','劉諫議挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','疇昔英游後，推尊輩行先。',48,'全唐诗/poet.song.143000.json','["疇昔英游後，推尊輩行先。", "班聯容接武，坐立愧差肩。", "我已無如老，公非不永年。", "思賢仍感舊，衰涕兩潸然。"]'),
('6191c020-2387-4508-9770-41352e6f5ae6','次范至能憶同游石湖韻','周必大','宋','宋诗','song-poetry','','[]','桃源非真亦非空，幾年誤轉漁郎篷。',128,'全唐诗/poet.song.143000.json','["桃源非真亦非空，幾年誤轉漁郎篷。", "豈知石湖天尺五，不隔三萬弱水中。", "主公心伴白鷗沒，莫莫朝朝醉花月。", "邇來一念了世緣，蟬冕照人頭未雪。", "如今又作衣錦回，汀洲依舊玉成堆。", "聞道丹青憶賢佐，白麻早晚從天來。", "斷章批處階重抹，敢向坐中論禮絕。", "午橋他日倘重陪，庶見方瞳并綠髮。"]'),
('1b4adde2-52f5-4356-9b0c-ea80aedd1146','胡邦衡惠淳字韻佳什回首十年間不知幾往返矣雖歲月逾邁而格律益高降嘆不足敬用賡和','周必大','宋','宋诗','song-poetry','','[]','掃迹龍門六小春，渴聞談論齒生津。',64,'全唐诗/poet.song.143000.json','["掃迹龍門六小春，渴聞談論齒生津。", "築巖勳業方圖舊，倚市工夫謾鬭新。", "百二山河行入手，三千風月莫迷人。", "彌縫直出羲農上，舉世終由魯叟淳。"]'),
('efc7146b-3b99-47f2-bff4-b2079b28664b','次韻王仲行尚書宿直兩絕句  其一','周必大','宋','宋诗','song-poetry','','[]','東省南宮切太微，夔龍行集鳳凰池。',32,'全唐诗/poet.song.143000.json','["東省南宮切太微，夔龍行集鳳凰池。", "更哦殿閣薰風句，坐覺微凉生桂枝。"]'),
('65361ca6-1bd1-4e1a-a81d-b0d2be60ec2c','次韻王仲行尚書宿直兩絕句  其二','周必大','宋','宋诗','song-poetry','','[]','紫禁同依日月輝，蒼顔獨愧羽毛奇。',32,'全唐诗/poet.song.143000.json','["紫禁同依日月輝，蒼顔獨愧羽毛奇。", "水如明鏡雖堪俯，笑汝星星誰肯嬉。"]'),
('3fefa026-f604-4788-8130-9135f0a5cc42','徐元敏察院頃和子中兄長篇語頗相屬今承出使交廣次韻送行兼簡經略劉文潛','周必大','宋','宋诗','song-poetry','','[]','少年同仕秦淮口，醉裏殷勤掃花帚。',192,'全唐诗/poet.song.143000.json','["少年同仕秦淮口，醉裏殷勤掃花帚。", "蒼顔白髮二紀中，夢斷賞心并折柳。", "非才晚汙論思地，分察久觀彈擊手。", "端方期不負耳目，詰曲誰能學跟肘。", "善良無憂藜藿採，讒諂有類麏䴥走。", "三年執法念少休，萬里立功圖不朽。", "遥知二十五州民，即日春風散醇酒。", "吏驚綉斧指東海，士喜文星避南斗。", "由來炎雲多瘴癘，是處黄茅少林藪。", "自從英英賢牧至，蔽芾棠陰地無醜。", "同年相逢定傾蓋，痛飲何妨暫濡首。", "書來不用詫梅花，共說蒼生蘇息否。"]'),
('c2860a31-8620-4626-ba6f-7911068562e2','次張欽夫經略韻送胡長彥司戶還廬陵','周必大','宋','宋诗','song-poetry','','[]','解印陶元亮，居鄉馬少游。',48,'全唐诗/poet.song.143000.json','["解印陶元亮，居鄉馬少游。", "久憐高士少，今喜故人優。", "客至無何飲，身閒有底愁。", "自然仁者壽，誰羨道家流。"]'),
('7d6c76ef-67c4-4ac8-a6b7-4fc2fccdcd23','劉共甫樞密挽詞三首  其一','周必大','宋','宋诗','song-poetry','','[]','勳在居留地，名高宥密庭。',48,'全唐诗/poet.song.143000.json','["勳在居留地，名高宥密庭。", "旄頭期掃彗，箕尾倏騎星。", "不相知由命，占天忍促齡。", "平生經濟策，付與簡編青。"]'),
('538a03b8-3690-4f30-a637-d4a547fc1fbc','劉共甫樞密挽詞三首  其二','周必大','宋','宋诗','song-poetry','','[]','世抱忠精節，心睎社稷臣。',48,'全唐诗/poet.song.143000.json','["世抱忠精節，心睎社稷臣。", "拖紳遺奏日，馳驛挾醫辰。", "讜論留丹扆，清班閟紫宸。", "史魚屍諫後，聖代不無人。"]'),
('2c4bd4bc-28e3-41b5-ba70-6f6f2630d6cd','劉共甫樞密挽詞三首  其三','周必大','宋','宋诗','song-poetry','','[]','芸省翻黄卷，詞垣賦紫薇。',48,'全唐诗/poet.song.143000.json','["芸省翻黄卷，詞垣賦紫薇。", "年華飛電過，耆德曉星稀。", "梅閣臨風迥，滕城指日歸。", "懷賢并感舊，衰涕一時揮。"]'),
('a50faba6-7b87-4ac4-88f4-e583a468575b','兵部王仲行尚書惠詩敘近日直舍隔壁論詩說棋之戲次韻爲謝尚書近錄舊詩一篇爲贈故并及之','周必大','宋','宋诗','song-poetry','','[]','詩可弄萬象，棋能消百憂。',180,'全唐诗/poet.song.143000.json','["詩可弄萬象，棋能消百憂。", "苦吟復苦戰，已過心休休。", "自從識夫子，十閲長安秋。", "奇才揜衆俊，博物包九流。", "游戲亦臻極，他人歎無由。", "脚踏軟紅塵，手把大白浮。", "每坐客常屈，有社誰敢投。", "此事聊復爾，壯懷許聞不。", "殺虜盧龍溝，鎸羌西海頭。", "六奇藴秘策，鑿壁那可偷。", "稍見壺子機，已驚季咸儔。", "遂盜祖師法，敢與神秀侔。", "豈如念貧績，明許餘光求。", "故將綉段贈，不責玉案酬。", "從今空囊富，免爲杜陵羞。"]'),
('9c8db528-072e-496c-8b29-40f6e6381767','明堂慶成二十韻','周必大','宋','宋诗','song-poetry','','[]','親饗嚴三歲，邦彝重九筵。',240,'全唐诗/poet.song.143000.json','["親饗嚴三歲，邦彝重九筵。", "祖宗垂統大，天地著功全。", "惟睿崇昭報，于時展吉蠲。", "發揮皇祐日，潤色紹興年。", "稽古千齡契，齋心十日專。", "揭名新扁榜，書冊屏葷羶。", "假廟陰雲剝，升禋皓月團。", "無風摇燭影，有瑞燦星躔。", "不值連宵雨，那彰倏霽天。", "貳觴猶翼翼，百拜愈乾乾。", "歸次徒勞奏，回班特許朘。", "賀儀隨仗入，霈澤御樓宣。", "獻胙金絲合，簪花錦綉鮮。", "慈皇顔有喜，聖孝古無前。", "和氣騰都邑，歡聲徧海壖。", "祺祥應曼羨，壽祿自綿延。", "臣也芻蕘賤，恩斯雨露偏。", "執綏華蓋裏，草赦玉堂邊。", "第頌甘居後，逢辰幸獨先。", "四方今日靖，申誦我將篇。"]'),
('ccd186c7-685d-4153-ae0a-67a33cd0f045','內直以金橘送七兄','周必大','宋','宋诗','song-poetry','','[]','晝卧玉堂殿，眼看金彈丸。',48,'全唐诗/poet.song.143000.json','["晝卧玉堂殿，眼看金彈丸。", "禹包經歲月，鄭驛助杯盤。", "黄带霜前綠，甘移醉後酸。", "江湖有兄弟，此日憶團欒。"]'),
('699426aa-f860-469f-8626-e77bb50eb674','送鹿伯可致政直閣兼簡吳明可致政給事','周必大','宋','宋诗','song-poetry','','[]','垂車七十古來稀，况是丁年解鞅鞿。',64,'全唐诗/poet.song.143000.json','["垂車七十古來稀，况是丁年解鞅鞿。", "神虎衣冠洪景掛，都門供帳仲翁歸。", "前銜新命俱郎宿，處士儒冠總少微。", "林下若逢龍閣老，爲言台嶺轉光輝。"]'),
('4c286d7a-1a88-412f-bcdd-0970cb33be0e','戴子微運使出使湖北約以惡語送行而未遣也佳篇見督次韻奉寄','周必大','宋','宋诗','song-poetry','','[]','早日逍遥侍從間，重來奉引近威顔。',64,'全唐诗/poet.song.143000.json','["早日逍遥侍從間，重來奉引近威顔。", "倦趨北闕晨霜冷，思上南樓夜月閒。", "直指不誇新衣綉，曲臺只記舊班聯。", "豈知隔面心猶渴，空訝相如下筆慳。"]'),
('9b44ff26-fbdf-4fb3-a994-dbcf8384b3e1','張待制挽詞','周必大','宋','宋诗','song-poetry','','[]','桂籍聲名早，松門歲月賒。',48,'全唐诗/poet.song.143000.json','["桂籍聲名早，松門歲月賒。", "鎮東多惠愛，使北有光華。", "豈料尋春騎，翻成會葬車。", "珠園舊亭舘，細雨泫新花。"]'),
('ee59c801-e30a-41b6-9cb8-07d4e294f5d9','進讀三朝寶訓終篇賜宴賜賚謝恩詩','周必大','宋','宋诗','song-poetry','','[]','藝祖提劍開八荒，太宗混一垂衣裳。',272,'全唐诗/poet.song.143000.json','["藝祖提劍開八荒，太宗混一垂衣裳。", "真皇破虜神武揚，夷夏億寧法度彰。", "寶訓成書紀宏綱，有典有則萬葉昌。", "憶昔壬午神龍翔，季秋庚子辰集房。", "肇開講席臨青廂，赭袍玉斧光照廊。", "台司夾侍書案黄，翰林進讀天容莊。", "微臣簪筆近御牀，親聞玉音義甚長。", "君子小人初何常，非關時運弱與强。", "祗係人主所否臧，當年記注此特詳。", "往來寒暑今一章，牙篦謬執心徬徨。", "終篇正值恩德洋，道山肆筵酌天漿。", "宮花壓帽羅絲簧，硯來復古翰墨光。", "馬出帝閑真驌驦，閩山正焙隨寶香。", "君賜如天不可量，歸美獨愧詞荒唐。", "恭惟聖治超百王，夙夜基命不敢康。", "文德既修狄可攘，俎豆永掃旄頭芒。", "三聖勳烈同煒煌，萬年億載娛慈皇。"]'),
('77981d17-807d-4324-a747-cac81c569d79','文忠烈公居洛有丙午同甲會詩今執政府凡三位樞密使王季海參政錢師魏先在焉前歲夏某忝參預連牆而居適然齊年時號丙午坊次文公韻簡公','周必大','宋','宋诗','song-poetry','','[]','文公八十會伊川，盛事于今又百年。',64,'全唐诗/poet.song.143000.json','["文公八十會伊川，盛事于今又百年。", "豈意蒼顔華髮叟，亦陪黄閣紫樞仙。", "府居末至容連棟，班路前瞻愧比肩。", "丁丙連干支合德，君臣慶會豈虛傳。"]'),
('5bfafd04-1a5c-49cf-a613-d6c67795d523','慶東宮生辰','周必大','宋','宋诗','song-poetry','','[]','聖祖基長發，皇家慶遠覃。',144,'全唐诗/poet.song.143000.json','["聖祖基長發，皇家慶遠覃。", "金輪常御極，銀榜夙占男。", "萸節辰遲五，蓂階莢度三。", "英姿同父祖，秀氣集輿堪。", "仁孝由天縱，溫文亦性涵。", "兩宮今並事，三善此誰慙。", "玉佩班昕肅，牙篦道日談。", "儉寧從節苦，正每斥言甘。", "甲觀蘭開殿，南陽菊映潭。", "名參周發誦，壽百古彭聃。", "政省叨峩弁，宮僚阻盍簪。", "賓筵應秩秩，鐘鼓夢韽韽。"]'),
('d026bc4f-6dc1-4a29-a003-7e87186b0f99','龍圖閣直學士吳明可挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','冠掛十年餘，齡周八秩初。',48,'全唐诗/poet.song.143000.json','["冠掛十年餘，齡周八秩初。", "錦囊遺藁富，紫橐賜金虛。", "似白猶希白，如疏更景疏。", "清風并亮節，付與汗青書。"]'),
('5597f481-840b-4087-9f13-585929dde161','龍圖閣直學士吳明可挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','憶昨經洪井，連朝點玳筵。',48,'全唐诗/poet.song.143000.json','["憶昨經洪井，連朝點玳筵。", "東湖波浩蕩，南苑月嬋娟。", "偃飲驚三雅，蛩吟羨百篇。", "祗今悲舊事，何日奠新阡。"]'),
('ed1bd184-fd21-406b-a7de-b4462201afbd','和龍舒兄春日出郊韻','周必大','宋','宋诗','song-poetry','','[]','庭束蒲鞭吏晝閒，禽聲人語兩關關。',64,'全唐诗/poet.song.143000.json','["庭束蒲鞭吏晝閒，禽聲人語兩關關。", "郊坰戎隊穿花裏，阡陌兒童戲雉間。", "禪語屢題投子寺，仁風常滿皖公山。", "薦書聞道交宸几，尺一封泥合錫還。"]'),
('3bd83221-0781-471d-98aa-8453cbd04d16','敷文閣學士李仁甫挽詞十絕  其一','周必大','宋','宋诗','song-poetry','','[]','萬古仇池一老仙，前身遊宦憶西川。',32,'全唐诗/poet.song.143000.json','["萬古仇池一老仙，前身遊宦憶西川。", "令威化鶴空千歲，何似重來十五年。"]'),
('6e9e1b3c-8f11-4400-bacc-31c4e38abd9a','敷文閣學士李仁甫挽詞十絕  其二','周必大','宋','宋诗','song-poetry','','[]','父子才名震蜀都，家風人道似三蘇。',32,'全唐诗/poet.song.143000.json','["父子才名震蜀都，家風人道似三蘇。", "不知岷嶺英靈氣，底向眉山特地殊。"]'),
('5f423da6-a6e0-40c8-a0db-1a8af7586697','敷文閣學士李仁甫挽詞十絕  其三','周必大','宋','宋诗','song-poetry','','[]','經學淵源史筆高，文章餘力埒風騷。',32,'全唐诗/poet.song.143000.json','["經學淵源史筆高，文章餘力埒風騷。", "紛紛小技誇流俗，磨滅身名笑爾曹。"]'),
('89077abb-9251-4295-8903-a33875d17a8f','敷文閣學士李仁甫挽詞十絕  其四','周必大','宋','宋诗','song-poetry','','[]','頻駕輶軒析左符，直從梁益到江湖。',32,'全唐诗/poet.song.143000.json','["頻駕輶軒析左符，直從梁益到江湖。", "棠陰處處留遺愛，芹泮人人憶大儒。"]'),
('9f466326-c76a-41fb-8f0a-c509a8b7a8a2','敷文閣學士李仁甫挽詞十絕  其五','周必大','宋','宋诗','song-poetry','','[]','鳴佩甘泉不乏人，誰能博古復通今。',32,'全唐诗/poet.song.143000.json','["鳴佩甘泉不乏人，誰能博古復通今。", "直如汲黯非遊俠，忠似更生不鑄金。"]'),
('d28ef5bc-6fed-420b-ab09-1a694cdd449e','敷文閣學士李仁甫挽詞十絕  其六','周必大','宋','宋诗','song-poetry','','[]','千卷長編已刻閩，爭傳副墨價兼金。',32,'全唐诗/poet.song.143000.json','["千卷長編已刻閩，爭傳副墨價兼金。", "冠篇不得同迂叟，遺恨猶應記玉音。"]'),
('08f98803-4771-45ce-8e52-c42fab65339a','敷文閣學士李仁甫挽詞十絕  其七','周必大','宋','宋诗','song-poetry','','[]','是是非非口即心，掃除人僞只天真。',32,'全唐诗/poet.song.143000.json','["是是非非口即心，掃除人僞只天真。", "身全五福仍通貴，造物因公勸善人。"]'),
('6c4ad6aa-9fe2-47c0-9832-b0b2557e8fc5','敷文閣學士李仁甫挽詞十絕  其八','周必大','宋','宋诗','song-poetry','','[]','病後精神更湛然，掛冠剛欲及生前。',32,'全唐诗/poet.song.143000.json','["病後精神更湛然，掛冠剛欲及生前。", "去來自在渾無礙，撫掌僧徒浪學禪。"]'),
('9654520c-2be7-4810-aa53-775954cc144e','敷文閣學士李仁甫挽詞十絕  其九','周必大','宋','宋诗','song-poetry','','[]','蓬監曾叨繼後塵，史闈何幸對題名。',32,'全唐诗/poet.song.143000.json','["蓬監曾叨繼後塵，史闈何幸對題名。", "非才自是無能役，太息難忘故舊情。"]'),
('2c673280-3f62-4ab6-b179-4ef90db88760','敷文閣學士李仁甫挽詞十絕  其一○','周必大','宋','宋诗','song-poetry','','[]','我畏譏讒口屢緘，獨公嗜好不酸鹹。',32,'全唐诗/poet.song.143000.json','["我畏譏讒口屢緘，獨公嗜好不酸鹹。", "每傾苦酒思談笑，萬里何由奠巽嚴。"]'),
('fcf63900-24f6-4762-ac02-076591309ad7','讀樂天詩戲效其體','周必大','宋','宋诗','song-poetry','','[]','側足二三臣，平頭六十人。',48,'全唐诗/poet.song.143000.json','["側足二三臣，平頭六十人。", "胸中冰與炭，鏡裏雪兼銀。", "豈有花經眼，何嘗酒入唇。", "勞生成底事，胡不早收身。"]'),
('41bca133-24a8-4420-a29b-9e8c0119e0cc','三月六日中宮生辰二府例以前四日就孤山四聖觀設醮泛舟至玉壺環碧園因記歐陽公治平三年丙午歲上巳和韓丞相詩謂是歲始頒明天曆三月三日丁巳故有節正須知鳳曆新之句今歲亦逢辛巳而又歲皆丙午誠異事也輒借原韻賦詩一篇簡諸公','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東華正踏軟紅塵，却趁西湖祓禊辰。',64,'全唐诗/poet.song.143000.json','["東華正踏軟紅塵，却趁西湖祓禊辰。", "曆似明天時令正，春逢閏歲物華新。", "流連花柳輸豪俠，判斷湖山愧隠淪。", "尚擬鳴鑾一遊豫，還陪英衮奉嚴宸。"]'),
('1d23157b-5ac2-4579-ae00-c36da14a2157','高宗皇帝挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','社稷興中否，干戈靜四溟。',48,'全唐诗/poet.song.143000.json','["社稷興中否，干戈靜四溟。", "生年同藝祖，慶壽似慈寧。", "人憶庚庚兆，天垂九九齡。", "向來懷夏禹，今祔越山青。"]'),
('989b3f20-4e86-46f0-ade2-e55f2e1d08cc','高宗皇帝挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','太極乾元父，清都大帝宮。',48,'全唐诗/poet.song.143000.json','["太極乾元父，清都大帝宮。", "宴酣忘御駿，仙去任遺弓。", "音遏思堯顙，旻號泣舜瞳。", "孤臣臺閣舊，淚血灑春風。"]'),
('b077e3ed-c797-4712-8680-f2eb852e43dc','陶淵明己酉重九詩一首某以此年此日舟次吉水距永和財一程耳輒用其韻先寄二兄十三弟并呈提舉七兄','周必大','宋','宋诗','song-poetry','','[]','王覲十五載，歸來稀舊交。',96,'全唐诗/poet.song.143000.json','["王覲十五載，歸來稀舊交。", "我鬢昔已華，今茲固宜凋。", "去國甫重五，還家倏登高。", "永和有兄弟，咫尺如烟霄。", "緬懷江東使，地遠心更勞。", "遥知上翠微，江山勝金焦。", "豈無茱萸酒，望望心鬰陶。", "相從會有日，永矣非一朝。"]'),
('e4801f15-fa2c-4827-9ff0-eae9553edad8','贛守鄭舜舉寄詩酒於答書中就附四句','周必大','宋','宋诗','song-poetry','','[]','十七篇詩酒滿壺，贛州風景塞繩樞。',32,'全唐诗/poet.song.143000.json','["十七篇詩酒滿壺，贛州風景塞繩樞。", "詩中有畫今摩詰，安用當年八境圖。"]'),
('edab7241-252a-45b1-acc2-1017fa53bd9b','南園築小堂鄰里侯暘獻上梁文戲成小詩記實解嘲','周必大','宋','宋诗','song-poetry','','[]','半畝園林數尺堂，凡花疎竹小池塘。',32,'全唐诗/poet.song.143000.json','["半畝園林數尺堂，凡花疎竹小池塘。", "平泉綠野休相笑，事業功名合自量。"]'),
('7d32585c-17c8-466e-b446-1e0908d571ea','郊居三池皆種蓮自五月開至七月末無日不寓目今得七兄秋浦佳篇謹次嚴韻','周必大','宋','宋诗','song-poetry','','[]','雲錦撐舟引興長，冉香回首惜年芳。',64,'全唐诗/poet.song.143000.json','["雲錦撐舟引興長，冉香回首惜年芳。", "碧筩擎雨時傾蓋，紅旆摇風暫亞槍。", "近渚何勞攀太華，真妝應筆弄西凉。", "夕蟾忽散金千炬，歸夢依稀到玉堂。"]'),
('71299f79-522d-49b7-88a2-94475df4bab1','和七兄秋浦韻','周必大','宋','宋诗','song-poetry','','[]','遵渚遲魚素，巡簷驗鵲占。',48,'全唐诗/poet.song.143000.json','["遵渚遲魚素，巡簷驗鵲占。", "江雲懷李白，籬菊詠陶潛。", "句好那容畫，才高却道鹽。", "皇華聊吏隠，清論付廷僉。"]'),
('049bb8e0-1f20-49bf-af39-e5de50c524a5','次七兄韻題二兄靜明閣','周必大','宋','宋诗','song-poetry','','[]','堤有芙蓉沼有蕖，東西精舍直平湖。',64,'全唐诗/poet.song.143000.json','["堤有芙蓉沼有蕖，東西精舍直平湖。", "市朝間闊聊中隠，山隰橫陳豈子都。", "杖屨意行非得得，輪蹄心遠任區區。", "休窮眼力爲疆界，且把詩篇替畫圖。"]'),
('ba7ac535-5cb3-4e6c-910b-9ab8c68fef6d','七兄以庚戌重陽前解江東常平印泝江而歸先寄二詩次韻  其一','周必大','宋','宋诗','song-poetry','','[]','早日常同席，中間屢話離。',48,'全唐诗/poet.song.143000.json','["早日常同席，中間屢話離。", "呂梁今破夢，曹髮共深期。", "菊圃新開徑，茅齋正築基。", "不妨風雨夜，酌酒更論詩。"]'),
('a8c37c86-9506-4ca9-80a6-082c9043bd90','七兄以庚戌重陽前解江東常平印泝江而歸先寄二詩次韻  其二','周必大','宋','宋诗','song-poetry','','[]','春駕輕車上九華，秋乘大舸泝風沙。',64,'全唐诗/poet.song.143000.json','["春駕輕車上九華，秋乘大舸泝風沙。", "欲拋彭澤追元亮，何待龍山宴孟嘉。", "行止非關人力勝，清平自有部民誇。", "征帆衝雨何時至，東望牙檣眼屢花。"]'),
('1dac1652-653e-482b-9492-01e5b32e2eca','廣西漕屬呂君祖平以其六世祖文靖公及五世伯祖惠穆公帖示周某敬題其後','周必大','宋','宋诗','song-poetry','','[]','世臣本非喬木，故笏真是甘棠。',28,'全唐诗/poet.song.143000.json','["世臣本非喬木，故笏真是甘棠。", "奕葉鈞樞翰墨，寶章何媿諸王。"]'),
('477d85ab-960e-4a9f-81b6-50bb7659b6b2','送劉公度縣丞赴江陵','周必大','宋','宋诗','song-poetry','','[]','投分復連牆，閒居味更長。',48,'全唐诗/poet.song.143000.json','["投分復連牆，閒居味更長。", "送春慵斲句，惜別怕傳觴。", "我正羣麋鹿，君當騖驌驦。", "但令同臭味，不必共行藏。"]'),
('4ccd22bc-168f-46ef-bb3b-af12c9e18137','太和芍藥最盛有紅都勝黄樓子爲之冠昔山谷常宰邑篇詠極多獨遺此花四月八日與諸友共賞戲成小詩','周必大','宋','宋诗','song-poetry','','[]','紅勝依稀如魏紫，緗樓彷彿似姚黄。',32,'全唐诗/poet.song.143000.json','["紅勝依稀如魏紫，緗樓彷彿似姚黄。", "元豐詩尹渾無語，豈是參謀闕海棠。"]'),
('3803e27c-fdd5-42fd-8fc6-b55ac3328342','簡提刑吳大卿二首  其一','周必大','宋','宋诗','song-poetry','','[]','瑞節頻移意可知，西川西廣又江西。',32,'全唐诗/poet.song.143000.json','["瑞節頻移意可知，西川西廣又江西。", "蘇黄到處君行部，物色分留待品題。"]'),
('f78ac15d-5af6-42ba-a610-93eef38edeed','簡提刑吳大卿二首  其二','周必大','宋','宋诗','song-poetry','','[]','堆勝橫看白鷺洲，青原穩著釣臺幽。',32,'全唐诗/poet.song.143000.json','["堆勝橫看白鷺洲，青原穩著釣臺幽。", "魯公翰墨師川句，訪古何妨與一遊。"]'),
('36cf3513-8acd-4860-b59c-d790982bda68','權州楊倅子直方以詩惠鶴雛次韻爲謝','周必大','宋','宋诗','song-poetry','','[]','未解連軒賦鮑昭，且陪茫蕩醉東臯。',64,'全唐诗/poet.song.143000.json','["未解連軒賦鮑昭，且陪茫蕩醉東臯。", "初非日浴身原潔，何待天沖志已高。", "羽服便能隨羽扇，霜翎正合伴霜毛。", "使君今是徐州守，會宴雲龍樂且遨。"]'),
('b970490d-7395-46a2-870e-555e69d73ee4','吉水周中顯秀才相識二十餘年來求永新譚煥主簿榮壽堂詩爲賦一首因以勉譚','周必大','宋','宋诗','song-poetry','','[]','憶昨淳熙躋壽域，東朝長樂慶七十。',96,'全唐诗/poet.song.143000.json','["憶昨淳熙躋壽域，東朝長樂慶七十。", "譚家有子列冠裳，翁媼同時膺命秩。", "兩宮今奉慈福宮，萬有千歲三宮同。", "十年一講慶壽禮，老人版授方重重。", "煥也曾試南宮裏，一第終當慁子耳。", "從今更闢榮壽堂，他日郊封詔填委。"]'),
('097ea8b2-1702-46c4-ae89-cfc4788ac839','安福宗子師共兄弟五人作慈順堂養母求詩','周必大','宋','宋诗','song-poetry','','[]','五竇曾誇擢桂枝，從今天族更光輝。',32,'全唐诗/poet.song.143000.json','["五竇曾誇擢桂枝，從今天族更光輝。", "會看鼓吹喧龜洛，何止三人從伏妃。"]'),
('3832b6d1-5142-4f31-b630-668d27bfa4df','送廣西譚景先經幹兼簡趙帥朱漕','周必大','宋','宋诗','song-poetry','','[]','舊歷南游上海航，今經鏵觜下灕江。',64,'全唐诗/poet.song.143000.json','["舊歷南游上海航，今經鏵觜下灕江。", "元戎正值詩書帥，廉使曾臨父母邦。", "不憚客從南去再，要陪驛召北來雙。", "水衡自古同丞拜，豈必紅蕖映碧幢。"]'),
('fd35b6e5-f78a-4e80-b51f-1c58506af9d5','永和鎮曾峑季高明秀樓','周必大','宋','宋诗','song-poetry','','[]','心得高明趣，樓開井邑間。',48,'全唐诗/poet.song.143000.json','["心得高明趣，樓開井邑間。", "巡簷風與月，隠几水兼山。", "景物因天巧，軒窗占地慳。", "寒暄俱可至，徙倚不知還。"]'),
('a9819dac-9db5-470c-8fd3-2368873f58f8','次韻馬惟良亦樂園','周必大','宋','宋诗','song-poetry','','[]','滿腹詩書却灌園，固應浩養百憂寬。',64,'全唐诗/poet.song.143000.json','["滿腹詩書却灌園，固應浩養百憂寬。", "竹林松徑長蕭爽，柳色花光自際蟠。", "貢焙延曾春泛雪，鄉醪醉客夜傾丹。", "當年悔不分銀菟，空把新詩反復觀。"]'),
('07de9295-d312-47d4-a715-c630e3a4e13b','紹興丙寅侍伯父赴辰州宿長沙驛今四十七年驛敝重修感舊成詩錄呈子中兄并示子開弟','周必大','宋','宋诗','song-poetry','','[]','朝宗元以汴爲京，閩廣江湖此問津。',64,'全唐诗/poet.song.143000.json','["朝宗元以汴爲京，閩廣江湖此問津。", "南渡苦無三宿客，北征時有五溪賓。", "壯遊我亦深懷舊，傳舍人皆勸作新。", "契闊誰憐今四紀，欲論前事只三人。"]'),
('c86542a2-56b8-4174-be33-13baa14160c8','寄題張元善總領新作楚觀','周必大','宋','宋诗','song-poetry','','[]','章華蕪沒岳陽城，風月還從此地分。',64,'全唐诗/poet.song.143000.json','["章華蕪沒岳陽城，風月還從此地分。", "目極洪流江接漢，胸吞大澤夢連雲。", "年豐棲畝糧盈野，士飽騰槽馬軼羣。", "收取關河報明主，雲臺烟閣佇奇勳。"]'),
('530ea2ab-096a-48d3-b505-38ce91419988','程元成待制書來敘別圃攬有亭葵心秀野二堂之勝見索惡語老病不暇徧賦謾往一篇','周必大','宋','宋诗','song-poetry','','[]','燭引金蓮白玉堂，宮垂銀榜左春坊。',64,'全唐诗/poet.song.143000.json','["燭引金蓮白玉堂，宮垂銀榜左春坊。", "毛曾久倚黄門樹，武子今封召伯棠。", "攬有羨君花竹秀，課無憐我簿書忙。", "欲知兩地相同處，亭午葵心向太陽。"]'),
('f54e71ab-eab6-4731-8afc-cf55dd159599','寄題永新張氏無盡藏堂','周必大','宋','宋诗','song-poetry','','[]','山間明月江上風，取之無禁用不窮。',96,'全唐诗/poet.song.143000.json','["山間明月江上風，取之無禁用不窮。", "仇仙一發醯鷄蒙，往往擇勝貪天功。", "斯堂飛梁挾雙虹，坐客常滿尊不空。", "翰林主人極形容，無奈圓缺雌與雄。", "豈如清都廣寒宮，默存身已遊其中。", "長春不夜四序同，禦寇法善聊相從。"]'),
('4d498548-65b4-4cc4-bde6-a29098114250','紹興三年十月丙辰長沙郡貢士三十人于公堂太守周某賦詩一篇代鹿鳴之歌','周必大','宋','宋诗','song-poetry','','[]','風雅因遺楚，離騷遂變湘。',48,'全唐诗/poet.song.143000.json','["風雅因遺楚，離騷遂變湘。", "江山清得助，日月爛爭光。", "之子俱勍敵，斯文合擅場。", "三元猶未遠，準擬再名坊。"]'),
('7e899f0b-0aed-4271-baba-7d38290ebfca','次韻謝豐叔賈運使','周必大','宋','宋诗','song-poetry','','[]','錦衾留畫省，綉斧上清湘。',48,'全唐诗/poet.song.143000.json','["錦衾留畫省，綉斧上清湘。", "儒以真無敵，臣於遠有光。", "二天臨宴席，五字冠文場。", "晝接行蕃錫，權奇下八方。"]'),
('fd74d47a-2565-40cd-aa16-c2c1b2113f0b','十一月二十七日劉公度徐用之許相過公度居憂止酒用之偶食素適有餉小春團茶者因成拙詩奉簡','周必大','宋','宋诗','song-poetry','','[]','平日何曾忘穆生，如今胡不飲公榮。',64,'全唐诗/poet.song.143000.json','["平日何曾忘穆生，如今胡不飲公榮。", "頗嫌性僻嵇中散，爲怕情傷阮步兵。", "美意正須羹碧澗，衰顔聊復飯青精。", "更携天上新圓月，同試沙瓶雪水清。"]'),
('86d8ec5c-2179-4857-9bc2-76d72149059e','資正殿學士蕭照鄰挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','科甲早巍巍，官曹總帝畿。',48,'全唐诗/poet.song.143000.json','["科甲早巍巍，官曹總帝畿。", "間嘗森畫戟，畢竟踐黄扉。", "衣鉢傳兒輩，笙歌徹妓圍。", "百年盈省陌，何翅古來稀。"]'),
('c9b083b3-50c0-41c8-be1b-108b938d743e','資正殿學士蕭照鄰挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','共政時雖少，同朝日最多。',48,'全唐诗/poet.song.143000.json','["共政時雖少，同朝日最多。", "聯鏕趨鶴禁，列饌祝鷄窠。", "平昔顔常好，歸來鬢未皤。", "飛昇尋乃祖，示病笑維摩。"]'),
('4990befb-ea3f-4ec5-ac01-d572425478da','寄題謝昌國尚書桂山堂','周必大','宋','宋诗','song-poetry','','[]','京國薪如桂，家山桂滿林。',48,'全唐诗/poet.song.143000.json','["京國薪如桂，家山桂滿林。", "葉留經歲碧，花雨盛秋金。", "作楫商舟穩，爲梁漢殿深。", "幽香宜自閟，莫待斧斤尋。"]'),
('0798fad2-381d-4149-b730-8cf1f64a41b7','任漕子嚴挽詞','周必大','宋','宋诗','song-poetry','','[]','壯志宵興著祖鞭，雄辭銳欲勒燕然。',64,'全唐诗/poet.song.143000.json','["壯志宵興著祖鞭，雄辭銳欲勒燕然。", "一生僅踏金門地，半世常遊玉笥天。", "勝墅棋高無敵手，奪袍句好有新編。", "高風高上凌雲閣，那復觀梅月照筵。"]'),
('1c255499-791c-44bd-9301-521c90a51c76','程元成待制寵示和篇其自序用樂天尹洛并一漁翁事可謂精切嘆服不已再次韻奉酬','周必大','宋','宋诗','song-poetry','','[]','侍冠早已掛朝堂，鄉縣榮標晝錦坊。',64,'全唐诗/poet.song.143000.json','["侍冠早已掛朝堂，鄉縣榮標晝錦坊。", "尚記香山曾尹洛，更同魯國欲漁棠。", "春風醉客金絲緩，夜燭彈棋玉石忙。", "應笑汲卿猶未去，强扶衰病理淮陽。"]'),
('fc5e89a7-1bd7-49cb-85de-d52de3718285','胡元之提刑寺丞迂塗相過寵示二詩次韻爲謝兼簡趙再可經略張君量運使  其一','周必大','宋','宋诗','song-poetry','','[]','惠政郡州楷，清名萬口傳。',48,'全唐诗/poet.song.143000.json','["惠政郡州楷，清名萬口傳。", "南交需按察，北闕正詳延。", "契分元重複，封疆互接連。", "勞歸知有日，還佇楚江邊。"]'),
('565e0aee-7440-44ca-b826-7275191c178a','胡元之提刑寺丞迂塗相過寵示二詩次韻爲謝兼簡趙再可經略張君量運使  其二','周必大','宋','宋诗','song-poetry','','[]','外計初馳傳，元戎久奏功。',48,'全唐诗/poet.song.143000.json','["外計初馳傳，元戎久奏功。", "馬牛非北海，鷄犬是新豐。", "梅萼三冬綠，榴花四季紅。", "德星臨越分，桂海即吳中。"]'),
('8dc91f59-37ba-4b60-bf08-0e1919834b15','送孫從之秘監歸朝供職','周必大','宋','宋诗','song-poetry','','[]','蚤看媠鵬萬里風，晚陪劍履大明宮。',64,'全唐诗/poet.song.143000.json','["蚤看媠鵬萬里風，晚陪劍履大明宮。", "誰知九郡提封廣，還許三年使事同。", "我合掛冠尋舊隠，君當補衮用新功。", "中興盛事人應說，五紀吾邦四少蓬。"]'),
('42049a65-ac77-4c90-ae2d-1f76bcaff01d','臘旦大雪運使何同叔送羊羔酒拙詩爲謝','周必大','宋','宋诗','song-poetry','','[]','未雪兵厨已擊鮮，雪中從事到尊前。',64,'全唐诗/poet.song.143000.json','["未雪兵厨已擊鮮，雪中從事到尊前。", "淺斟未辦銷金帳，快瀉聊憑藥玉船。", "醉夢免教園踏菜，富兒休詫饌羅羶。", "爛頭自合侯關內，何必移封向酒泉。"]'),
('8de91a31-ef34-4bef-8601-d825510ea5f7','上巳訪楊廷秀賞牡丹于御書匾榜之齋其東園僅一畝爲術者九名曰三三徑意象絕新','周必大','宋','宋诗','song-poetry','','[]','楊監全勝賀監家，賜湖豈比賜書華。',64,'全唐诗/poet.song.143000.json','["楊監全勝賀監家，賜湖豈比賜書華。", "四環自斸三三徑，頃刻常開七七花。", "門外有田聊伏臘，望中無處不烟霞。", "却慚下客非摩詰，無畫無詩只謾誇。"]'),
('214c2e58-8edf-4d04-a61a-07a411a2ab2c','王才臣求園中六詩楊秘監謝尚書皆賦 莊敬日强齋','周必大','宋','宋诗','song-poetry','','[]','曲禮毋不敬，聖門恭而安。',24,'全唐诗/poet.song.143000.json','["曲禮毋不敬，聖門恭而安。", "少成復習慣，心廣仍體胖。"]'),
('0828ce21-cc1a-4530-aa6e-0ed48bbd7f79','王才臣求園中六詩楊秘監謝尚書皆賦 格齋','周必大','宋','宋诗','song-poetry','','[]','世事環無端，聖功井有汔。',24,'全唐诗/poet.song.143000.json','["世事環無端，聖功井有汔。", "欲知至不至，密驗物交物。"]'),
('a41cb723-0563-4d39-aba4-e553205556fb','王才臣求園中六詩楊秘監謝尚書皆賦 南谷','周必大','宋','宋诗','song-poetry','','[]','志士非匏瓜，焉能繫不食。',24,'全唐诗/poet.song.143000.json','["志士非匏瓜，焉能繫不食。", "毋安白駒空，請放鳴騶入。"]'),
('593e8917-de00-4c5a-aa72-9c4377e6c504','王才臣求園中六詩楊秘監謝尚書皆賦 竹亭','周必大','宋','宋诗','song-poetry','','[]','良夜月篩影，清晨風掃壇。',24,'全唐诗/poet.song.143000.json','["良夜月篩影，清晨風掃壇。", "自合侯千戶，何須斬萬竿。"]'),
('aa6a5f90-1869-48dd-94e5-48fa8375b3a6','王才臣求園中六詩楊秘監謝尚書皆賦 松菴','周必大','宋','宋诗','song-poetry','','[]','冬與滕六宜，夏與趙盾敵。',24,'全唐诗/poet.song.143000.json','["冬與滕六宜，夏與趙盾敵。", "更有茯苓功，保君千歲質。"]'),
('ee6e70a0-635a-4709-b21e-dabfd2421015','王才臣求園中六詩楊秘監謝尚書皆賦 腴亭','周必大','宋','宋诗','song-poetry','','[]','雨浥燕脂落，肌豐骨肉勻。',24,'全唐诗/poet.song.143000.json','["雨浥燕脂落，肌豐骨肉勻。", "方知杜陵老，曾寫此花真。"]'),
('7f858584-7da4-4559-978c-c2b87a544688','孝宗皇帝挽詩二首  其一','周必大','宋','宋诗','song-poetry','','[]','聖德高難繼，天心遠莫推。',48,'全唐诗/poet.song.143000.json','["聖德高難繼，天心遠莫推。", "如何堯舜主，不與武宣時。", "勤政精彌厲，平戎志竟齎。", "唯留大風句，千古日星垂。"]'),
('c34cf8ea-6d69-49ad-a6cc-be823796d2cd','孝宗皇帝挽詩二首  其二','周必大','宋','宋诗','song-poetry','','[]','移御重華意，微臣粗探端。',48,'全唐诗/poet.song.143000.json','["移御重華意，微臣粗探端。", "思陵三載服，文母萬年歡。", "方侍瑶池宴，俄藏禹穴冠。", "餘生卧江海，空有淚成丹。"]'),
('fc0e59a6-41d9-4bca-917a-e0e922be8542','十月九日陳誠之送菊花小詩奉答','周必大','宋','宋诗','song-poetry','','[]','十月風霜動，籬邊菊始黄。',24,'全唐诗/poet.song.143000.json','["十月風霜動，籬邊菊始黄。", "從來司曆過，失不閏重陽。"]'),
('c0bb9ecf-fdcb-4a3b-8298-e282309808ba','僕營小圃方兩月而張坦夫示腴莊圖有起予之意輒成鄙句','周必大','宋','宋诗','song-poetry','','[]','百年種德十年栽，映带雲巖與月臺。',64,'全唐诗/poet.song.143000.json','["百年種德十年栽，映带雲巖與月臺。", "無問四時留客醉，何曾一日不花開。", "人人爭羨富登覽，物物豈知工剪裁。", "我比樊須身更老，只今學圃亦悠哉。"]'),
('1f1fe89b-e0e8-44dd-882f-3ebf25371ddf','慶元乙卯某與歐陽伯威葛德源俱年七十適敝居落成乃往時同試之地小集圃中再用潞公韻成鄙句并錄舊詩奉呈','周必大','宋','宋诗','song-poetry','','[]','結茅近市壓平川，圍棘爭門想少年。',64,'全唐诗/poet.song.143000.json','["結茅近市壓平川，圍棘爭門想少年。", "鹿記楊侯歌始舉，鶴歸丁令化飛仙。", "詩場曾作推敲手，文會今隨出入肩。", "同甲唱酬殊未已，首篇聊記老而傳。"]'),
('37db637d-5284-4747-ad1a-9c6940d6d26f','春日早起  其一','周必大','宋','宋诗','song-poetry','','[]','謾有衣冠已卷懷，本無車馬可驚猜。',32,'全唐诗/poet.song.143000.json','["謾有衣冠已卷懷，本無車馬可驚猜。", "春來早起關何事，點檢園花幾種開。"]'),
('e69278c9-bffc-460c-b96c-60e91c62fcd5','春日早起  其二','周必大','宋','宋诗','song-poetry','','[]','樓上雲山逐望來，樓前花木及時開。',32,'全唐诗/poet.song.143000.json','["樓上雲山逐望來，樓前花木及時開。", "老夫脚力猶强在，不記登臨日幾迴。"]'),
('5dbcb56d-f9f2-4fc1-ad0b-8512ae9cad46','寄楊廷秀待制','周必大','宋','宋诗','song-poetry','','[]','共作槐忙五十春，交情非復白頭新。',32,'全唐诗/poet.song.143000.json','["共作槐忙五十春，交情非復白頭新。", "却思此地初傾蓋，舊事重論有幾人。"]'),
('8420de7e-0b16-4141-b912-88fa51dcb896','臨賀太守簡挽詞','周必大','宋','宋诗','song-poetry','','[]','宣力曾揚善，何人范轄如。',48,'全唐诗/poet.song.143000.json','["宣力曾揚善，何人范轄如。", "一身忘險阻，多士極吹噓。", "幕府誰無敵，君才獨有餘。", "主賓俱已矣，懷舊渺愁予。"]'),
('c1edfdcb-ac41-42b5-80ad-e6039f0d81df','西昌陳誠之送黄樓芍藥仍枉長篇老懶不能次韻戲答二絕句連歲許紅都未至末章及之  其一','周必大','宋','宋诗','song-poetry','','[]','芍藥名先記鄭風，那因嘉木辨雌雄。',32,'全唐诗/poet.song.143000.json','["芍藥名先記鄭風，那因嘉木辨雌雄。", "姚黄後出今亡矣，合把黄樓列上公。"]'),
('7c221c02-84ec-49b8-8f19-2f6e7479a7f3','西昌陳誠之送黄樓芍藥仍枉長篇老懶不能次韻戲答二絕句連歲許紅都未至末章及之  其二','周必大','宋','宋诗','song-poetry','','[]','六一先生舊帥揚，分寧太史尹西昌。',32,'全唐诗/poet.song.143000.json','["六一先生舊帥揚，分寧太史尹西昌。", "只緣未睹紅都勝，便似參謀待海棠。"]'),
('ab35b3dc-ead8-4cb2-bd64-45c7e6b29663','送道士張唯深','周必大','宋','宋诗','song-poetry','','[]','出世須拋世俗文，休論何遜與陰鏗。',32,'全唐诗/poet.song.143000.json','["出世須拋世俗文，休論何遜與陰鏗。", "但求仙伯三年艾，會向彌明頂上行。"]'),
('a00792a4-c61d-4a4f-b46d-52e12c6c7ff2','彭孝求以綠野行送芍藥數種鄙句爲謝','周必大','宋','宋诗','song-poetry','','[]','占斷春光及夏初，琉璃剪葉朵珊瑚。',64,'全唐诗/poet.song.143000.json','["占斷春光及夏初，琉璃剪葉朵珊瑚。", "休論花品同而異，且詠詩人樂且訏。", "北第莫辭金鑿落，南禪爭看玉盤盂。", "彭宣微恙何妨醉，自有嬌癡婢子扶。"]'),
('105cc018-f8e3-4860-a226-ba7322eae996','魚兒牡丹得之湘中花紅而蕊白狀類雙魚累累相比枝不能勝壓而下垂若俛首然鼻目良可辨葉與牡丹無異亦以二月開因是得名其幹則芍藥也予命曰花嬪而賦是詩聞江東山谷間甚多','周必大','宋','宋诗','song-poetry','','[]','天教姚魏主芳菲，合有宮嬪次列妃。',64,'全唐诗/poet.song.143000.json','["天教姚魏主芳菲，合有宮嬪次列妃。", "玉頸圓瑳宜粉面，霞裙深染學翬衣。", "枝頭窈窕魚雙貫，風裏蹁躚鳳對飛。", "莫把根苗方芍藥，留春不似送將歸。"]'),
('4507231e-66f0-43d7-8188-584276610364','子中兄再示新詩以妃爲僭次韻解嘲','周必大','宋','宋诗','song-poetry','','[]','妃即嬪嬙非並后，公卿雖備要嚴徐。',64,'全唐诗/poet.song.143000.json','["妃即嬪嬙非並后，公卿雖備要嚴徐。", "黄裳敢僣夫人服，紫袖聊瞻御坐裾。", "石韞山輝元倚玉，媠飛海運本名魚。", "莫因韓李同佳傳，便廢千年太史書。"]'),
('61e3dd0f-c429-4868-bd3c-153e265ab490','太守趙山甫示和篇次韻爲謝','周必大','宋','宋诗','song-poetry','','[]','阿嬌金屋聚芳菲，當御銀環序妾妃。',64,'全唐诗/poet.song.143000.json','["阿嬌金屋聚芳菲，當御銀環序妾妃。", "龍女墜天頩素頰，鮫人出水織纁衣。", "袖垂戶外瞻雙引，燕在宮中第一飛。", "不用蟲魚箋爾雅，使君行合左符歸。"]'),
('55b08064-0b77-4a8f-b73d-aa78a5c8e127','李子權屢求所居江月亭浴沂齋詩老病未能作坐上示及和花妃詩甚工即席次韻一首所謂一彩兩賽也','周必大','宋','宋诗','song-poetry','','[]','姚皇去後幾菲菲，湘水依然從二妃。',64,'全唐诗/poet.song.143000.json','["姚皇去後幾菲菲，湘水依然從二妃。", "雙淚一時紅作鬣，連枝千載綠爲衣。", "檻前斑竹應同伴，波面文鴛欲共飛。", "吟徧世間閒草木，何如江月詠沂歸。"]'),
('36c3fc13-1df6-4877-b486-aba28c7b8680','楊廷秀秘監萬花川谷中洛花甚富乃用野人韻爲魚兒牡丹賦詩光榮多矣惡語敘謝','周必大','宋','宋诗','song-poetry','','[]','萬花川谷第芳菲，也許湘靈媵伏妃。',64,'全唐诗/poet.song.143000.json','["萬花川谷第芳菲，也許湘靈媵伏妃。", "翠葉迎風牽荇带，紅綃浴日濕宮衣。", "共船不妬龍陽釣，警乘猶疑洛渚飛。", "誰把荒園一魚目，換將五十六珠歸。"]'),
('efb02932-aef0-421d-a43a-b81cccc8afd6','題劉訥畫趙韓魏王文潞公司馬溫公歐陽文忠公王荆公蘇文忠公黄太史像','周必大','宋','宋诗','song-poetry','','[]','勳業文章各致身，精神未易寫丹青。',32,'全唐诗/poet.song.143000.json','["勳業文章各致身，精神未易寫丹青。", "八朝三百年間事，付與承明著作廷。"]'),
('fbb3ec9d-a678-4a86-89b0-d4f2e65d6cd7','廷秀用進退韻格賦奉祠喜罷感思詩次韻','周必大','宋','宋诗','song-poetry','','[]','壽宮均逸跨三年，諫紙停書剩幾番。',64,'全唐诗/poet.song.143000.json','["壽宮均逸跨三年，諫紙停書剩幾番。", "聞道君王開獻納，豈容公子散神仙。", "東華行踏京塵軟，南澗休貪釣石溫。", "三字底須論十字，券錢何似給餐錢。"]'),
('64046524-d990-4ecf-a384-be5426015b63','臨川梁譯投冰溪救母謝昌國作孝德記楊廷秀有詩次其韻譯不仕年四十九而終  其一','周必大','宋','宋诗','song-poetry','','[]','王祥名冠晉公卿，大節寧非爲剖冰。',32,'全唐诗/poet.song.143000.json','["王祥名冠晉公卿，大節寧非爲剖冰。", "救母如梁真篤孝，奈何不貴不長生。"]'),
('648ac8f3-e091-4295-94d9-2a06904afa2a','臨川梁譯投冰溪救母謝昌國作孝德記楊廷秀有詩次其韻譯不仕年四十九而終  其二','周必大','宋','宋诗','song-poetry','','[]','商丘本意得珍珠，河曲淫隈不可臨。',32,'全唐诗/poet.song.143000.json','["商丘本意得珍珠，河曲淫隈不可臨。", "親已顛危心更切，眼看寒谷乃平林。"]'),
('01cbbe4a-4488-43f8-81ff-7a9326709aa3','李得善賦絕句疑麕爲鹿按廣韻注鹿云麞屬注麞云鹿屬爾雅亦各言之故說文專指麕爲麞則與鹿爲二物明矣次韻求教','周必大','宋','宋诗','song-poetry','','[]','麞頭安得比麋茸，紋點胎斑更異同。',32,'全唐诗/poet.song.143000.json','["麞頭安得比麋茸，紋點胎斑更異同。", "爾雅昔嘗窺郭璞，方言今試問楊雄。"]'),
('0c8f407a-e544-4206-a5d7-ea8ab6022675','寄題太和胡氏福榮堂','周必大','宋','宋诗','song-poetry','','[]','福備天教百順并，應須富貴又長生。',64,'全唐诗/poet.song.143000.json','["福備天教百順并，應須富貴又長生。", "九霄慶澤霑身潤，五色綸章照眼明。", "翁媼歲時稱壽禮，兒孫晝夜讀書聲。", "來春更看新先輩，綠綬斑衣分外榮。"]'),
('28189357-5516-4184-8525-40f2551dd6d6','乙卯中秋初夜見月欲登樓而陰五鼓如永和鎮省七兄月色如晝','周必大','宋','宋诗','song-poetry','','[]','携壺擬欲上層樓，雲掩冰輪且罷休。',32,'全唐诗/poet.song.143000.json','["携壺擬欲上層樓，雲掩冰輪且罷休。", "誰料五更南柵路，却成邂逅好中秋。"]'),
('ade21ed3-e280-49b8-bd56-40791d4dc000','平園之北有荷花數畝張彥和兄弟以售于予戲作小詩','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','紅紅白白滿方塘，風度人言似六郎。',32,'全唐诗/poet.song.143000.json','["紅紅白白滿方塘，風度人言似六郎。", "屬我屬君何必問，匡廬蓮社有周張。"]'),
('45a09081-2d5a-4d4a-be5d-521f6cadf346','中秋梅桂盛開前所未有黄巖老通判欲賦詩紀異輒以二韻引玉','周必大','宋','宋诗','song-poetry','','[]','巖前丹桂隴頭梅，元是蟾宮一處栽。',32,'全唐诗/poet.song.143000.json','["巖前丹桂隴頭梅，元是蟾宮一處栽。", "怪底今年秋月好，同時仙子下瑶臺。"]'),
('f9505fea-f237-48d9-8ae4-2836893d7d8d','李子西乙卯秋試畢携家兄舊詩相過索次韻','周必大','宋','宋诗','song-poetry','','[]','三日揮毫迥出群，貳師西伐有奇勳。',32,'全唐诗/poet.song.143000.json','["三日揮毫迥出群，貳師西伐有奇勳。", "便從蟾窟升金掌，休戀江東賦暮雲。"]'),
('6ef45cb9-beb6-43d8-9ee7-a161eadd5661','中秋古梅盛開次子中兄韻','周必大','宋','宋诗','song-poetry','','[]','抱甕畦夫破井苔，炎天日日灌陳荄。',32,'全唐诗/poet.song.143000.json','["抱甕畦夫破井苔，炎天日日灌陳荄。", "探支春夜無聲雨，贏得冰花带葉開。"]'),
('e69a919d-28ee-4e5c-906f-61be4e3a4c59','中秋招王才臣賞梅花廷秀待制有詩次韻','周必大','宋','宋诗','song-poetry','','[]','山中無曆記時節，望月巡簷探花發。',96,'全唐诗/poet.song.143000.json','["山中無曆記時節，望月巡簷探花發。", "適看如來金粟布，旋觀姑射膚凝雪。", "春自春兮秋自秋，總把繁枝插滿頭。", "那知上界碧瑶洞，也憶人世逍遥遊。", "梅花雪片偏宜桂，手執新詩心已醉。", "淮陰若肯過舞陽，盧子不羞從若士。"]'),
('10f3924b-f86a-424b-b500-218b1959caf8','歐陽邦基母曾氏挽詞','周必大','宋','宋诗','song-poetry','','[]','章拜通明舊，書刊勸戒新。',48,'全唐诗/poet.song.143000.json','["章拜通明舊，書刊勸戒新。", "誰歟生此子，賢矣若而人。", "慈孝平生事，康寧九十鄰。", "令君千字誄，四美得鋪陳。"]'),
('aaafd55e-2a91-43cd-a402-6bffc68573a9','吉水縣黄塤母歐陽氏挽詞','周必大','宋','宋诗','song-poetry','','[]','歐桂望螺川，遺風女亦賢。',48,'全唐诗/poet.song.143000.json','["歐桂望螺川，遺風女亦賢。", "勉夫于兩造，教子以三遷。", "彤管言無間，金籯業有傳。", "好營高燥地，置此萬家阡。"]'),
('14a70e57-ec2b-44a5-9285-91ff9e4f392c','吳斗南架閣求夢芳亭詩  其一','周必大','宋','宋诗','song-poetry','','[]','屈平流放楚江皋，蕭艾叢中思鬰陶。',32,'全唐诗/poet.song.143000.json','["屈平流放楚江皋，蕭艾叢中思鬰陶。", "君是國香人服媚，詩情端合反離騷。"]'),
('85cfacbc-5577-46e2-86f5-c1cb5ba40665','吳斗南架閣求夢芳亭詩  其二','周必大','宋','宋诗','song-poetry','','[]','枕中莫問熟黄粱，夢裏何妨集衆芳。',32,'全唐诗/poet.song.143000.json','["枕中莫問熟黄粱，夢裏何妨集衆芳。", "芸省翻書慵辟蠹，蘭闈起草會含香。"]'),
('06e1f06a-9e7b-4af7-ac1d-bdf10bd9ad0d','江西漕張送大有年堂酒百壺戲答小詩','周必大','宋','宋诗','song-poetry','','[]','無何日飲口流涎，大有年堂酒滿船。',32,'全唐诗/poet.song.143000.json','["無何日飲口流涎，大有年堂酒滿船。", "孔聖百觚誰敢比，仲由嗑嗑且希賢。"]'),
('f9a31c36-547f-44f6-b40f-8f2a6f6d5fcc','乙卯冬楊廷秀訪平園即事  其一','周必大','宋','宋诗','song-poetry','','[]','乘興不回安道舟，銷憂同倚仲宣樓。',32,'全唐诗/poet.song.143000.json','["乘興不回安道舟，銷憂同倚仲宣樓。", "莫嫌四面酸風射，猶勝三場瀋汗流。"]'),
('e6cb06c2-e507-4cd4-9eaa-97c304d6799f','乙卯冬楊廷秀訪平園即事  其二','周必大','宋','宋诗','song-poetry','','[]','梅得詩翁八月歌，至今萬朵壓枝多。',32,'全唐诗/poet.song.143000.json','["梅得詩翁八月歌，至今萬朵壓枝多。", "明年結子應無數，金鼎調時味正和。"]'),
('d8045bfd-893e-45e3-925f-79985fa824c0','初春巖桂著花詩人太和令君首賦佳篇才臣伯和仲和三友繼作句法高妙不容措辭姑述四句','周必大','宋','宋诗','song-poetry','','[]','蟾窟雲根夜夜新，天台子落四時榮。',32,'全唐诗/poet.song.143000.json','["蟾窟雲根夜夜新，天台子落四時榮。", "君看月桂閒花草，猶似長春竊此名。"]'),
('442d7020-dc89-4611-8628-8f398e43e975','經略待制趙侍郎挽詞','周必大','宋','宋诗','song-poetry','','[]','仙系根蟠李，王孫種自龍。',48,'全唐诗/poet.song.143000.json','["仙系根蟠李，王孫種自龍。", "暮年都督府，早日大司農。", "密印加三品，朝冠掛四松。", "清暉遺跡在，山水爲誰容。"]'),
('d5c700b9-a7b7-46b0-ba82-ef73a54c61f4','送徐淵子知縣朝奉還臺','周必大','宋','宋诗','song-poetry','','[]','聞子才華自石湖，眼看清政似冰壺。',64,'全唐诗/poet.song.143000.json','["聞子才華自石湖，眼看清政似冰壺。", "坊村不識催科吏，亭傳焉知警捕符。", "此去詣臺鳬舉舄，向來行陌雉將雛。", "朝回試望星辰履，倘許吹噓上漢無。"]'),
('cf6a6ce7-b5ff-4791-bbf3-6fc393ed0012','閣皂沖妙陳處和寄蒼玉軒圖仍枉佳篇小詩爲謝','周必大','宋','宋诗','song-poetry','','[]','鵝溪未易掃千尋，龍籜何曾看溢林。',32,'全唐诗/poet.song.143000.json','["鵝溪未易掃千尋，龍籜何曾看溢林。", "誰遣琅玕青我眼，道人披腹有高吟。"]'),
('b4b9f418-fca6-4dba-b3b6-c87b104ec6ef','次韻楊廷秀  其一','周必大','宋','宋诗','song-poetry','','[]','江國群芳自有餘，詩才酒興不愁無。',32,'全唐诗/poet.song.143000.json','["江國群芳自有餘，詩才酒興不愁無。", "却憐西蜀移根遠，醉向東風落筆初。"]'),
('a95dbdc8-676d-43af-8d92-5ba4a26d3f7b','次韻楊廷秀  其二','周必大','宋','宋诗','song-poetry','','[]','傅粉施朱淡復濃，不辭沐雨更梳風。',32,'全唐诗/poet.song.143000.json','["傅粉施朱淡復濃，不辭沐雨更梳風。", "豈知命似佳人薄，不在吾公樂事中。"]'),
('8498105f-184e-46e6-b9f0-5a9052e2bc09','楊子直示還壽皇御批制草熟狀將以新詩歎服匠手走筆奉酬既謝厚貺且爲王春度玉墀之祝','周必大','宋','宋诗','song-poetry','','[]','病渴相如思苦遲，至今夢怯草麻時。',64,'全唐诗/poet.song.143000.json','["病渴相如思苦遲，至今夢怯草麻時。", "鼎湖鑄就龍新去，雲漢章成露尚垂。", "冬日茅簷雖可曝，春風浴殿豈忘思。", "使君自有如綸筆，會踏金鑾契主知。"]'),
('5f412f9f-7523-42c0-b2c1-cc70acb6cd70','茅山劉先覺高士繪雲琴圖求詩次楊廷秀韻','周必大','宋','宋诗','song-poetry','','[]','目送歸雲膝抱琴，山林猶恐不高深。',32,'全唐诗/poet.song.143000.json','["目送歸雲膝抱琴，山林猶恐不高深。", "應憐三十年前客，擾擾塵心損道心。"]'),
('55a1a3af-35b1-4d5c-9509-9a7beb0b8149','廷秀跋雲琴圖記高士被遇阜陵再賦小詩','周必大','宋','宋诗','song-poetry','','[]','羽衣當日望堯雲，薰殿臨風和舜琴。',32,'全唐诗/poet.song.143000.json','["羽衣當日望堯雲，薰殿臨風和舜琴。", "龍已乘雲絃已絕，披圖我亦涕沾襟。"]'),
('0c54af4a-145c-40d3-857e-6af74c167a7c','次韻孫從之侍郎寄題新喻周氏用德堂','周必大','宋','宋诗','song-poetry','','[]','醉經飲德樂厭厭，餘味蓴羹豉下鹽。',32,'全唐诗/poet.song.143000.json','["醉經飲德樂厭厭，餘味蓴羹豉下鹽。", "安得同爲堂上客，共繙三萬軸牙籤。"]'),
('4801ea12-fd77-4cb5-ab2d-b2dde09714d0','次韻楊廷秀待制寄題朱氏渙然書院  其一','周必大','宋','宋诗','song-poetry','','[]','日出杲杲安問螢，弨掛翻翻誰受檠。',32,'全唐诗/poet.song.143000.json','["日出杲杲安問螢，弨掛翻翻誰受檠。", "大哉風行水上渙，一夕泮盡峨峨冰。"]'),
('f7a62454-d4a1-438c-8e18-8475b3b79002','次韻楊廷秀待制寄題朱氏渙然書院  其二','周必大','宋','宋诗','song-poetry','','[]','誠齋萬事悟活法，誨人有功如利涉。',32,'全唐诗/poet.song.143000.json','["誠齋萬事悟活法，誨人有功如利涉。", "嗟我大類醯雞然，時復一窺甕中天。"]'),
('e14d1343-9f8d-4abd-831f-e3465b1f738f','次韻廷秀待制寄題李紀風月無邊樓','周必大','宋','宋诗','song-poetry','','[]','尺壁之珍城價買，寸金之土連郭外。',64,'全唐诗/poet.song.143000.json','["尺壁之珍城價買，寸金之土連郭外。", "豈知風月不論錢，誰主誰賓眼爲界。", "斯樓廣大由心胸，應有嘉客傾坐中。", "厭厭夜飲樂未終，白間已射朝曦紅。"]'),
('5032e54d-d966-4320-aa5d-5d9aff2def91','次韻廷秀待制玉蕊','周必大','宋','宋诗','song-poetry','','[]','姑射山前雪照人，長安水畔態尤真。',64,'全唐诗/poet.song.143000.json','["姑射山前雪照人，長安水畔態尤真。", "步摇翹玉中心整，瓔珞塗金四面勻。", "常笑荼醿藏浪蕊，獨陪芍藥殿餘春。", "自從唐代來天女，直到平園見後陳。"]'),
('c85ed69d-6999-4f9d-ae14-220a30117492','次楊子直使君韻','周必大','宋','宋诗','song-poetry','','[]','雪繭冰絲結素華，天孫初織費繅車。',64,'全唐诗/poet.song.143000.json','["雪繭冰絲結素華，天孫初織費繅車。", "花開金谷空千種，蕊疊瑶英自一家。", "下比山礬誰薄相，上攀瓊木客雄誇。", "集仙翰苑須公等，歸繼唐賢植此花。"]'),
('f32d2a43-a96b-4f7f-af8c-5f0338b4dc7f','次王伯奮通判韻','周必大','宋','宋诗','song-poetry','','[]','三槐交蔭盛京華，八座摛文富五車。',64,'全唐诗/poet.song.143000.json','["三槐交蔭盛京華，八座摛文富五車。", "玉樹合教依故國，霜蕤何事到山家。", "幸經泥軾新題品，全勝雲軿昔誕誇。", "絕唱强酬書字大，固應傳笑眼昏花。"]'),
('caef5c55-9c80-49f9-af34-8c55155ed2ad','林順卿教授兩爲玉蕊花賦長韻富贍清新老病無以奉酬輒用楊使君韻爲謝','周必大','宋','宋诗','song-poetry','','[]','廣文行實稱才華，如節鸞和馭寶車。',64,'全唐诗/poet.song.143000.json','["廣文行實稱才華，如節鸞和馭寶車。", "曾燕瓊林天一握，却吟玉蕊示三家。", "大篇追補唐詩闕，盛事常留魯頖誇。", "別有冰姿延客住，白池賸種白蓮花。"]'),
('ce46f1fd-db5f-43c6-ab11-b1ce550c47f5','三月二十八日春華樓前芍藥盛開招歐葛二兄再爲齊年之集次舊韻','周必大','宋','宋诗','song-poetry','','[]','老去猶思飲吸川，靜中還喜日爲年。',64,'全唐诗/poet.song.143000.json','["老去猶思飲吸川，靜中還喜日爲年。", "艾耆天畀如三壽，談辨人驚似八仙。", "洞鎖嵩峰偏入眼，丹成𡵺嶁遠齊肩。", "定知樂事年年共，更看新詩句句傳。"]'),
('d18fcc45-3998-4271-8a59-a4e8451dc9f1','陳誠之以長句送揚州花仍催踐快閣之約戲答','周必大','宋','宋诗','song-poetry','','[]','清歌句句戛鳴球，紅藥年年具彩舟。',32,'全唐诗/poet.song.143000.json','["清歌句句戛鳴球，紅藥年年具彩舟。", "更約倚晴登快閣，真成騎鶴上揚州。"]'),
('455abd19-db53-43f9-9c10-3911027a5415','題安成劉江報德堂白爵圖','周必大','宋','宋诗','song-poetry','','[]','孝行通穹壤，珍祥應鼓枹。',24,'全唐诗/poet.song.143000.json','["孝行通穹壤，珍祥應鼓枹。", "是家飛白爵，誰子泥青烏。"]'),
('ca1ea00b-b792-40d2-986e-4beba44d92af','錢文季狀元去春用楊吉州子直韻賦玉蕊詩老悖久稽奉酬今承秩滿還朝就以爲餞','周必大','宋','宋诗','song-poetry','','[]','晝攬群芳博物華，夕披衆說聚螢車。',64,'全唐诗/poet.song.143000.json','["晝攬群芳博物華，夕披衆說聚螢車。", "花來北固無新唱，詩到西崑有故家。", "鄉里孝廉流澤遠，弟兄科甲搢紳誇。", "盍歸史館開羣玉，徐步詞垣判五花。"]'),
('1c157b8d-6ebf-480f-8138-92c6fa52308a','趙正則司戶沿檄而歸玉蕊已過追賦車字韻詩奉答','周必大','宋','宋诗','song-poetry','','[]','春深遊客競繁華，寶馬香輪带麯車。',64,'全唐诗/poet.song.143000.json','["春深遊客競繁華，寶馬香輪带麯車。", "不爲來看招隠樹，有誰肯顧野人家。", "飛飛粉蝶鬚相映，皎皎銀蟾色共誇。", "今得審言詩勝畫，傳神何必趙昌花。"]'),
('a6b6aba9-ccbf-47c0-9570-e4bcf4010f51','江西美示古調七篇皆以風雅久寂寞爲首句責僕一言僕素不能詞念此意不可不酬走筆直述所懷而非詩也','周必大','宋','宋诗','song-poetry','','[]','古人足禮義，情動形于言。',72,'全唐诗/poet.song.143000.json','["古人足禮義，情動形于言。", "四始雖不同，如委出一源。", "朅從此道廢，根淺枝葉煩。", "衆作日以工，大本日以諼。", "君欲繼前修，要當養其原。", "第令思無邪，庶幾三百篇。"]'),
('4d1bf541-6af6-4c78-85bc-81bba54d2fba','平園老叟周某敬讀次對兄芙容絕句歎服不已效顰於後','周必大','宋','宋诗','song-poetry','','[]','秋花少似春花紅，眼明見此木芙蓉。',32,'全唐诗/poet.song.143000.json','["秋花少似春花紅，眼明見此木芙蓉。", "斜臨野水作清鏡，似照曉粧濃未濃。"]'),
('1e9d938a-bd07-447b-94aa-8a2934218c29','重九次七兄韻','周必大','宋','宋诗','song-poetry','','[]','追歡尊有酒，適興樂無荒。',48,'全唐诗/poet.song.143000.json','["追歡尊有酒，適興樂無荒。", "風雨如知節，塤箎共陟岡。", "憑高臨鴈翅，履險失羊腸。", "醉墨淋漓處，珍材費樂浪。"]'),
('3134724a-e906-4472-ada5-ce6a19f81350','楊廷秀送牛尾貍侑以長句次韵','周必大','宋','宋诗','song-poetry','','[]','江南十月方肅霜，小槽初滴鵝兒黄。',176,'全唐诗/poet.song.143000.json','["江南十月方肅霜，小槽初滴鵝兒黄。", "頗思指動異味嘗，門正張羅誰末將。", "披綿强來推不去，枯蝦欲進止之戶。", "羊羶豕腥尤可厭，肪截脂凝在何處。", "草玄子雲黄門郎，遺我黑質而白章。", "形之硬語弩力强，寫以奇字侔史蒼。", "愧無纖手色傾國，壓糟磨刀走臧獲。", "喜于左手持蟹黄，美勝八珍熟熊白。", "古來貍首歌侯門，名以牛後真屈君。", "從今玉汝洗俗諺，好與紈袖陪梁園。", "公詩如貂不煩削，我續狗尾句空著。"]'),
('4a087a14-86a9-43b9-9f44-28ed86f2b541','寄題高仲一殿撰識山堂長韻','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','買山老山間，乃識山之容。',288,'全唐诗/poet.song.143000.json','["買山老山間，乃識山之容。", "愛山無古今，此論誰非同。", "仇仙來匡廬，一轉語獨工。", "不識山面目，只緣在山中。", "譬之塵漠漠，又如水溶溶。", "人魚居其間，孰識礙與通。", "我昔少年日，自携七尺筇。", "盤旋山南北，憩息林西東。", "朝看山之橫，暮看山之縱。", "貪多眼爲乏，陟險足已慵。", "拱揖且不暇，賞識良自蒙。", "方悟白司馬，草堂對穹隆。", "彼既若獻狀，此亦如發蒙。", "秀甲天下山，至言出心胸。", "今君欲繼之，築堂會奇峯。", "何嘗遠城市，而能日迎逢。", "山形不動體，山色含真空。", "風雲有蓄洩，氣象無終窮。", "雨餘四面翠，日麗千仞紅。", "氤氳香爐烟，挺拔雙劍鋒。", "最愛五老人，崚嶒美所鍾。", "可望不可即，有意容相從。", "羅列皆兒孫，几席次第供。", "山雖跨兩邦，茲焉實長雄。"]'),
('ab828216-6d86-4e03-8328-a22779065407','凍頭王氏藝芳堂','周必大','宋','宋诗','song-poetry','','[]','一聞編簡香，如入芝蘭室。',48,'全唐诗/poet.song.143000.json','["一聞編簡香，如入芝蘭室。", "况將百尺樓，高貯三萬帙。", "清芬藹階庭，賸馥沾黨術。", "從渠海上夫，顛倒放李赤。"]'),
('9bd3182c-16b6-4096-af25-b1395dfb39e2','丁巳二月甲子蜀錦堂海棠盛開適有惠川綉晝錦堂記者招伯威德源爲齊年會次舊韻','周必大','宋','宋诗','song-poetry','','[]','曾因客夢到西川，萬戶疏封祇隔年。',64,'全唐诗/poet.song.143000.json','["曾因客夢到西川，萬戶疏封祇隔年。", "花重錦官思杜老，鶴飛沙苑看徐仙。", "衰顔尚許任爭齒，淺量深慚賜及肩。", "照眼蜀粧依綉幌，共驚十載讖先傳。"]'),
('5ffe2b6b-08d5-4ef6-9420-616cd41e20c6','二月十二日夜夢奏事','周必大','宋','宋诗','song-poetry','','[]','曾抱疲駑佐聖明，枕中議政似平生。',32,'全唐诗/poet.song.143000.json','["曾抱疲駑佐聖明，枕中議政似平生。", "五更鼓角驚殘夢，彷彿街司報點聲。"]'),
('4fe5d476-6e0a-47c1-8a18-176e585e33bc','晨起有感二首  其一','周必大','宋','宋诗','song-poetry','','[]','楚尹三爲禮未衰，湯衡五就欲持危。',32,'全唐诗/poet.song.143000.json','["楚尹三爲禮未衰，湯衡五就欲持危。", "翺翔不作奔陳計，接淅何堪去魯時。"]'),
('623a356b-1611-44b4-8377-05c98c574772','晨起有感二首  其二','周必大','宋','宋诗','song-poetry','','[]','內禪纔成便乞身，營營衆口尚成城。',32,'全唐诗/poet.song.143000.json','["內禪纔成便乞身，營營衆口尚成城。", "後來進退交相累，何似當初微罪行。"]'),
('7690b037-9053-41df-a331-f4e71471b439','平江顔侍郎挽詩','周必大','宋','宋诗','song-poetry','','[]','吳門自古俊髦多，中外推公政事科。',64,'全唐诗/poet.song.143000.json','["吳門自古俊髦多，中外推公政事科。", "議禮不妨豐酒課，治繁猶暇講禪那。", "榻前屢記宣除目，川上遥憐逐逝波。", "底用鎸碑紀廉直，鄉評正自不消磨。"]'),
('a2b69828-c21c-4e1b-8e31-87b3d7f57bc9','曾無疑以長韻送金橘時已暮春次韻','周必大','宋','宋诗','song-poetry','','[]','荼䕷殿春枝滿霜，盧橘熟夏今乃黄。',128,'全唐诗/poet.song.143000.json','["荼䕷殿春枝滿霜，盧橘熟夏今乃黄。", "彈丸煌煌照坐光，老叟驚詫見未嘗。", "客言採果孟冬月，剖竹爲符带蒼雪。", "包之赫蹏滿貯中，纏以絲枲外合節。", "或藏綠豆因醉翁，或雜寸膏仍緘封。", "三說未識將誰從，但覺色香新摘同。", "分甘安能與衆樂，秘方何惜都傳却。", "已誇指下石化金，仙指并求君勿噱。"]'),
('87ec254e-0a55-4e54-a48d-bb010b067d3a','彭孝求以詩送芍藥云今年厄閏不佳且許紅都勝不至云待明年戲答小詩','周必大','宋','宋诗','song-poetry','','[]','厄閏黄楊古所傳，翻階紅藥豈其然。',32,'全唐诗/poet.song.143000.json','["厄閏黄楊古所傳，翻階紅藥豈其然。", "明年果得真都勝，便是雙鶬一箭穿。"]'),
('58dbd3c9-42f5-4d9d-a580-fb7a7ae163b9','連年視聽不明有耳雨空花之對今歲尤甚戲成小詩','周必大','宋','宋诗','song-poetry','','[]','夜雨稀聞聞耳雨，春花微見見空花。',32,'全唐诗/poet.song.143000.json','["夜雨稀聞聞耳雨，春花微見見空花。", "自憐他日盲宰相，今復癡聾作富家。"]'),
('0e52bbbd-cab1-42c9-9c40-084f816c8cdf','去年孫從之示玉蕊佳篇時過未敢賡和今年此花盛開輒次嚴韻并以新刻辨証爲獻','周必大','宋','宋诗','song-poetry','','[]','食菜曾饕三百囷，種花重看一番新。',64,'全唐诗/poet.song.143000.json','["食菜曾饕三百囷，種花重看一番新。", "洞仙舊賞輪無迹，工部高吟筆有神。", "疊雪雅宜歌白雪，送春仍欲買青春。", "向來僞帖今冰釋，從此佳名徧廣輪。"]'),
('3d127b90-7291-4caa-b82c-2c9e50407df2','張履妻王氏挽詞','周必大','宋','宋诗','song-poetry','','[]','逮事尊嫜日以嚴，退從娣姒一何謙。',64,'全唐诗/poet.song.143000.json','["逮事尊嫜日以嚴，退從娣姒一何謙。", "不愁囊橐金珠減，但喜園林錦綉添。", "四德助成家赫赫，一身寧計病懨懨。", "歸尋二稚應無憾，况有良人爲發潜。"]'),
('8072894e-1d9a-431d-8a30-7dc5cc58c6dd','追挽新永州守張奭妻宜人王氏','周必大','宋','宋诗','song-poetry','','[]','世系蟬聯運紫樞，夫家鱗襲佩銅魚。',64,'全唐诗/poet.song.143000.json','["世系蟬聯運紫樞，夫家鱗襲佩銅魚。", "奉先睦族俱難繼，燾後劬躬總可書。", "身到東南門有爛，年周甲子饋俄虛。", "異時追錫魚軒寵，不及零陵從隼旟。"]'),
('cb24796f-384d-4654-9247-eb99d274e640','永新賀升卿著春秋會正論屢督跋戲往','周必大','宋','宋诗','song-poetry','','[]','三傳名家各是非，聖經元自許傳疑。',32,'全唐诗/poet.song.143000.json','["三傳名家各是非，聖經元自許傳疑。", "遲遲著語君知否，游夏猶難措一辭。"]'),
('d18e4871-b8e6-4186-90b7-580f5f761694','江西美錄示新舊詩一篇戲贈二十字于後','周必大','宋','宋诗','song-poetry','','[]','夢筆異文通，詩篇總自工。',24,'全唐诗/poet.song.143000.json','["夢筆異文通，詩篇總自工。", "長哦三伏裏，句句是清風。"]'),
('fe7aee20-2e9c-48e2-a3f9-2bb43358abc9','洪景盧內翰爲甘叔懷作碧崖修造疏戲題小詩奉勸本宮管轄而下諸道友助緣','周必大','宋','宋诗','song-poetry','','[]','碧崖道士拍洪肩，白水真人覓玉泉。',32,'全唐诗/poet.song.143000.json','["碧崖道士拍洪肩，白水真人覓玉泉。", "我似東軒無一物，閣山風月不論錢。"]'),
('12a9171a-6b71-44ab-b151-5a184f58023b','胡氏逢慶堂詩用秉成兄韻','周必大','宋','宋诗','song-poetry','','[]','柿紅萱蘤映階濃，泥紫芝函带璽封。',64,'全唐诗/poet.song.143000.json','["柿紅萱蘤映階濃，泥紫芝函带璽封。", "善積古稱家有慶，身强今看子其逢。", "壽觴莫惜斟三雅，祿養猶期饌萬鍾。", "樂與鄉人傳盛事，老來醉筆任橫縱。"]'),
('ecdce654-934b-47bf-83fc-d49e3492a787','次韻李得善學錄需酒納婦','周必大','宋','宋诗','song-poetry','','[]','合好須憑麯米春，分甘那暇問醨醇。',32,'全唐诗/poet.song.143000.json','["合好須憑麯米春，分甘那暇問醨醇。", "遥知北海招嘉客，共賀東牀得好姻。"]'),
('e0b5e6d2-3db8-4eb8-8200-bff6d248ca51','戊午仲春同甲小集次舊韻','周必大','宋','宋诗','song-poetry','','[]','會老三人似潁川，同生絳縣免疑年。',64,'全唐诗/poet.song.143000.json','["會老三人似潁川，同生絳縣免疑年。", "尊常有酒何妨醉，事每無心即是仙。", "儉欲固應知足足，忘形誰問是肩肩。", "香山已寫丹青像，洛誦仍憑副墨傳。"]'),
('6b504675-dff3-4fbb-9f26-5ac1bc306818','太和彭孝求連年許芍藥紅都勝今方以唐律送一株小詩爲謝','周必大','宋','宋诗','song-poetry','','[]','龍洲舊說紅都勝，象罔今逢赤水珠。',32,'全唐诗/poet.song.143000.json','["龍洲舊說紅都勝，象罔今逢赤水珠。", "更挽春衫來比並，如纏十萬上江都。"]'),
('53e5ba5d-2719-4786-a8e0-621be07db11e','紹興庚午某與安成劉逢辰秋闈同薦逢辰四子伯德禮淳熙甲午解魁登第今宰臨川仲德仁拔癸卯解叔德恭負雋聲季德性紹熙乙卯復冠鄉舉出示當時小錄手澤在焉爲題二小詩於後  其一','周必大','宋','宋诗','song-poetry','','[]','丁年韋布逐槐忙，結綬王畿四紀强。',32,'全唐诗/poet.song.143000.json','["丁年韋布逐槐忙，結綬王畿四紀强。", "只把衣冠掛神虎，夢回猶未熟黄粱。"]'),
('f2df4048-c979-4268-bdca-083c6c945f6e','紹興庚午某與安成劉逢辰秋闈同薦逢辰四子伯德禮淳熙甲午解魁登第今宰臨川仲德仁拔癸卯解叔德恭負雋聲季德性紹熙乙卯復冠鄉舉出示當時小錄手澤在焉爲題二小詩於後  其二','周必大','宋','宋诗','song-poetry','','[]','鹿鳴舊籍晚重看，翰墨場中興久闌。',32,'全唐诗/poet.song.143000.json','["鹿鳴舊籍晚重看，翰墨場中興久闌。", "同榜諸郎皆舉首，老夫安得不衰殘。"]'),
('5874132e-cb0b-49f2-9d7c-332da1adeb57','新光州守趙師奭字國佐才高一世仕京口以讒廢宰太和以憂歸得郡待對沒於逆旅家會稽又遭焚識者閔之今既葬矣其子寄行狀求追挽嗟悼不足情見乎辭','周必大','宋','宋诗','song-poetry','','[]','籍甚天支萬事通，傷哉人爵一生窮。',64,'全唐诗/poet.song.143000.json','["籍甚天支萬事通，傷哉人爵一生窮。", "飛英北固讒何極，游刃西昌秩未終。", "千騎絕憐成畫餠，八人乃忍助融風。", "只因快閣長流水，遺恨滔滔向浙東。"]'),
('ec0a77d6-51c1-4b2d-992e-804713b67e23','劉仙才仲子俊示其父醉菴詩集索鄙句','周必大','宋','宋诗','song-poetry','','[]','蹇步媻珊到竹溪，病眸眩瞀亂金篦。',64,'全唐诗/poet.song.143000.json','["蹇步媻珊到竹溪，病眸眩瞀亂金篦。", "清風滿座無塵事，遺墨盈編有舊題。", "久羨山人居水北，今知詩社續江西。", "醉吟跌宕誰能寫，髣髴琳瑯識介圭。"]'),
('1bafcb8a-2702-4a26-9e5a-1b04b0ee7cf1','子中兄招飲次韵  其一','周必大','宋','宋诗','song-poetry','','[]','青衿學道不憂貧，黄髮相看並乞身。',32,'全唐诗/poet.song.143000.json','["青衿學道不憂貧，黄髮相看並乞身。", "前有二疏今可企，免教人謂魯無人。"]'),
('0a55e051-5a64-4127-9619-8c6c86734eb5','子中兄招飲次韵  其二','周必大','宋','宋诗','song-poetry','','[]','立朝共踏東華土，居里同抽北闕身。',32,'全唐诗/poet.song.143000.json','["立朝共踏東華土，居里同抽北闕身。", "從此清風與明月，尊前真屬兩閒人。"]'),
('b8a85700-997d-4836-ae83-88681cdc270a','慶元戊午重九天氣晴和侍七兄提舉監丞早集清都臺午飯讀書臺晚集神岡西臺皆古迹也戲成小詩','周必大','宋','宋诗','song-poetry','','[]','午風和氣借春來，雨足黄花越節開。',32,'全唐诗/poet.song.143000.json','["午風和氣借春來，雨足黄花越節開。", "要識重陽真富貴，弟兄一日歷三臺。"]'),
('ef12546d-1679-44b0-98be-3f1843beff8c','己未立春留楊伯子知縣小酌夜聞窗竹有聲伯子以爲雪或曰風也已而果雪詰旦敲門送詩走筆戲和','周必大','宋','宋诗','song-poetry','','[]','莫訝衰翁笑口開，故人風度繼歐梅。',64,'全唐诗/poet.song.143000.json','["莫訝衰翁笑口開，故人風度繼歐梅。", "墮簁雪陣魚麗遠，蹋迹詩仙鳳沼來。", "酒似茅柴居膈上，句如桂子落天台。", "新年春日相追逐，誰謂天公厭兩回。"]'),
('84a7e8c4-0b61-4ec6-9d24-ec913060fa79','己未二月十七日會同甲次舊韻','周必大','宋','宋诗','song-poetry','','[]','里仁初不問山川，身健從交換歲年。',64,'全唐诗/poet.song.143000.json','["里仁初不問山川，身健從交換歲年。", "紅紫丁寧容老圃，丹青點化屬詩仙。", "情均鴈序兼鶑友，壽貫犀顱映鶴肩。", "莫筭酒行徵罰令，一株花下一盃傳。"]'),
('7038ad68-3067-4b1a-bdbc-1b458e228298','送韓希道移漕江東','周必大','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','饋餉隨蕭不作難，秦淮今視漢秦關。',64,'全唐诗/poet.song.143000.json','["饋餉隨蕭不作難，秦淮今視漢秦關。", "天開虎踞龍蟠處，地近雞翹豹尾間。", "洗印先經三峽寺，觀風徧踏九華山。", "盡收奇秀歸詩稿，却趁賡歌供奉班。"]'),
('bac984b9-fe68-4b88-9cee-d2755af1b4ac','賀升卿年垂八十以詩寄平園新詠二十二篇又錄十年前簡予四詩尚有訪戴之興謹次最後一章韻爲謝','周必大','宋','宋诗','song-poetry','','[]','文與年高豈樂天，字隨心正亦公權。',64,'全唐诗/poet.song.143000.json','["文與年高豈樂天，字隨心正亦公權。", "吟詩作賦晴窗裏，問柳尋花野水邊。", "喜我新巢三徑就，勞君舊句一時編。", "雪舟有興休回棹，共載期追李郭仙。"]'),
('6e7bc5d6-65fc-4080-8b6d-b7f4098e2fe0','朱叔止通判屢示詩詞綽有家法輒次年字韵一篇兼簡汪仲嘉敷學樓大防顯學二尚書','周必大','宋','宋诗','song-poetry','','[]','筆勢奔騰决大川，談鋒激烈敵丁年。',64,'全唐诗/poet.song.143000.json','["筆勢奔騰决大川，談鋒激烈敵丁年。", "花開共入長春苑，柯爛爭看不老仙。", "西笑君先聽漢履，上征我未拍洪肩。", "從今日日親漁釣，恐有三賢尺素傳。"]'),
('abd91cca-c511-460d-b164-cd337de0c6ac','仲嘉致政敷學尚書汪兄寵和鄙句且寄適軒記詩銘等皆慕白樂天語也敬以來意盡用樂天事次韻','周必大','宋','宋诗','song-poetry','','[]','鄞川人物擬三川，公似香山更永年。',64,'全唐诗/poet.song.143000.json','["鄞川人物擬三川，公似香山更永年。", "楊柳夭桃俱是幻，蓬萊兜率孰非仙。", "平生名脫虞卿曆，歲晚詩齊夢得肩。", "近岸連檣多賈客，定携新句海東傳。"]'),
('8e3fc2e5-396d-45be-ba95-c1c14155cd95','顯學尚書樓大防奉九十六歲之親戲綵未央古今鮮儷遠蒙五詩皆和鄙句謹次韻爲慶','周必大','宋','宋诗','song-poetry','','[]','萱堂眉壽正增川，手種蟠桃莫計年。',64,'全唐诗/poet.song.143000.json','["萱堂眉壽正增川，手種蟠桃莫計年。", "得道身陪金母宴，應緣居近寶陀仙。", "煌煌八座歡承膝，濟濟諸孫戲疊肩。", "家慶新圖爭快覩，願將摹本寄郵傳。"]'),
('dab6a8bf-7e98-4625-be51-6cf8dd142257','奉酬新劍南守朱叔止次舊韵寵寄之什','周必大','宋','宋诗','song-poetry','','[]','竹使分符化劍川，政成應不俟期年。',64,'全唐诗/poet.song.143000.json','["竹使分符化劍川，政成應不俟期年。", "買臣聊引會稽綬，長倩即登廷尉仙。", "棋戶雖高猶易敵，詩壇彌峻却難肩。", "通家有契無纖隙，惡語深藏莫遍傳。"]'),
('03368c98-06dd-4069-8b12-202e1e54bef7','徐商老參議直閣進書登瀛創儒榮堂來索鄙句許示奏稿寄題','周必大','宋','宋诗','song-poetry','','[]','三孔三劉歲月賒，後來儒術數君家。',64,'全唐诗/poet.song.143000.json','["三孔三劉歲月賒，後來儒術數君家。", "五枝舊折燕山桂，八月新乘海上槎。", "方履圓冠無愧怍，西崑東觀有光華。", "牙籤縱許窺青簡，銀海何堪眩黑花。"]'),
('9c2f6405-8223-4aa6-ba4c-74b886983fc2','多葉白牡丹一幹兩花其一重臺其一每葉之上間以青純前所未聞名之曰青白圭蓋用司馬相如檄析圭注白藏天子青分諸侯也爲賦此詩','周必大','宋','宋诗','song-poetry','','[]','品極王封壺有妃，其餘國艷視諸姬。',64,'全唐诗/poet.song.143000.json','["品極王封壺有妃，其餘國艷視諸姬。", "上黄貴紫知無敵，藏白分青合付誰。", "舊譜由來虛爵邑，新名此去備藩維。", "古之兄弟方華鄂，今以公侯屬縹枝。"]'),
('d727e0c9-51af-4d36-a7a8-15bce3c748d1','參政李秀叔挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','憶昨淳熙謹萬微，再登耆哲貳繁機。',64,'全唐诗/poet.song.143000.json','["憶昨淳熙謹萬微，再登耆哲貳繁機。", "謀猷入告宸心沃，俊乂旁招物望歸。", "惠斂十連遺愛遠，年開九秩近臣稀。", "全名備福公何憾，念舊傷情涕自揮。"]'),
('14af32aa-a059-45b7-a8f5-636a8a100e57','參政李秀叔挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','十載山林號後谿，三朝鍾鼎列前疑。',64,'全唐诗/poet.song.143000.json','["十載山林號後谿，三朝鍾鼎列前疑。", "進賢自許唐師德，持論人推蕭望之。", "玉立諸郎傳素業，金聲高弟振清規。", "送車遠莫陪千兩，誄行深慚措一辭。"]'),
('ba3e7867-6c9e-40fe-b5ee-b2f80db4833d','三月三日適值清明會客江樓共觀並蒂魏紫偶成二小詩約坐客同賦  其一','周必大','宋','宋诗','song-poetry','','[]','上巳清明共一時，魏花開處亦連枝。',32,'全唐诗/poet.song.143000.json','["上巳清明共一時，魏花開處亦連枝。", "前身應是唐宮女，猶記昭容雙袖垂。"]'),
('4a7f197a-05d3-4024-a1ba-70add9683db0','三月三日適值清明會客江樓共觀並蒂魏紫偶成二小詩約坐客同賦  其二','周必大','宋','宋诗','song-poetry','','[]','修禊歸來却踏青，臨流謀野兩關情。',32,'全唐诗/poet.song.143000.json','["修禊歸來却踏青，臨流謀野兩關情。", "不如省事遊春女，挑菜渚邊看水生。"]'),
('4e3d0b54-ec61-4998-9631-0546570b465e','某昨蒙寶文待制輒送揚州紅都勝欲占小詩敘謝怯大巫而止茲者賢郎明府相過屢索芍藥詩實不曾作謹用前意成四韵拙遲可笑','周必大','宋','宋诗','song-poetry','','[]','紅藥何年有，繁花掃地無。',48,'全唐诗/poet.song.143000.json','["紅藥何年有，繁花掃地無。", "風光分謝砌，根撥記江都。", "兩兩丹山鳳，炎炎赤水珠。", "春衫誰氏女，比並强施朱。"]'),
('e81edcaa-3b0f-40fb-9a42-6ce54bade32a','永新談漢卿求筠坡書院詩用誠齋之韵之意而推廣之','周必大','宋','宋诗','song-poetry','','[]','軒窗彌望猗猗竹，有斐切磋琢磨足。',64,'全唐诗/poet.song.143000.json','["軒窗彌望猗猗竹，有斐切磋琢磨足。", "天籟鳴風異絲木，晝夜鏘金戛球玉。", "碧梧空有栖鳳枝，何如以實飼其兒。", "扶摇下視鴻鵠陂，附翼會集夔龍池。"]'),
('23ac2034-8fff-4cd9-8df6-23076c907ebf','安福孝子朱雲孫血指刲股燃臂愈父母疾化遂行于室家邑上其事于州他日讀待制廷秀楊公所述誌公之文爲題小詩于後','周必大','宋','宋诗','song-poetry','','[]','孝子因親不愛膚，忠臣爲國亦忘軀。',32,'全唐诗/poet.song.143000.json','["孝子因親不愛膚，忠臣爲國亦忘軀。", "一毫不拔何爲者，此姓渠名枉共朱。"]'),
('c14c6102-3051-485a-9c44-ed9bf7608014','無心居士劉君挽詞','周必大','宋','宋诗','song-poetry','','[]','應物無心善自寬，臨財有義肯儒酸。',64,'全唐诗/poet.song.143000.json','["應物無心善自寬，臨財有義肯儒酸。", "竹林逸老多餘慶，鴻苑奇書獨飽觀。", "名父平生淹簿領，佳兒他日紹衣冠。", "追思再世相逢舊，西望梅溪一永歎。"]'),
('645c23fb-c8fe-4fae-919b-d228b52bbf1a','龍學張彥父挽詞','周必大','宋','宋诗','song-poetry','','[]','豈弟基巖邑，名聲起使華。',96,'全唐诗/poet.song.143000.json','["豈弟基巖邑，名聲起使華。", "臺評扶國是，諫紙合謨嘉。", "念昔陪東府，看公肅正衙。", "班齊人立鶚，疏出字飛鴉。", "漢履星辰遠，江祠歲月賒。", "負圖官益峻，賜札禮彌加。", "耄耋常稱道，兒孫競克家。", "歸全無一愧，殄瘁有長嗟。"]'),
('243bc5c4-7c8e-484f-8aba-f3d5c8e48fec','王籍文學求讀書堂詩','周必大','宋','宋诗','song-poetry','','[]','倚相端能記典墳，子羔未可治人民。',64,'全唐诗/poet.song.143000.json','["倚相端能記典墳，子羔未可治人民。", "十年莫作攸之恨，萬卷方知甫也神。", "堂下從渠糟粕議，城南容我簡編親。", "鐵更三擿韋三絕，將聖猶然况後人。"]'),
('22a23a1b-4daf-4be0-a89f-140341075fc4','平園創三層樓子直秘書遠貺新詩有山中宰之句自念掛朝服築層樓偶與陶隠居相符他日倘得壽與之齊則登臨之樂未已也次韵爲謝每句用本傳中語','周必大','宋','宋诗','song-poetry','','[]','弘景掛冠永明年，築樓三層家政傳。',64,'全唐诗/poet.song.143000.json','["弘景掛冠永明年，築樓三層家政傳。", "俯聽松風輒欣然，時人望之疑是仙。", "天教輕捷遊方外，自喜向來不爲宰。", "耄期猶且有壯容，誓戒何妨臨鄮海。"]'),
('f058ae2e-b7ab-4147-9f66-806eb6deedc9','丙辰七兄有詩及人月分圓己未彼此服藥未能夜坐今次舊韵爲重九之約','周必大','宋','宋诗','song-poetry','','[]','初非遠道思綿綿，自是岑岑懶涉川。',64,'全唐诗/poet.song.143000.json','["初非遠道思綿綿，自是岑岑懶涉川。", "咫尺却成千里隔，蹉跎還負十分圓。", "坐看碧落飛金鏡，遥想黄樓運筆椽。", "寬約重陽各强健，登高同賦去年篇。"]'),
('1b1bc5e0-bad9-4e4d-8cda-22e9a2669bb5','小詩戲王駒甫請來早轉約伯威德源得善彥和志伯西美粹夫及愚卿兄弟共不托一盃已有定例不設他味','周必大','宋','宋诗','song-poetry','','[]','巖桂芙蓉映菊籬，小春仍上海棠枝。',32,'全唐诗/poet.song.143000.json','["巖桂芙蓉映菊籬，小春仍上海棠枝。", "甕頭幸有茅柴酒，來看平園萬戶棋。"]'),
('da880c65-1ab9-4e4a-b3db-0e7c7469baa5','端明殿學士張定叟挽詞','周必大','宋','宋诗','song-poetry','','[]','魏國勳勞四海知，南軒愛直古人遺。',64,'全唐诗/poet.song.143000.json','["魏國勳勞四海知，南軒愛直古人遺。", "中興家世誰如此，季氏豪英尚似之。", "金殿新班將得政，玉麟舊鎮且移麾。", "落星小駐星還落，江路東西總去思。"]'),
('48d0c733-57fb-414b-ba9f-ac4fcb640bcd','次韻楊廷秀待制二首  其一','周必大','宋','宋诗','song-poetry','','[]','十年不侍殿東頭，臨水登山隠者流。',64,'全唐诗/poet.song.143000.json','["十年不侍殿東頭，臨水登山隠者流。", "一眼瞳方無異相，三層勾曲有巍樓。", "幸殊王粲非吾土，何事龐公不入州。", "至後臘前天欲雪，扁舟乘興肯來不。"]'),
('8db1a8af-92c6-4ee9-a4a5-00a08f82d3c3','次韻楊廷秀待制二首  其二','周必大','宋','宋诗','song-poetry','','[]','官府新辭上界仙，碧瑶洞口晉桃源。',64,'全唐诗/poet.song.143000.json','["官府新辭上界仙，碧瑶洞口晉桃源。", "默存常在清都境，歸去休蕪靖節園。", "爲問隆樓并傑閣，何如易野及平原。", "明年大作南溪社，會訪拾遺花柳村。"]'),
('22c9cc33-286e-4f57-8fcd-228bb6a750b5','廬陵主簿李子賢東頃示長牋用劉元城主簿可教事去秋復惠楚詞皆未果答今代還索言老謬勿哂','周必大','宋','宋诗','song-poetry','','[]','地跨江閩秀氣兼，玉成界尺直方廉。',64,'全唐诗/poet.song.143000.json','["地跨江閩秀氣兼，玉成界尺直方廉。", "西曹久處習鑿齒，高士誰知孫子嚴。", "我愧元城題品重，君能楚些筆鋒銛。", "天門底用相吹送，公道今方拔滯淹。"]'),
('0b1c522b-70bb-4af4-9d42-7d0175a2ab36','七兄初約登新樓作重陽敦前歲之盟適病足不能出佳篇送魚酒且及二蘇逍遥堂風雨之句次韵敘謝併爲後約','周必大','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','徧走三臺一日中，前年樂事轉頭空。',64,'全唐诗/poet.song.143000.json','["徧走三臺一日中，前年樂事轉頭空。", "新樓期對萸并菊，舊約翻吟雨與風。", "魚繞長江殊有味，酒篘大甕浩無窮。", "登臨何必拘重九，脚力强時信即通。"]'),
('0c6c8857-90bb-4d3f-9bf6-1195004ae986','讀張敬夫南軒集夜夢賦詩','周必大','宋','宋诗','song-poetry','','[]','道學人爭說，躬行少似君。',48,'全唐诗/poet.song.143000.json','["道學人爭說，躬行少似君。", "中心惟至一，餘事亦多聞。", "湖廣規模遠，濂伊講習勤。", "平生忠與敬，彷彿在斯文。"]'),
('a1decf87-47db-47db-af42-aa0011c47191','慶元庚申華隠樓成其下明農堂新接牡丹亦盛開敬邀伯威德源二兄小集用舊韵','周必大','宋','宋诗','song-poetry','','[]','花接門園記洛川，明農堂畔識豐年。',64,'全唐诗/poet.song.143000.json','["花接門園記洛川，明農堂畔識豐年。", "自量拾級身猶健，共約樓居意欲仙。", "倚檻聊舒千里目，舉頭應側萬人肩。", "那知賓主非劉石，枉作沙河酒席傳。"]'),
('f2354057-6676-49b9-954b-75a99955a2ff','盧帥錢待制之望挽詞','周必大','宋','宋诗','song-poetry','','[]','白鹿爭看擁碧油，貂蟬銳欲出兜鍪。',64,'全唐诗/poet.song.143000.json','["白鹿爭看擁碧油，貂蟬銳欲出兜鍪。", "初官事業追山盜，晚歲功名靜海舟。", "鶴唳八公垂破賊，虎飛萬里欠封侯。", "儒科有子傳衣鉢，積善徐卿慶未休。"]'),
('6e71652f-86ff-4a64-867c-caaddbf0a206','送楊伯子知南昌縣','周必大','宋','宋诗','song-poetry','','[]','往年餞尊公，出宰新吳縣。',72,'全唐诗/poet.song.143000.json','["往年餞尊公，出宰新吳縣。", "仁愛馴桑雉，聖明遇禾絹。", "君今治南昌，家學世其官。", "密令行教化，明庭集孔鸞。", "煌煌牛斗間，寶氣先後應。", "卓魯聚一門，誰續職方乘。"]'),
('602aa1ee-db31-4607-8241-f18e6b611bce','蕭彥育頃年示詩篇且求次誠齋待制所贈佳句之韵嘗許赴省時勉爲之適相過以七步見窘就坐呈老醜聊述本意','周必大','宋','宋诗','song-poetry','','[]','詩勿驚人日以昌，巍科只待賦阿房。',64,'全唐诗/poet.song.143000.json','["詩勿驚人日以昌，巍科只待賦阿房。", "源深元自流三峽，幹老今誰敵豫章。", "肯向洛陽尋白傅，曾從江夏學黄香。", "漠廷結綬君家事，不羨彈冠貢與王。"]'),
('7f6118e9-deed-44c7-9322-3e52b6f51a14','通直郎致仕劉楹挽詞','周必大','宋','宋诗','song-poetry','','[]','殖學摛文衆所推，掾州佐邑譽尤歸。',64,'全唐诗/poet.song.143000.json','["殖學摛文衆所推，掾州佐邑譽尤歸。", "羊羔德備嘗縫革，神虎門高早挂衣。", "斯疾頓乖今者愈，此生誰及古來稀。", "遥瞻烏石岡邊路，挽奠無從只淚揮。"]'),
('769bf530-6467-4f01-9f26-ae44fc24095f','次張子儀抑篇荔枝詩韵','周必大','宋','宋诗','song-poetry','','[]','馹騎塵飛受暑風，絕憐丹臉透青龍。',64,'全唐诗/poet.song.143000.json','["馹騎塵飛受暑風，絕憐丹臉透青龍。", "歐閩後出名高尚，廣蜀先驅品下中。", "遥憶東坡分曬白，預邀老杜賦輕紅。", "明年倘未歸黄闥，生熟何憂更異同。"]'),
('2ee7123f-365a-474f-b8da-d457292ee47a','光宗皇帝挽詩二首  其一','周必大','宋','宋诗','song-poetry','','[]','與進依三善，從遊閲五冬。',48,'全唐诗/poet.song.143000.json','["與進依三善，從遊閲五冬。", "初終存繾綣，議論極從容。", "輔政時雖淺，開藩眷自濃。", "不如仙宅犬，猶從鼎湖龍。"]'),
('98385306-b144-4e50-ba3f-e4e6a7a995d1','光宗皇帝挽詩二首  其二','周必大','宋','宋诗','song-poetry','','[]','仁愛周華夏，英聰貫古今。',48,'全唐诗/poet.song.143000.json','["仁愛周華夏，英聰貫古今。", "知人符日照，裕物稱天臨。", "閒退親傳子，憂勞舊損心。", "景光昭百世，昧谷謾西沉。"]'),
('167268b5-96a7-4255-a407-37fad2255b27','贛守張子智重修思賢閣奉趙清獻公','周必大','宋','宋诗','song-poetry','','[]','霜凝憲簡肅朝衣，日轉熙臺治郡時。',64,'全唐诗/poet.song.143000.json','["霜凝憲簡肅朝衣，日轉熙臺治郡時。", "事道初無中與外，居仁自有勇兼慈。", "甿謠曾詠來何暮，德政常留去後思。", "眼看清規非面友，肩隨畫像是心期。"]'),
('a5d01c94-0f14-427d-adf1-d126dba69c87','余仲鏞從辟廣西示洪景盧所作松風閣記題詩反招隠','周必大','宋','宋诗','song-poetry','','[]','小松風颼颼，長松風冽冽。',48,'全唐诗/poet.song.143000.json','["小松風颼颼，長松風冽冽。", "遥知蒙溪上，餘韵兩清絕。", "宦遊正可樂，歸夢未應切。", "待生丁固腹，徐化莊周蝶。"]'),
('f3e97600-6f63-46ad-8964-5e3a85e9f689','寄題安福朱景源景雲所居二首  其一','周必大','宋','宋诗','song-poetry','','[]','四始昭垂棠棣詩，九江屹立義門碑。',32,'全唐诗/poet.song.143000.json','["四始昭垂棠棣詩，九江屹立義門碑。", "請君更學張公藝，忍字常爲一字師。"]'),
('4cf0e5b0-7afb-45eb-8b31-94690e3182de','寄題安福朱景源景雲所居二首  其二','周必大','宋','宋诗','song-poetry','','[]','友悌人知天亦知，風雷會變籜龍兒。',32,'全唐诗/poet.song.143000.json','["友悌人知天亦知，風雷會變籜龍兒。", "從今直節亭前後，枝茂宗生竹也慈。"]'),
('861d3f32-79a8-4e3a-a60e-c2198d030256','管長源朝奉挽詞','周必大','宋','宋诗','song-poetry','','[]','青袍黄甲舊蜚英，紫綬金章晚更榮。',64,'全唐诗/poet.song.143000.json','["青袍黄甲舊蜚英，紫綬金章晚更榮。", "隠德家傳遼北客，修齡人羨濟南生。", "墓中深刻同年筆，世上難磨異日名。", "識面有時追往事，傷情無路奠佳城。"]'),
('5a746526-465b-43d7-b8e0-7ad526ef41ad','萬安頼秀才家拾青樓二首  其一','周必大','宋','宋诗','song-poetry','','[]','經術逢辰富貴兼，取名銀艾未傷廉。',32,'全唐诗/poet.song.143000.json','["經術逢辰富貴兼，取名銀艾未傷廉。", "更須喚作藏書閣，別貯鄴侯三萬籤。"]'),
('0b043935-1c47-4a76-8da3-76d5a0f1c3df','萬安頼秀才家拾青樓二首  其二','周必大','宋','宋诗','song-poetry','','[]','高柳侵簷带綠烟，平林遥望倚青天。',32,'全唐诗/poet.song.143000.json','["高柳侵簷带綠烟，平林遥望倚青天。", "詩人不必工摹寫，留與恩袍色鬭鮮。"]'),
('51a353ab-6cf4-4034-be1e-5f5cc5952b6c','靜菴曾伯虞挽詞','周必大','宋','宋诗','song-poetry','','[]','往聞郭林山，學易之指南。',72,'全唐诗/poet.song.143000.json','["往聞郭林山，學易之指南。", "艮齋從其子，議論青出藍。", "授徒蘭溪上，妙理常窮探。", "真旨傳何人，著錄推靜菴。", "稱疾似玄晏，觀復師老聃。", "芸芸已歸根，弔客無多談。"]'),
('a4d2f929-3b1d-4987-9da6-1a1115983043','登仕郎曾忠佐迎母王于樂氏母許新居成即歸于是築第高沙極輪奐母欲遷而逝乃虛中堂榜之曰思永爲賦四韻','周必大','宋','宋诗','song-poetry','','[]','夏屋渠渠斲采椽，筍輿就養有成言。',64,'全唐诗/poet.song.143000.json','["夏屋渠渠斲采椽，筍輿就養有成言。", "南陔久嘆薪吹棘，北戶空勞草樹萱。", "堂上只容瞻像設，寢中那復問寒暄。", "朝思夕念嗟何及，彷彿神遊入夢魂。"]'),
('22432602-4dda-42d6-8d05-92c1143a5b42','寄題江陵撫幹胡仲方官舍信美樓  其一','周必大','宋','宋诗','song-poetry','','[]','彼美人兮樓楚都，身親棨戟俯江湖。',32,'全唐诗/poet.song.143000.json','["彼美人兮樓楚都，身親棨戟俯江湖。", "賓僚遂使多賢者，共顧飛鴻亦樂乎。"]'),
('89ff0924-0827-4af2-855c-75e5b7735c97','寄題江陵撫幹胡仲方官舍信美樓  其二','周必大','宋','宋诗','song-poetry','','[]','家在香城溪水邊，冠霞飛閣切雲烟。',32,'全唐诗/poet.song.143000.json','["家在香城溪水邊，冠霞飛閣切雲烟。", "從軍樂事猶吾土，底用銷憂賦仲宣。"]'),
('12fa1d64-82b8-4775-ba24-6e8958dc90b1','追挽胡季文知縣','周必大','宋','宋诗','song-poetry','','[]','萬人競渡一標歸，鄉國今猶記錦衣。',64,'全唐诗/poet.song.143000.json','["萬人競渡一標歸，鄉國今猶記錦衣。", "芹藻再思俱有造，穀蒲連執總成非。", "風吹劍首空遺吷，日照禺中遽落暉。", "宿草縱存無路哭，追懷往事共歔欷。"]'),
('23246057-4e28-4af2-8851-eee36a9a7e4f','送楊子止赴郴守羅達甫之招二首  其一','周必大','宋','宋诗','song-poetry','','[]','使君爲郡入蘇天，六月清風更穆然。',32,'全唐诗/poet.song.143000.json','["使君爲郡入蘇天，六月清風更穆然。", "子到同吟仙井橘，公餘趁賞北湖蓮。"]'),
('2beb8305-550f-4523-86f1-e360bad405ab','送楊子止赴郴守羅達甫之招二首  其二','周必大','宋','宋诗','song-poetry','','[]','誰傳衣鉢付揚雲，卿子文鋒舊冠軍。',32,'全唐诗/poet.song.143000.json','["誰傳衣鉢付揚雲，卿子文鋒舊冠軍。", "主合握蘭賓折桂，來春吉語一時聞。"]'),
('ec1c5251-f7c5-491a-bfad-ffe48aee92a7','七月十四日江西美約周愚卿兄弟及許景陽相過共觀鶴雛羽毛褐色因飲食雙投新酒擘閩中新荔放白蓮池上遂成勝賞明日西美有詩走筆奉和','周必大','宋','宋诗','song-poetry','','[]','起來汗浹似翻漿，客带清風變早凉。',64,'全唐诗/poet.song.143000.json','["起來汗浹似翻漿，客带清風變早凉。", "鶴子曳衣猶淺褐，鵝兒對酒已深黄。", "白蓮近揖三千女，丹荔遐招十八娘。", "但把槐忙付年少，不妨老伴燕林塘。"]'),
('366b1dd3-f851-48bc-a3bc-7681dac182a1','江西美復送四景詩再次韻','周必大','宋','宋诗','song-poetry','','[]','酉歲應知富酒漿，頻年暫輟奏伊凉。',64,'全唐诗/poet.song.143000.json','["酉歲應知富酒漿，頻年暫輟奏伊凉。", "沼蓮不使紅侵碧，池鵠聊容白護黄。", "照坐雖無駢火實，潔尊幸有絡絲娘。", "西風早晚驅殘暑，何日尋盟到野塘。"]'),
('599d35a8-433d-4de6-a28b-59f88ed3df80','時久闕雨回西美柬就附小詩','周必大','宋','宋诗','song-poetry','','[]','君能多益辦，我鼓再而衰。',24,'全唐诗/poet.song.143000.json','["君能多益辦，我鼓再而衰。", "安得催詩雨，心摇畢月離。"]'),
('1ea52b04-359f-4397-97e8-fd45c21bbfb3','三次韻答江西美','周必大','宋','宋诗','song-poetry','','[]','菲飲簞壺食與漿，淡交非復世炎凉。',64,'全唐诗/poet.song.143000.json','["菲飲簞壺食與漿，淡交非復世炎凉。", "佳名誰合戎州綠，妙語端由太史黄。", "無怨不須移孔議，有情未可老徐娘。", "荷香襲坐忘歸興，不覺昏鴉影渡塘。"]'),
('d7859d0e-4eb8-46da-aaa2-c4580ef01eff','四次韻','周必大','宋','宋诗','song-poetry','','[]','只因瑞露酌天漿，解后移尊赴晚凉。',64,'全唐诗/poet.song.143000.json','["只因瑞露酌天漿，解后移尊赴晚凉。", "眼看碧幢擎蓋綠，心慚白鵠立槐黄。", "飲隨人量陳三雅，興入詩懷咏四娘。", "雲黑月離今驗矣，共欣甘雨溢陂塘。"]'),
('19832fcd-4d4a-4891-b19e-1cbd54861b93','五次韻','周必大','宋','宋诗','song-poetry','','[]','客嘉合饋五先漿，竹好仍生一味凉。',64,'全唐诗/poet.song.143000.json','["客嘉合饋五先漿，竹好仍生一味凉。", "天與冰肌勝傅粉，星馳火齊捷飛黄。", "將雛華表疑丁令，喚渡京江憶杜娘。", "屢枉新篇誰可擬，一川烟草賀橫塘。"]'),
('e0c8929f-c16f-4bf6-96b2-7c18caffcbe3','四景詩似欠一篇五更枕上足成之錄呈西美司書勿勞屬和僕亦偃旗閉壘矣','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','甘寒何必柘爲漿，也解逡巡造醴凉。',64,'全唐诗/poet.song.143000.json','["甘寒何必柘爲漿，也解逡巡造醴凉。", "更喜鶴鳴添子和，休因荔進引蕉黄。", "花如宋玉窺鄰女，詩似劉郎問泰娘。", "只欠西湖雙畫舫，便疑風景類錢塘。"]'),
('bc9c73d4-d495-427e-bde5-24b2b693cdce','八月十八日與客小集賞巖桂而紅梅海棠金林檎盛開明日江西美賦四絕句走筆次首篇韻','周必大','宋','宋诗','song-poetry','','[]','壯觀江潮拍岸時，肯來小圃訪樊遲。',32,'全唐诗/poet.song.143000.json','["壯觀江潮拍岸時，肯來小圃訪樊遲。", "天憐無以娛嘉客，併發春花伴桂枝。"]'),
('d3817005-9869-4026-af4c-e3fefda73b37','龍泉李宗儒師儒兄弟槐陰書院','周必大','宋','宋诗','song-poetry','','[]','君不見漢京辟雍載黄圖，博士直舍三千區。',134,'全唐诗/poet.song.143000.json','["君不見漢京辟雍載黄圖，博士直舍三千區。", "分行數百曰槐市，下有諸生講唐虞。", "又不見本朝肇啟邇英閣，稽古隆儒號經幄。", "風清枝翠似交舞，日暖花黄時細落。", "君家欣慕名書齋，伯仲方將與計偕。", "橋門且陪億萬計，朝路終馳十二街。", "義郴文章妙天下，引喻牛行相君舍。", "勉君植德企前修，他日兒孫攀逸駕。"]'),
('449d0415-fe00-4004-8e42-69aa1967dc29','龍泉項汝弼字唐卿盧溪書院','周必大','宋','宋诗','song-poetry','','[]','往聞澹菴評鄉賢，有朋曰項如箎塤。',128,'全唐诗/poet.song.143000.json','["往聞澹菴評鄉賢，有朋曰項如箎塤。", "是非褒貶乃枝葉，孝友忠信爲本根。", "姓名不願唱上第，詔旨特許旌高門。", "化行同邑得模楷，經授猶子留淵源。", "輕財重義續前烈，築屋貯書貽後昆。", "誰能漸磨入我室，毋但涉獵游其藩。", "泉江况乃多侍從，遠親二郭近則孫。", "學成衮衮上臺省，健翮萬里看騰騫。"]'),
('92c42d30-fd46-463d-9534-902611e60166','寄題龍泉李氏萬卷堂','周必大','宋','宋诗','song-poetry','','[]','斷簡殘編已可披，排籤插架有餘師。',64,'全唐诗/poet.song.143000.json','["斷簡殘編已可披，排籤插架有餘師。", "五三載籍多爲貴，九百虞初小不遺。", "潤屋殊非阿堵物，傳家自是寧馨兒。", "老來鉛槧心猶在，每憶讎書館殿時。"]'),
('22a1a9bc-07e0-4d5c-90d4-196dda18df7e','安福歐陽紹之奉議桃花石二絕句  其一','周必大','宋','宋诗','song-poetry','','[]','蟠桃一綻歲三千，仙傳荒唐未必然。',32,'全唐诗/poet.song.143000.json','["蟠桃一綻歲三千，仙傳荒唐未必然。", "何似此花留巧石，有開無落更長年。"]'),
('da590c86-e63f-4c52-af22-f0c5e5e8152c','安福歐陽紹之奉議桃花石二絕句  其二','周必大','宋','宋诗','song-poetry','','[]','武陵溪畔古桃源，洞合空勞記往還。',32,'全唐诗/poet.song.143000.json','["武陵溪畔古桃源，洞合空勞記往還。", "晉代漁郎心不轉，隨花化石在人間。"]'),
('e4fef28d-23c7-4116-91a6-4524db872061','嚴寬桂巖堂二絕句  其一','周必大','宋','宋诗','song-poetry','','[]','巖桂標名本在山，城居翻以桂爲巖。',32,'全唐诗/poet.song.143000.json','["巖桂標名本在山，城居翻以桂爲巖。", "香浮仙籍書生事，早拜恩袍映彩衫。"]'),
('03cdbdf2-b193-48b8-88b2-a0eb1e0a9837','嚴寬桂巖堂二絕句  其二','周必大','宋','宋诗','song-poetry','','[]','卜築華堂已八年，花因舊植有新添。',32,'全唐诗/poet.song.143000.json','["卜築華堂已八年，花因舊植有新添。", "廣寒何待中秋到，明月清風即步蟾。"]'),
('48b91ac9-e186-4b25-8c8e-5a66a8bae754','次韵章茂獻謝茶','周必大','宋','宋诗','song-poetry','','[]','墨談名高筆有花，胸中五色補皇家。',64,'全唐诗/poet.song.143000.json','["墨談名高筆有花，胸中五色補皇家。", "諫書夜奏常焚稿，講舌時乾每賜茶。", "秘祝重尋丹竈火，長生元笑紫河車。", "新詩有味知何似，雙井春來試白芽。"]'),
('3592982e-b3c9-4224-8935-f173dad5a445','太和宰趙嘉言  其一','周必大','宋','宋诗','song-poetry','','[]','爭渡行人簇水邊，水中鮫鰐慣垂涎。',32,'全唐诗/poet.song.143000.json','["爭渡行人簇水邊，水中鮫鰐慣垂涎。", "從今何待跛男子，共載誰非利涉川。"]'),
('f1796ff8-5bf4-4ccf-88e9-602795ac294f','太和宰趙嘉言  其二','周必大','宋','宋诗','song-poetry','','[]','攤酒催錢吏打門，那堪嫁娶畫朱陳。',32,'全唐诗/poet.song.143000.json','["攤酒催錢吏打門，那堪嫁娶畫朱陳。", "稍捐官府秋毫利，散作鄉村浩蕩春。"]'),
('b48c9e00-6547-411b-a756-227414ae5e90','太和縣丞廳葺三亭于官廨曰真清曰特秀曰成蹊又有讀書臺龍首池寄題三疊  其一','周必大','宋','宋诗','song-poetry','','[]','古來丞尚涉文書，近世何曾識吏胥。',32,'全唐诗/poet.song.143000.json','["古來丞尚涉文書，近世何曾識吏胥。", "不對溪山種桃李，官居真復似僧居。"]'),
('02556cd2-a35b-4dc1-9313-74956e96e1a6','太和縣丞廳葺三亭于官廨曰真清曰特秀曰成蹊又有讀書臺龍首池寄題三疊  其二','周必大','宋','宋诗','song-poetry','','[]','松竹林中讀異書，公餘有味在三餘。',32,'全唐诗/poet.song.143000.json','["松竹林中讀異書，公餘有味在三餘。", "立之猶未登臺閣，予不負丞丞負予。"]'),
('d6002086-3c2d-46a0-9c95-c5cc43e788ae','太和縣丞廳葺三亭于官廨曰真清曰特秀曰成蹊又有讀書臺龍首池寄題三疊  其三','周必大','宋','宋诗','song-poetry','','[]','池疏龍首水循除，日暖游鯈得自如。',32,'全唐诗/poet.song.143000.json','["池疏龍首水循除，日暖游鯈得自如。", "官已忘機民正樂，魚今知我我知魚。"]'),
('13fc72ab-613e-4221-b40d-5f2024ebc265','送綸丞郡章貢','周必大','宋','宋诗','song-poetry','','[]','雞犬新豐識，江山清獻游。',48,'全唐诗/poet.song.143000.json','["雞犬新豐識，江山清獻游。", "吾寧忘舊隠，汝且事賢侯。", "剩酌廉泉水，徐題戲彩樓。", "明年更强健，亦欲理方舟。"]'),
('54de8b1f-3373-4e9f-952b-9ee95e5f817c','華文閣學士沈持要挽詞  其一','周必大','宋','宋诗','song-poetry','','[]','百篇奧穾上規姚，一代英靈水出苕。',64,'全唐诗/poet.song.143000.json','["百篇奧穾上規姚，一代英靈水出苕。", "使節帥符周郡國，天臺儲禁切雲霄。", "趨庭祿養連三組，御極恩章接四朝。", "行馬施門兼五福，死生窮達祇囂囂。"]'),
('941beb6d-1500-49db-989c-3b62b2378e68','華文閣學士沈持要挽詞  其二','周必大','宋','宋诗','song-poetry','','[]','宦遊到處績皆凝，名遂歸來望更增。',64,'全唐诗/poet.song.143000.json','["宦遊到處績皆凝，名遂歸來望更增。", "棋勢晝翻饒國手，蒲團夜坐敵禪僧。", "風標常憶清如鶴，書札頻通細若蠅。", "戲綵堂空詩版在，禾興耆舊傳吳興。"]'),
('45b031b0-8872-4541-8d5c-beb5551a4930','寄題贛簿彭南夫讀書樓二絕  其一','周必大','宋','宋诗','song-poetry','','[]','曾門嘗佐虎頭州，濟美人猶羨督郵。',32,'全唐诗/poet.song.143000.json','["曾門嘗佐虎頭州，濟美人猶羨督郵。", "三仕今看孫又子，會持麾節繼前修。"]'),
('4f32b93d-46b6-41b8-b15d-f7015e3b1159','寄題贛簿彭南夫讀書樓二絕  其二','周必大','宋','宋诗','song-poetry','','[]','江山不怕簿書迷，鸞鳳何妨枳棘棲。',32,'全唐诗/poet.song.143000.json','["江山不怕簿書迷，鸞鳳何妨枳棘棲。", "公退讀書消永夜，遥知太乙下青藜。"]'),
('8b46ca17-6036-4b63-a237-0fde74a9a1ea','劉訥畫廬陵三老圖求詩','周必大','宋','宋诗','song-poetry','','[]','同辭宦路返鄉閭，兩驌驦中間以駑。',64,'全唐诗/poet.song.143000.json','["同辭宦路返鄉閭，兩驌驦中間以駑。", "前後顧瞻羞倚玉，支干引從偶連珠。", "三人不用邀明月，九老何妨續畫圖。", "從漢二疏唐尹後，相新相近此應無。"]'),
('6c02c236-fcbb-487d-83e7-2080cefb6d1c','西美司書賦生瑇瑁佳篇仍索鄙句奉和一首','周必大','宋','宋诗','song-poetry','','[]','衷甲藩身却誤身，誰教全體點斑鱗。',64,'全唐诗/poet.song.143000.json','["衷甲藩身却誤身，誰教全體點斑鱗。", "幸容生致池中物，忍使刳爲席上珍。", "剩買魚鹽便爾性，閒隨龜鶴稱吾真。", "却思御合紋如豆，侍食鈞天二十春。"]'),
('5660a666-07f6-45b5-baad-049645a506b7','走筆再次西美韵兼簡季章','周必大','宋','宋诗','song-poetry','','[]','天教尤物伴閒身，不爲衣裳易介鱗。',64,'全唐诗/poet.song.143000.json','["天教尤物伴閒身，不爲衣裳易介鱗。", "莫效盧亭思辟毒，且同李閣賦潜珍。", "釦金元重名兼器，飾带空號假象真。", "久侍尚方叨賜予，新凉來醉茇堂春。"]'),
('0cb65563-4c2e-4624-b8c0-351382910001','次韵楊廷秀待制瑞香花','周必大','宋','宋诗','song-poetry','','[]','灞橋忍凍兩眉攢，漢殿含香別一般。',64,'全唐诗/poet.song.143000.json','["灞橋忍凍兩眉攢，漢殿含香別一般。", "粉面固宜垂紫袖，錦裳何必著中禪。", "禁庭侍史令同宿，宮帽花枝故自欒。", "咀嚼新詩懷舊直，刺貪寧不愧何檀。"]'),
('9e0ce2a4-76bc-45bb-a025-0cac812820e1','廷秀再用韻見寄末句易檀爲蘭故亦不復從前韵','周必大','宋','宋诗','song-poetry','','[]','修竹凌寒劍戟攢，何如綺綉媚千般。',64,'全唐诗/poet.song.143000.json','["修竹凌寒劍戟攢，何如綺綉媚千般。", "爐薰錦帳朝衣夾，花顫金釵舞袖禪。", "少態山茶空艷艷，多姿梅蕊恨欒欒。", "西清垂意君知否，應記青綾握舊蘭。"]'),
('babd58e4-1ef1-4209-8a9a-629d1fde9625','丞相余端禮挽詞','周必大','宋','宋诗','song-poetry','','[]','勳業良平亞，聲名丙魏齊。',96,'全唐诗/poet.song.143000.json','["勳業良平亞，聲名丙魏齊。", "擎天安玉座，推轂聚金閨。", "鄉墅休鵬翼，沙堤望馬蹄。", "新麾辭海上，舊治樂湘西。", "豈料占飛鵩，真成夢白雞。", "九重思汝礪，三鎮有兒啼。", "昔者同朝久，公乎不我睽。", "八哀空日誦，一束幾時携。"]'),
('b182b8a7-5d1d-41ba-8970-1cb51727cb8c','楊子直秘書以一詩送小兒歸省又一絕及平園花木校文苑英華併次韵發笑  其一','周必大','宋','宋诗','song-poetry','','[]','老去何心悅盛華，觀書無奈眼昏花。',32,'全唐诗/poet.song.143000.json','["老去何心悅盛華，觀書無奈眼昏花。", "但思載酒揚雄宅，細問三州二部家。"]'),
('3ee4a49a-0c94-416e-ac24-a4ce513f6763','楊子直秘書以一詩送小兒歸省又一絕及平園花木校文苑英華併次韵發笑  其二','周必大','宋','宋诗','song-poetry','','[]','栽花種竹滿平園，人道安閒似樂天。',32,'全唐诗/poet.song.143000.json','["栽花種竹滿平園，人道安閒似樂天。", "自笑鉛黄消永日，何如蠻素樂華年。"]'),
('72dd6937-3fc0-4e1b-bedb-6eceb334cab2','壬戌冬至胡季亨伯信仲威叔賢相過洛花一朵正開置酒賞之王南劍偶遣矮人獻笑坐中以開閉長短爲戲因成四韵','周必大','宋','宋诗','song-poetry','','[]','霽色舒圭景，寒醅艷玉杯。',48,'全唐诗/poet.song.143000.json','["霽色舒圭景，寒醅艷玉杯。", "關譏方且閉，國色已先開。", "幸有佳賓客，將何助笑咍。", "共言長至日，底事矮人來。"]'),
('7a554010-777a-420b-9b1c-fce29d273a13','嘉泰癸亥元日口占寄呈永和乘成兄','周必大','宋','宋诗','song-poetry','','[]','歸田初不隔江淮，底事新元未往來。',64,'全唐诗/poet.song.143000.json','["歸田初不隔江淮，底事新元未往來。", "賭酒彈棋真夢爾，膠牙藍尾亦悠哉。", "莫思樂事年年減，且喜春花日日開。", "兄弟相看俱八十，研朱贏得祝嬰孩。"]'),
('0e3326d1-bf5d-460f-a71e-1fbd384ed5ef','正月三日胡季亨及伯信仲威叔賢昆仲歐陽宅之李達可同自永和來雨中小集疊岫閣用金鼎玉舟勸酒下視梅林戲舉說命五說戲祝六君蒙次前韵賦佳篇各徵舊事各以一篇爲謝 答胡季亨','周必大','宋','宋诗','song-poetry','','[]','未復中原近守淮，前朝該輔只時來。',64,'全唐诗/poet.song.143000.json','["未復中原近守淮，前朝該輔只時來。", "濟川用礪我無是，作醴和羹何有哉。", "正喜春晴知歲美，頓招兩蕊坐筵開。", "和詩更作齊兒語，老手屠龍合拊孩。"]'),
('6aca6e2b-7b7a-4ce8-ab75-72012daf5d13','正月三日胡季亨及伯信仲威叔賢昆仲歐陽宅之李達可同自永和來雨中小集疊岫閣用金鼎玉舟勸酒下視梅林戲舉說命五說戲祝六君蒙次前韵賦佳篇各徵舊事各以一篇爲謝 答胡伯信','周必大','宋','宋诗','song-poetry','','[]','舟浮江海達于淮，不盡詞源衮衮來。',64,'全唐诗/poet.song.143000.json','["舟浮江海達于淮，不盡詞源衮衮來。", "人是浴沂三益者，句成泛剡兩佳哉。", "千鍾但使尊中滿，九秩從教案上開。", "却憶兒童聚嬉戲，爭騎竹馬弄泥孩。"]'),
('deb8579d-a987-4b00-b690-8f3deca56441','正月三日胡季亨及伯信仲威叔賢昆仲歐陽宅之李達可同自永和來雨中小集疊岫閣用金鼎玉舟勸酒下視梅林戲舉說命五說戲祝六君蒙次前韵賦佳篇各徵舊事各以一篇爲謝 答胡仲威','周必大','宋','宋诗','song-poetry','','[]','元和頌聖雅平淮，韓柳文章付後來。',64,'全唐诗/poet.song.143000.json','["元和頌聖雅平淮，韓柳文章付後來。", "聯璧照人今粲者，斷金定契古誰哉。", "白醪勸我頻霑醉，青眼逢君肯懶開。", "會散東風吹面纈，凍梨忻喜色如孩。"]'),
('e9938585-328f-4d67-a700-77be4c4837cc','正月三日胡季亨及伯信仲威叔賢昆仲歐陽宅之李達可同自永和來雨中小集疊岫閣用金鼎玉舟勸酒下視梅林戲舉說命五說戲祝六君蒙次前韵賦佳篇各徵舊事各以一篇爲謝 答胡叔賢','周必大','宋','宋诗','song-poetry','','[]','朱顔青綬憶秦淮，白鷺洲疑鰲駕來。',64,'全唐诗/poet.song.143000.json','["朱顔青綬憶秦淮，白鷺洲疑鰲駕來。", "側畔交游欣作者，中間賡和負康哉。", "新春漸覺風光好，陳迹時將日記開。", "惟有詩情不如昔，旁觀撫掌倒綳孩。"]'),
('61c78a51-4516-430d-9230-839daf7eb153','正月三日胡季亨及伯信仲威叔賢昆仲歐陽宅之李達可同自永和來雨中小集疊岫閣用金鼎玉舟勸酒下視梅林戲舉說命五說戲祝六君蒙次前韵賦佳篇各徵舊事各以一篇爲謝 答歐陽宅之','周必大','宋','宋诗','song-poetry','','[]','安流咫尺異踰淮，有興何妨疊櫂來。',64,'全唐诗/poet.song.143000.json','["安流咫尺異踰淮，有興何妨疊櫂來。", "茗椀茅柴殊易耳，萍虀豆粥豈難哉。", "談鋒不怕通宵直，燕席寧辭逐日開。", "况是上元佳節近，華燈萬點看蓮孩。"]'),
('60de51c1-5a5a-4e57-8eb0-eb24ede9a4cc','正月三日胡季亨及伯信仲威叔賢昆仲歐陽宅之李達可同自永和來雨中小集疊岫閣用金鼎玉舟勸酒下視梅林戲舉說命五說戲祝六君蒙次前韵賦佳篇各徵舊事各以一篇爲謝 答李達可','周必大','宋','宋诗','song-poetry','','[]','濁涇不必羨清淮，社燕賓鴻任去來。',64,'全唐诗/poet.song.143000.json','["濁涇不必羨清淮，社燕賓鴻任去來。", "老子何曾憑日者，後生正合競時哉。", "圓規枉把方心鑿，塵世常令笑口開。", "八十老翁行未得，不如能說小兒孩。"]'),
('3488c0be-d1d4-4beb-b26b-a86db3355d18','周愚卿江西美劉棠仲各賦江珧詩牽强奉答用一字韻格','周必大','宋','宋诗','song-poetry','','[]','東海沙田種蛤珧，南烹苦酒濯瓊瑶。',64,'全唐诗/poet.song.143000.json','["東海沙田種蛤珧，南烹苦酒濯瓊瑶。", "饌因暫弃常珍變，指爲將嘗異味摇。", "珠剖蚌胎那畏鷸，柱呈馬甲更名䖴。", "累人口腹吾何敢，慚愧三英喜且謠。"]'),
('7addcd79-3e63-45b6-bc09-f978ffb4d03c','元宵煮浮圓子前輩似未嘗賦此坐間成四韵','周必大','宋','宋诗','song-poetry','','[]','今夕知何夕，團圓事事同。',48,'全唐诗/poet.song.143000.json','["今夕知何夕，團圓事事同。", "湯官尋舊味，竈婢詫新功。", "星燦烏雲裏，珠浮濁水中。", "歲時編雜咏，附此說家風。"]'),
('434cc957-22ed-4f99-9a34-62f384ddfdb0','再賦','周必大','宋','宋诗','song-poetry','','[]','時節三吳重，勻圓萬顆同。',48,'全唐诗/poet.song.143000.json','["時節三吳重，勻圓萬顆同。", "溲浮雖有法，烹煮豈無功。", "杜喜雲抄白，徐妨酒復中。", "策勳俱是秫，適口不同風。"]'),
('74ff6d4a-7934-4320-b29d-087a3b571c25','茶園王琰求清暑堂詩次王民瞻敷文胡邦衡資政二公舊韻','周必大','宋','宋诗','song-poetry','','[]','早遮西日覓王官，晚倚南窗審膝安。',64,'全唐诗/poet.song.143000.json','["早遮西日覓王官，晚倚南窗審膝安。", "亹亹清風揮麈落，紛紛蒼雪著笙寒。", "花前白酒傾雲液，竹裏行厨洗玉盤。", "江月上時凉意足，四絃三弄瀉驚湍。"]'),
('e4fa11c4-ff6d-4905-8a80-4272ba8220d8','陳正仲提刑制勘甫畢首過小樓既出新詩仍惠手書十扇次韵二篇致感幸之意  其一','周必大','宋','宋诗','song-poetry','','[]','纔將疑獄决春秋，便顧居鄉馬少游。',64,'全唐诗/poet.song.143000.json','["纔將疑獄决春秋，便顧居鄉馬少游。", "犯斗海槎光斗野，應星漢節照星樓。", "法書飛動鸞窺沼，韵語清高鶴唳洲。", "田父鄰家爭借問，頃來重客有今不。"]'),
('8b725198-91a7-4b57-9dfb-e54e5b35f157','陳正仲提刑制勘甫畢首過小樓既出新詩仍惠手書十扇次韵二篇致感幸之意  其二','周必大','宋','宋诗','song-poetry','','[]','早飛鵰鶚凜橫秋，晚向山林思倦遊。',64,'全唐诗/poet.song.143000.json','["早飛鵰鶚凜橫秋，晚向山林思倦遊。", "夢斷堯階方寸地，身居陶隠上層樓。", "山園遥對青原寺，江勢中分白鷺洲。", "不值熙朝人遂性，果能獨樂此園不。"]'),
('3f1c07e8-0410-47c6-9e6f-3e976628208b','陳正仲提刑輒還嚴近正及郊禋索語贈別適小圃芙蓉同海棠盛開笑令著句併成四韵','周必大','宋','宋诗','song-poetry','','[]','綉衣持斧大江南，人在春風和氣間。',64,'全唐诗/poet.song.143000.json','["綉衣持斧大江南，人在春風和氣間。", "草合園扉秋綠縟，花開環堵曉斕斑。", "席前宣室趍嚴召，樂奏端誠趁近班。", "記取臨分留愛景，芙蓉色鬭海棠殷。"]'),
('87a493b1-6128-433a-a266-c4ef0eb881b0','月石屏蛾月硯詩','周必大','宋','宋诗','song-poetry','','[]','歐公命蘇公，吟咏月石屏。',144,'全唐诗/poet.song.143000.json','["歐公命蘇公，吟咏月石屏。", "蘇公與范子，酬唱涵星泓。", "兩公文字祥，天畀子墨卿。", "嗟予何爲者，而得二美并。", "屏也歐青氈，流傳到柴荆。", "硯兮此尤物，秋月端正生。", "盤拏丹桂枝，瓊繞白玉繩。", "姮娥寔天眼，皎皎不自呈。", "但留雙蛾眉，下鎮蟾兔精。", "我生月斯望，真契非强名。", "烏玦磨有光，玄雲潤無聲。", "願賡前賢句，透脅令人驚。"]'),
('55b72f09-028a-4139-b21a-a509350df09d','悼亡之後病齒不能食拔去其甚者有感賦小詩','周必大','宋','宋诗','song-poetry','','[]','咀嚼勞劬八十年，更因缺落拔其殘。',32,'全唐诗/poet.song.143000.json','["咀嚼勞劬八十年，更因缺落拔其殘。", "已無韓愈妻堪詫，只欠張蒼乳可餐。"]'),
('f1706751-e40f-41c3-ad55-eb7fc9f26770','元樞陳叔達挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','淡墨名何早，洪鈞轉稍遲。',48,'全唐诗/poet.song.143000.json','["淡墨名何早，洪鈞轉稍遲。", "藝文追伏鄭，德業望臯夔。", "寔事常求是，多聞更闕疑。", "斯民先覺者，人代捨公誰。"]'),
('9dce7272-532c-4cda-a79d-0b3f1ecb7feb','元樞陳叔達挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','聯事麟臺裏，論心鶴禁中。',48,'全唐诗/poet.song.143000.json','["聯事麟臺裏，論心鶴禁中。", "賢愚雖有異，出處不無同。", "解后橋山日，凄凉浙水風。", "兒孫看競爽，門戶慶方隆。"]'),
('d51ac7d3-2edb-4b4a-86b1-ed510afa22a4','胡季亨圃中有觀生亭取觀天地萬物生意楊誠齋賦二詩次韵  其一','周必大','宋','宋诗','song-poetry','','[]','物我都歸造物中，存神過化本同風。',32,'全唐诗/poet.song.143000.json','["物我都歸造物中，存神過化本同風。", "靜觀此理怡然順，豈間深青與淺紅。"]'),
('9fc34704-87e8-42e1-88cd-b9b1cc5e15d6','胡季亨圃中有觀生亭取觀天地萬物生意楊誠齋賦二詩次韵  其二','周必大','宋','宋诗','song-poetry','','[]','只道春榮夏乃亨，誰知四序總生生。',32,'全唐诗/poet.song.143000.json','["只道春榮夏乃亨，誰知四序總生生。", "黄鐘大呂還相處，上下方能著五聲。"]'),
('38616a59-1770-4638-a4bb-e052a0bffac4','臨川貢士徐子比先世有十萬莊今唯一山巋然田間立曰獨秀求予下語因記東坡以是名南康田氏之峰就用此意致登科之祝','周必大','宋','宋诗','song-poetry','','[]','不須十萬憶膏粱，有羨崔莊獨遣荒。',32,'全唐诗/poet.song.143000.json','["不須十萬憶膏粱，有羨崔莊獨遣荒。", "獨秀佳名今暗合，要三二別四壺方。"]'),
('8681af27-4710-47ae-bf35-88908909e67e','某紹興甲子赴試此地卜居今十年三歷秋舉每遇中秋必與親舊歌舞之今歲大病使令輩散遣蕭然偶伯信仲威携子姪相過喜成四韵','周必大','宋','宋诗','song-poetry','','[]','上元甲子此攻堅，卜築安居正十年。',64,'全唐诗/poet.song.143000.json','["上元甲子此攻堅，卜築安居正十年。", "登堞遥觀燈奪晝，歸家却賞月流天。", "丹臺旋葺新爐竈，絳帳都拋舊管絃。", "頼有故人將驥子，功名不斷復青氈。"]'),
('8383eeef-ed11-4869-ab04-b81e6d38dd64','東坡像李伯時作曾無疑藏之命予贊之','周必大','宋','宋诗','song-poetry','','[]','龍章鳳姿，揮斥八極。',40,'全唐诗/poet.song.143000.json','["龍章鳳姿，揮斥八極。", "天心月脅，照映萬物。", "孟子之氣，莊周之文。", "瞻之在前，尚有典型。"]'),
('e0b3d972-ceec-49f7-9db1-18bf0d3e7fae','徐涇教授求六一先生贊','周必大','宋','宋诗','song-poetry','','[]','我不識公，而哀斯文。',40,'全唐诗/poet.song.143000.json','["我不識公，而哀斯文。", "稷言臯謨，宋艷班香。", "四海所宗，一鄉何有。", "瞻之在前，瞠乎若後。"]'),
('9f8a38f3-b7ff-4e8d-8e1c-c342b7381462','又求胡忠簡公贊','周必大','宋','宋诗','song-poetry','','[]','春秋尊王，外攘夷狄。',40,'全唐诗/poet.song.143000.json','["春秋尊王，外攘夷狄。", "幼學壯行，終始惟一。", "凜然英氣，尚父是匹。", "揭之徂征，可却回紇。"]'),
('097ab680-ac10-4f91-adc9-182af155c7f9','宗室公衡真贊','周必大','宋','宋诗','song-poetry','','[]','信厚爲質，溫恭其儀。',20,'全唐诗/poet.song.143000.json','["信厚爲質，溫恭其儀。", "視此標的，盛哉本支。"]'),
('bbdca141-ed30-445f-9b8f-3a9c5d2f3ecd','趙山甫使君爲所部七十老叟記顔索贊','周必大','宋','宋诗','song-poetry','','[]','元亮無適俗韻，醉中强釋形神。',28,'全唐诗/poet.song.143000.json','["元亮無適俗韻，醉中强釋形神。", "置我青原臺上，不勞半道邀迎。"]'),
('619e859d-8354-4988-98ba-a428d3ba7652','友人曾無疑示予真索贊','周必大','宋','宋诗','song-poetry','','[]','懶逐溪風偶度雲，聊同江月戲分身。',32,'全唐诗/poet.song.143000.json','["懶逐溪風偶度雲，聊同江月戲分身。", "誰知鄭馹多佳客，也著駘佗一惡人。"]'),
('81c0c061-6b18-468a-b15e-dea4617b22ce','劉氏兄弟寫予真求贊時年七十','周必大','宋','宋诗','song-poetry','','[]','骨相屯，氣宇塵。',40,'全唐诗/poet.song.143000.json','["骨相屯，氣宇塵。", "濁不盈，臞不清。", "視汝形，肖汝身。", "無古心，無時名。", "乃久生，真幸民。"]'),
('7173ae0b-a7f0-48f3-bca6-ee550bf16d2b','梁光遠以予真置邱壑中','周必大','宋','宋诗','song-poetry','','[]','野巖非汝肖，山澤稱吾臞。',24,'全唐诗/poet.song.143000.json','["野巖非汝肖，山澤稱吾臞。", "珍重梁高士，深知謝幼輿。"]'),
('7cda0c14-d525-4189-ad43-f3098ad87998','太和貢士陳誠之記予顔欲置遠明樓昔白傅年七十一寫真詩云鶴毳變綠髮雞膚換朱顔予今年適同感而賦此','周必大','宋','宋诗','song-poetry','','[]','巍樓必欲稱元龍，須寫褒公與鄂公。',32,'全唐诗/poet.song.143000.json','["巍樓必欲稱元龍，須寫褒公與鄂公。", "鶴毳雞膚吾老矣，祇宜簑笠釣船中。"]'),
('d4655ea7-aac6-44fb-82e2-0b5ccd2a767f','慶元丁巳予與伯威歐陽兄德源葛兄三講丙午齊年會德源之子玢繪三壽圖求贊月日皆丙午也','周必大','宋','宋诗','song-poetry','','[]','三爲衆，一日壽。',32,'全唐诗/poet.song.143000.json','["三爲衆，一日壽。", "粃糠前，珠玉後。", "非面朋，乃益友。", "松竹鶴，同耐久。"]'),
('0ddf01bd-018d-42db-8fe9-95fa3ce9ed5a','南城吳氏記予七十三歲之顔','周必大','宋','宋诗','song-poetry','','[]','蟠木離奇，病鶴摧頹。',40,'全唐诗/poet.song.143000.json','["蟠木離奇，病鶴摧頹。", "以若形骸，而卜襟懷。", "無才無能，不競不猜。", "十目所視，人焉廋哉。"]'),
('7ee75a72-dfa0-4f59-bd99-c447263cc52e','聶倅寫真求贊','周必大','宋','宋诗','song-poetry','','[]','三年監州再攝州，家置繪像爭借留。',64,'全唐诗/poet.song.143000.json','["三年監州再攝州，家置繪像爭借留。", "便當紫綬朝冕旒，念我青笠操漁舟。", "携此鼠目而麞頭，歸來高閣包春秋。", "他年持節尋舊游，却校形容知似不。"]'),
('7aa8fb29-e6db-44f7-97fc-de38c4337795','紹興甲子予待試廬陵辭曹廳是秋失解後六年乃與計偕考官七人今惟提刑少監趙氏獨壽而康其子仲肅來爲掾即詩人堂之西闢小齋記予肄業之所寫真求贊併題二詩  其一','周必大','宋','宋诗','song-poetry','','[]','未冠來隨舉子忙，當時已似失林獐。',32,'全唐诗/poet.song.143000.json','["未冠來隨舉子忙，當時已似失林獐。", "而今年貌那堪畫，手種堂前樹亦蒼。"]'),
('fad2b6e3-e23f-40cd-a6d8-f5d49a399ab5','紹興甲子予待試廬陵辭曹廳是秋失解後六年乃與計偕考官七人今惟提刑少監趙氏獨壽而康其子仲肅來爲掾即詩人堂之西闢小齋記予肄業之所寫真求贊併題二詩  其二','周必大','宋','宋诗','song-poetry','','[]','五十餘春一遠莊，耕夫雖老未拋荒。',32,'全唐诗/poet.song.143000.json','["五十餘春一遠莊，耕夫雖老未拋荒。", "審言堂上新司戶，子厚書中顧十郎。"]'),
('7a1b60ba-2eb2-4995-a7bd-4a8b687ee4d9','高沙曾良臣築思堂以念親傍闢書閣肖楊誠齋及予像求贊','周必大','宋','宋诗','song-poetry','','[]','德行淵騫，曾參曷遺。',40,'全唐诗/poet.song.143000.json','["德行淵騫，曾參曷遺。", "蓋生也後，其年可推。", "遥遥華胄，古今與稽。", "誠齋則賢，我愧思齊。"]'),
('076dc938-37e8-472a-a375-645751627850','游元齡登仕寫予真求贊','周必大','宋','宋诗','song-poetry','','[]','休誇歲歲花相似，莫歎年年貌不同。',32,'全唐诗/poet.song.143000.json','["休誇歲歲花相似，莫歎年年貌不同。", "閒伴長松與龜鶴，免將開落問東風。"]'),
('91434954-9cdd-48f5-8984-ddb19c11e387','門客鄭安世寫壽星求贊','周必大','宋','宋诗','song-poetry','','[]','誰把江西一幸民，强摹南極老人星。',32,'全唐诗/poet.song.143000.json','["誰把江西一幸民，强摹南極老人星。", "穹龜鹿鶴朋三壽，伴我松根斸茯苓。"]'),
('49c424db-c4fb-4b76-bc68-e032811df6eb','趙倅彥璨寫予真求贊','周必大','宋','宋诗','song-poetry','','[]','王父當年此治中，嗟予鬢角未成童。',32,'全唐诗/poet.song.143000.json','["王父當年此治中，嗟予鬢角未成童。", "只因闔郡攀泥軾，何事偏圖鶴髮翁。"]'),
('bcef1a96-ded2-4006-9cff-4b915c34375d','英德邵守之綱記予衰顔戲題數語','周必大','宋','宋诗','song-poetry','','[]','使君燕頷虎頭，法當萬里封侯。',59,'全唐诗/poet.song.143000.json','["使君燕頷虎頭，法當萬里封侯。", "宜伯蜀而之廣，繪象祠于兩州。", "鈴閣雖非麟閣，胡爲畫此獼猴。", "亦如杭人效穆仲，獻笑于坡代俳優耶。"]'),
('8d5d87ab-58e0-43df-9ef9-f74e2cc6dd12','登仕郎張武來求一言因記衰顔就以勉之','周必大','宋','宋诗','song-poetry','','[]','德人之容，如玉其溫。',40,'全唐诗/poet.song.143000.json','["德人之容，如玉其溫。", "參前倚衡，以瞻以儀。", "我愧于是，將焉取斯。", "所貴者三，歸有餘師。"]'),
('14282742-7034-40ed-8d15-0304c22b2c95','予乾道中嘗除延平守閩憲皆當赴而改晚得富沙趨行甚峻亦不果赴今郡人吳岷寫真求贊因以遺之','周必大','宋','宋诗','song-poetry','','[]','三度除書下七閩，勒回深愧北山文。',32,'全唐诗/poet.song.143000.json','["三度除書下七閩，勒回深愧北山文。", "勞君爲寫山中相，要與邦人識使君。"]'),
('b708885a-e565-4c51-b3ea-cc7e09f61162','永豐監稅黄思義寫予真于大椿之下戲題','周必大','宋','宋诗','song-poetry','','[]','鬢髮皤然八十春，若爲百倍比莊椿。',32,'全唐诗/poet.song.143000.json','["鬢髮皤然八十春，若爲百倍比莊椿。", "藉令十此如彭祖，亦是雞窠九世人。"]'),
('4b403dab-0e12-4e3b-9fd4-0b161f7fca00','張孜仲寅寫予真倚松而立戲題','周必大','宋','宋诗','song-poetry','','[]','曾陪漢幄運前籌，也忝分封萬戶留。',32,'全唐诗/poet.song.143000.json','["曾陪漢幄運前籌，也忝分封萬戶留。", "未問家傳黄石法，且來閒伴赤松遊。"]'),
('0a5f2662-e25d-459a-84e3-7c0264e5b5dc','陸務觀之友杜敬叔寫予真戲題四句他日持似務觀一笑','周必大','宋','宋诗','song-poetry','','[]','西百官中識放翁，四年上下日相從。',32,'全唐诗/poet.song.143000.json','["西百官中識放翁，四年上下日相從。", "如今鶴伴山雞舞，羞對雲間陸士龍。"]'),
('4ff813e2-dbc8-4cf0-b118-bf9e5efd637f','李卿月子西記予七十七歲之顔求贊','周必大','宋','宋诗','song-poetry','','[]','太白天才丐後人，有時佳句似陰鏗。',32,'全唐诗/poet.song.143000.json','["太白天才丐後人，有時佳句似陰鏗。", "我無飯顆哦詩苦，枉被渠嘲太瘦生。"]'),
('f283a8de-b6e3-43cc-a895-06bbbb3427a3','鄭準廣文赴官九江携予真索贊','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','曾爲匡廬十日留，今猶化蝶夢江州。',32,'全唐诗/poet.song.143000.json','["曾爲匡廬十日留，今猶化蝶夢江州。", "憑君五老峯頭問，員外容添此老不。"]'),
('ffc493a6-bbd4-4939-a9ab-8f97bd7a0ffc','吉水贊府王覲時可爲平園寫真口占小詩','周必大','宋','宋诗','song-poetry','','[]','皓首相逢涉四年，君歸鄱水我螺川。',32,'全唐诗/poet.song.143000.json','["皓首相逢涉四年，君歸鄱水我螺川。", "清風明月思玄度，試展丹青即儼然。"]'),
('b2ce5f06-58b6-4e40-bd2f-fc852db5fd3c','徐教授寫予真求贊','周必大','宋','宋诗','song-poetry','','[]','雖非戚戚小人儒，亦豈堂堂大丈夫。',32,'全唐诗/poet.song.143000.json','["雖非戚戚小人儒，亦豈堂堂大丈夫。", "寫向廣文官舍裏，巍冠爲我講唐虞。"]'),
('7766caf7-d387-42aa-ac1a-8b609f679507','一甲子前與濟源李綦儀之遊從贛上今其婿謝幼學傳示衰容爲題四句','周必大','宋','宋诗','song-poetry','','[]','早同短李客南康，晚識渠家玉潤郎。',32,'全唐诗/poet.song.143000.json','["早同短李客南康，晚識渠家玉潤郎。", "自笑頭顱并目睫，依然如鼠復如麞。"]'),
('68d8ba8f-80a9-4789-ab21-11fe427c00cb','山谷自贊云作夢中夢見身外身福唐曾錫盛談西湖水晶宮之勝因寫予真用此意題四句','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','大患都緣有此身，笑看身外假爲真。',32,'全唐诗/poet.song.143000.json','["大患都緣有此身，笑看身外假爲真。", "夢中更作西湖夢，誰謂先生不到閩。"]'),
('70489092-b5d5-456c-b03b-b2796b086ebe','予平生願學忠恕既以自勉亦告于人王牒正則聞而悅之歸作唯齋九萬里風斯下矣寫衰容命之贊','周必大','宋','宋诗','song-poetry','','[]','中心爲忠，如心爲恕。',53,'全唐诗/poet.song.143000.json','["中心爲忠，如心爲恕。", "勉强行之，道其殆庶。", "苟憎鬷蔑之貌惡，而廢一言于堂下。", "則所謂唯之與阿，不能以寸而相去矣。"]'),
('c3416dbb-92f7-4b84-baf0-7979ac310a28','教官福唐劉季新寫陋質道以羽客索贊還鄉福乃提刑臺治僕嘗出使陛辭而留情見乎詞','周必大','宋','宋诗','song-poetry','','[]','带山負海，都督全閩。',40,'全唐诗/poet.song.143000.json','["带山負海，都督全閩。", "臨遣綉斧，言輟其行。", "夢想樂郊，或勤宵征。", "令威化鶴，會遊遼城。"]'),
('4be447e5-0db1-439e-a27b-83734c9a6ae6','本覺長老祖宏爲老兄弟寫真求贊次七兄韻','周必大','宋','宋诗','song-poetry','','[]','幅巾短褐雁行秋，不照青銅不倚樓。',32,'全唐诗/poet.song.143000.json','["幅巾短褐雁行秋，不照青銅不倚樓。", "今耄昔童無異性，世間寒暑任遷流。"]'),
('25d4bf56-5a83-4755-a0ff-8e1a0112e7c7','能仁監寺智超爲予寫真求贊','周必大','宋','宋诗','song-poetry','','[]','前生坐下一高僧，失脚中元自怨辰。',32,'全唐诗/poet.song.143000.json','["前生坐下一高僧，失脚中元自怨辰。", "但記本來真面目，何須悔現宰官身。"]'),
('856d68d7-10c8-4da4-be31-b8566cfe60fa','德回上人寫予真求贊','周必大','宋','宋诗','song-poetry','','[]','非律非禪自在身，免丁不納沒公憑。',32,'全唐诗/poet.song.143000.json','["非律非禪自在身，免丁不納沒公憑。", "明知未是龐居士，且可題爲破戒僧。"]'),
('b404aa9c-00d6-4f13-9da1-9fed05733f3a','贛州豐樂長老惠宣寫予真戲贊時年七十三','周必大','宋','宋诗','song-poetry','','[]','少年日醉鬰孤臺，鼎立三禪屢往來。',32,'全唐诗/poet.song.143000.json','["少年日醉鬰孤臺，鼎立三禪屢往來。", "豪氣雖存誰復識，形容變盡鬢皚皚。"]'),
('95c82227-a14c-4b06-aec9-6f3af4eb5aa6','青原祖燈監寺屢問予久不入山寫真戲題','周必大','宋','宋诗','song-poetry','','[]','欲作青原掛搭僧，傳聞米價逐時增。',32,'全唐诗/poet.song.143000.json','["欲作青原掛搭僧，傳聞米價逐時增。", "繞腰三篾非難事，空腹何能念葛藤。"]'),
('2339c780-70c9-4876-9f74-df567d23cba2','予久欲遊仰山而未暇行者智印寫真索贊','周必大','宋','宋诗','song-poetry','','[]','家居只在仰山傍，自笑癡蠅凍守窗。',32,'全唐诗/poet.song.143000.json','["家居只在仰山傍，自笑癡蠅凍守窗。", "也解分身千百億，從來一月印千江。"]'),
('ce2efbcd-d0d6-481b-afac-8bd25cf7f3b8','安福縣岳興院希琦求予真贊','周必大','宋','宋诗','song-poetry','','[]','僧坊何事俗塵同，索我精神阿堵中。',32,'全唐诗/poet.song.143000.json','["僧坊何事俗塵同，索我精神阿堵中。", "有相要知皆是妄，發真那更隕虛空。"]'),
('147cd13d-b40e-498c-bb8b-8f408015f05f','覺報長老道諶寫予兄弟真求贊次七兄韵','周必大','宋','宋诗','song-poetry','','[]','身凡心聖古盧能，未著袈裟已是僧。',32,'全唐诗/poet.song.143000.json','["身凡心聖古盧能，未著袈裟已是僧。", "冷煖自知師莫問，但看老色幾分增。"]'),
('64ee1e84-4b51-43d2-8a53-a68bbd5ab4bb','龍堂院宗慜寫真求贊次七兄韵','周必大','宋','宋诗','song-poetry','','[]','相將尋壑復經邱，潄石何妨更枕流。',32,'全唐诗/poet.song.143000.json','["相將尋壑復經邱，潄石何妨更枕流。", "得法龍須隨七祖，休官郎將繼牛頭。"]'),
