('ac36d2e4-a40e-47d4-975e-1a37a3c9a5b6','甲申四月甲子夜夢以焦坑小團及宜春新芽送隆慶長老了遠戲作柬云云矍然而寤枕上又補一頌以茶送達數日前曾有此意而一點千林非因想所及也  其一','周必大','宋','宋诗','song-poetry','','[]','達上座，惺惺著，靈根一點便通神，敗葉千林都掃却。',24,'全唐诗/poet.song.143000.json','["達上座，惺惺著，靈根一點便通神，敗葉千林都掃却。"]'),
('4372f7d2-592e-4725-8e79-c38aeded5621','甲申四月甲子夜夢以焦坑小團及宜春新芽送隆慶長老了遠戲作柬云云矍然而寤枕上又補一頌以茶送達數日前曾有此意而一點千林非因想所及也  其二','周必大','宋','宋诗','song-poetry','','[]','睡起尋思鹿覆蕉，更將惡水向人澆。',32,'全唐诗/poet.song.143000.json','["睡起尋思鹿覆蕉，更將惡水向人澆。", "夢中妄語渾閒事，眼暈生花好一鍫。"]'),
('d2187650-158b-4f79-8332-f787dff8efd3','與崔序老步月青玉峽漱玉泉坐瀑布之石橋天氣凉冷移坐法堂下對雙劍峰甚正序老求偈','周必大','宋','宋诗','song-poetry','','[]','劍峰有時折，瀑水有時竭。',24,'全唐诗/poet.song.143000.json','["劍峰有時折，瀑水有時竭。", "我性等虛空，今古無生滅。"]'),
('9439844d-a6fb-4778-a983-f371d6badcb6','故慶雲長老{尒（下小右兩點）}贊','周必大','宋','宋诗','song-poetry','','[]','七尺軀，歸底處。',26,'全唐诗/poet.song.143000.json','["七尺軀，歸底處。", "一尺素，寫得住。", "是真是假，有眼看覷。"]'),
('28749a23-7a7f-4408-aeaf-f55bba44b810','彥岑真贊','周必大','宋','宋诗','song-poetry','','[]','石中韞著無瑕玉，鑛裏淘成紫磨金。',32,'全唐诗/poet.song.143000.json','["石中韞著無瑕玉，鑛裏淘成紫磨金。", "八十年來岑鐵面，誰知一片老婆心。"]'),
('7f404f8d-b98e-4cb0-bb52-619998d62d45','送陸先生赴春闈','周必大','宋','宋诗','song-poetry','','[]','九重詔下選賢能，又見先生啟遠行。',64,'全唐诗/poet.song.143000.json','["九重詔下選賢能，又見先生啟遠行。", "離恨暗隨流水去，朔風穩送片帆輕。", "休嗟此日暌違事，預發來春晉錫榮。", "一去鵬程應九萬，始知佳夢合金精。"]'),
('b2b55aff-0766-4b4b-a65e-8067434fbf24','同前','周必大','宋','宋诗','song-poetry','','[]','何幸天涯款緒餘，軒昂氣概識雄圖。',64,'全唐诗/poet.song.143000.json','["何幸天涯款緒餘，軒昂氣概識雄圖。", "滔滔腹稿盈千軸，凜凜詞鋒敵萬夫。", "方對芝眉蒙數載，乍驚絳帳失規模。", "從茲穩步青雲上，始信沙堤夢不誣。"]'),
('dd7dc3e8-645d-4061-a9d4-077e673d54f5','余石月輓詞  其一','周必大','宋','宋诗','song-poetry','','[]','學重今顔子，年高漢伏生。',48,'全唐诗/poet.song.143000.json','["學重今顔子，年高漢伏生。", "鯉庭傳道德，鱣序列公卿。", "忠孝平生事，詩書後世名。", "於公無一憾，多士自傷情。"]'),
('e1a9de6e-1c46-4db6-823c-31d977a9a4a6','余石月輓詞  其二','周必大','宋','宋诗','song-poetry','','[]','自我居洪府，從公父子游。',48,'全唐诗/poet.song.143000.json','["自我居洪府，從公父子游。", "至言今在耳，往事忍回頭。", "風急唐山壟，雲埋石月樓。", "生芻無路奠，灑淚寄東流。"]'),
('743d4a64-ba45-497a-8d72-d6300c042e85','泰州守許寺正輓詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','昔在西京日，名臣數次公。',48,'全唐诗/poet.song.143000.json','["昔在西京日，名臣數次公。", "人歌廷尉德，帝念潁川功。", "出處君何異，修良譽亦同。", "誰提班固筆，千古紹高風。"]'),
('66292245-fc0f-4b8e-b8f9-9e777e71f389','泰州守許寺正輓詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','身襲黄門慶，腰懸紫綬龜。',48,'全唐诗/poet.song.143000.json','["身襲黄門慶，腰懸紫綬龜。", "未登知命歲，遽逼蓋棺期。", "風咽哀笳恨，雲凝斷壟悲。", "只應潘岳淚，重憶悼亡時。"]'),
('f76fe0b0-e067-4811-b425-9afc1209534a','孟郡王輓詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','炳靈崧嶽古諸姜，令德高標對寵光。',64,'全唐诗/poet.song.143000.json','["炳靈崧嶽古諸姜，令德高標對寵光。", "位冠西樞籌運幄，班高左棘綉爲裳。", "丁年聲譽佳公子，二紀功名異姓王。", "人物風流今已矣，空令吳越詠甘棠。"]'),
('5248016f-1700-4aba-9534-0737bf56fcc0','孟郡王輓詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','祥源總使奉真游，藏室提綱接勝流。',64,'全唐诗/poet.song.143000.json','["祥源總使奉真游，藏室提綱接勝流。", "書蠹只知三館樂，盤鯖不鬭五侯羞。", "名山早晚尋黄石，逝水須臾失夜舟。", "白馬素車分散後，何人更忍過西州。"]'),
('0b266895-b1c5-4fd5-bc88-f97e885b1b95','張朝宗挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','耆舊推西洛，於公見典刑。',48,'全唐诗/poet.song.143000.json','["耆舊推西洛，於公見典刑。", "全名高白璧，利刃拂青萍。", "日者瞻卿月，天乎隕使星。", "平生精藻鑒，桃李半槐庭。"]'),
('aff4d763-9f8c-4c5b-9c24-89be85fee136','張朝宗挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','甲第開鄰里，蝸廬遂不孤。',48,'全唐诗/poet.song.143000.json','["甲第開鄰里，蝸廬遂不孤。", "相從期晚歲，太息奠生芻。", "凉吹飛丹旐，殘陽詠白駒。", "傷心松柏路，螭首載龜趺。"]'),
('f8e2f090-0d65-4c99-9b01-7a4e4e47cc56','大行皇太后挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','瑞應興沙麓，祥源發狶韋。',48,'全唐诗/poet.song.143000.json','["瑞應興沙麓，祥源發狶韋。", "東朝方母育，滄海倏塵飛。", "蟾蟬冰輪影，鰲翻地軸機。", "宸心懷慕處，篋有五時衣。"]'),
('669078e1-ea27-40e9-8d30-98d9d0a9c576','大行皇太后挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','媯汭芳聲遠，思齊聖德優。',48,'全唐诗/poet.song.143000.json','["媯汭芳聲遠，思齊聖德優。", "湘妃初從舜，文母晚興周。", "養弃慈寧樂，神同永祐遊。", "鳳車青羽蓋，忍望浙江舟。"]'),
('112dcf60-65bd-4b5f-a384-3a8a1af1582b','同前  其一','周必大','宋','宋诗','song-poetry','','[]','得道西王母，思齊古太任。',48,'全唐诗/poet.song.143000.json','["得道西王母，思齊古太任。", "仙游歸少廣，人世失徽音。", "閬苑桃空熟，稽山柏自森。", "天心知舜孝，寒日慘多陰。"]'),
('f619da84-19eb-488a-b331-06aa11e3d919','同前  其二','周必大','宋','宋诗','song-poetry','','[]','憶昨登中壽，梅觴慶九重。',48,'全唐诗/poet.song.143000.json','["憶昨登中壽，梅觴慶九重。", "回春方晝永，月掩遽雲濃。", "鐘鼓沈長樂，蠶桑罷濯龍。", "宣仁遺懿在，定謚獨追蹤。"]'),
('baaab345-a0f9-4306-971e-bdce5d7d7e72','廣德軍鹿鳴燕樂語口號','周必大','宋','宋诗','song-poetry','','[]','才子雍容入帝京，使君勸駕意殊深。',64,'全唐诗/poet.song.143000.json','["才子雍容入帝京，使君勸駕意殊深。", "騎蟾定喜攀仙桂，鳴鹿先須詠野芩。", "好去玉階方寸近，休辭金盞十分斟。", "明年三月鶑花麗，洗眼宮袍宴上林。"]'),
('87fab8ef-d232-4d45-bb27-5e12c6b0a5ed','請盧帥樂語口號','周必大','宋','宋诗','song-poetry','','[]','三月春光未肯休，兩邦賓主總風流。',64,'全唐诗/poet.song.143000.json','["三月春光未肯休，兩邦賓主總風流。", "照階旌旆交輝映，環座笙歌競勸酬。", "尚有長紅强半在，休辭大白十分淳。", "介圭早晚催歸覲，應記臺城此日遊。"]'),
('56a98399-c559-4658-8da6-1b93073a5558','金國賀會慶節使副到闕紫宸殿宴致語口號','周必大','宋','宋诗','song-poetry','','[]','瑞氣輕籠合殿香，上尊初破早寒霜。',64,'全唐诗/poet.song.143000.json','["瑞氣輕籠合殿香，上尊初破早寒霜。", "千秋節應千齡運，萬歲聲隨萬歲觴。", "境似華胥民氣樂，夢如帝所樂聲長。", "年年太史前期奏，南極星明聖曆昌。"]'),
('67b6beb1-48de-48f7-bf2e-a6479e74a383','金國賀正旦使副到闕紫宸殿宴致語口號','周必大','宋','宋诗','song-poetry','','[]','北斗回杓恰指寅，東皇御極蚤施仁。',64,'全唐诗/poet.song.143000.json','["北斗回杓恰指寅，東皇御極蚤施仁。", "光風麗日依稀轉，御柳宮花次第新。", "魚藻有頒安萬物，鹿苹式燕樂嘉賓。", "小臣請祝君王壽，乾道宜過一萬春。"]'),
('c1684600-950a-4dc3-a390-294f69fcbac4','又','周必大','宋','宋诗','song-poetry','','[]','絳闕嵯峨映五雲，華簪合遝會芳宸。',64,'全唐诗/poet.song.143000.json','["絳闕嵯峨映五雲，華簪合遝會芳宸。", "盡收殘臘嚴凝氣，散作新年浩蕩春。", "盞斝頻宣恩意重，金絲徐韵樂聲純。", "欲知朝野歡娛處，聽取三呼萬歲人。"]'),
('641a75ea-cf89-42c2-8ba6-8da0f450b9a0','金國賀會慶聖節使副到闕紫宸殿宴致語口號','周必大','宋','宋诗','song-poetry','','[]','十月爲陽慶小春，電樞來應帝王真。',64,'全唐诗/poet.song.143000.json','["十月爲陽慶小春，電樞來應帝王真。", "天長地久千秋節，鰲抃歡呼四海人。", "黼座衮龍明日月，綉墩珠履切星辰。", "河圖已告無疆壽，安得區區計古椿。"]'),
('3e9564ca-17e5-484c-979e-f7552636f569','又','周必大','宋','宋诗','song-poetry','','[]','九陛天高輦下琱，千官雲集履鳴潮。',64,'全唐诗/poet.song.143000.json','["九陛天高輦下琱，千官雲集履鳴潮。", "霜迎愛日融城濕，香带祥風合殿飄。", "周宴恩濃魚在藻，舜廷化洽鳳儀簫。", "清臺夜夜占南極，常有華星炳絳霄。"]'),
('9ba5b2f8-4f60-411d-ba5d-9038a1773356','金國賀正旦使副到闕紫宸殿宴致語口號','周必大','宋','宋诗','song-poetry','','[]','淳熙紀號過千齡，玉曆今開第五春。',64,'全唐诗/poet.song.143000.json','["淳熙紀號過千齡，玉曆今開第五春。", "北極天高乾象正，東郊風暖物華新。", "漏添化國融和日，律饗熙臺鼓舞人。", "願挹滄溟供壽酒，無躬無盡奉嚴宸。"]'),
('b79422e2-817c-4c7a-bdf7-b333ba6686e4','二老堂會七兄樂語口號','周必大','宋','宋诗','song-poetry','','[]','早似機雲入帝鄉，晚如廣受出咸陽。',64,'全唐诗/poet.song.143000.json','["早似機雲入帝鄉，晚如廣受出咸陽。", "舊游應憶魚同隊，倦翼還欣雁著行。", "甲子八百九十朔，醉鄉三萬六千場。", "新陽漸漏春消息，二老風流日月長。"]'),
('b5543990-2241-41bd-9fa8-cc73177d20b5','句','周必大','宋','宋诗','song-poetry','','[]','竹多翻障月，木老只啼烏。',12,'全唐诗/poet.song.143000.json','["竹多翻障月，木老只啼烏。"]'),
('a6b5438b-3da3-454d-9936-088b835917a3','句','邊惇德','宋','宋诗','song-poetry','','[]','敢向詩壇挑老將。',8,'全唐诗/poet.song.143000.json','["敢向詩壇挑老將。"]'),
('aea1033a-91ac-4027-b7e4-fdd6f772f215','題玉川碾茶圖','周季','宋','宋诗','song-poetry','','[]','獨抱遣經舌本乾，笑呼赤脚碾龍團。',32,'全唐诗/poet.song.143000.json','["獨抱遣經舌本乾，笑呼赤脚碾龍團。", "但知兩腋清風起，未識捧甌春筍寒。"]'),
('5f071f8b-5176-4e16-a151-a0d69f64fbfc','句','周煇','宋','宋诗','song-poetry','','[]','捲簾試約東君問，花信風來第幾番。',16,'全唐诗/poet.song.143000.json','["捲簾試約東君問，花信風來第幾番。"]'),
('03f2faa3-43f7-470d-bd40-e3128a032c01','西園席上記事','駱適正','宋','宋诗','song-poetry','','[]','花隨春盡覓無痕，尚續餘歡索侑尊。',32,'全唐诗/poet.song.143000.json','["花隨春盡覓無痕，尚續餘歡索侑尊。", "一曲未終人已去，西園燈火欲黄昏。"]'),
('2e8fbfa5-ae47-4bc6-ab7a-f5f16a2f7213','富樂山  其一','雍有容','宋','宋诗','song-poetry','','[]','當時四海一劉備，至此已堪悲失脚。',32,'全唐诗/poet.song.143000.json','["當時四海一劉備，至此已堪悲失脚。", "出語翻爲樂國想，是人止可偏方著。"]'),
('e4e1ca91-22a4-46e3-a060-03f89a0240f3','富樂山  其二','雍有容','宋','宋诗','song-poetry','','[]','大漢曾封隆準翁，聞道山河錦綉中。',32,'全唐诗/poet.song.143000.json','["大漢曾封隆準翁，聞道山河錦綉中。", "安能鬰鬰久居此，睥睨三秦日欲東。"]'),
('4a38b933-9c86-4a95-a7ac-7e3a678cad07','高宗皇帝挽詞  其一','王淮','宋','宋诗','song-poetry','','[]','炎祚開中葉，龍翔自有真。',48,'全唐诗/poet.song.143000.json','["炎祚開中葉，龍翔自有真。", "揮戈回日照，洗甲挽天津。", "立極乾坤正，循環雨露新。", "嗣皇能繼志，詩爲武功陳。"]'),
('a7a09945-056a-4e20-8c42-23a34f666f02','高宗皇帝挽詞  其二','王淮','宋','宋诗','song-poetry','','[]','曆數堯咨舜，羹牆舜見堯。',48,'全唐诗/poet.song.143000.json','["曆數堯咨舜，羹牆舜見堯。", "三加徽號冊，五日未央朝。", "廟祀瞻龍衮，韶音遏鳳簫。", "伏蒲思往事，淚湔浙江潮。"]'),
('0bf3ae8a-835c-40db-8fd0-7a1951abd1ce','題福祐王廟','王淮','宋','宋诗','song-poetry','','[]','關中失鹿人爭逐，一去鴻門不可尋。',32,'全唐诗/poet.song.143000.json','["關中失鹿人爭逐，一去鴻門不可尋。", "千古英雄死遺恨，封侯廟食更何心。"]'),
('42bfd33a-41ae-4474-9c63-457fd958c847','詠釣臺  其一','潘畤','宋','宋诗','song-poetry','','[]','不到危臺久，重來恰十年。',48,'全唐诗/poet.song.143000.json','["不到危臺久，重來恰十年。", "壯懷今掃盡，遺象只依然。", "老我從疎拙，微官合弃捐。", "歸來營釣艇，長此卧風烟。"]'),
('399e0b57-b094-4693-a51b-1f53a1d250e3','詠釣臺  其二','潘畤','宋','宋诗','song-poetry','','[]','古屋顛巖上，荒祠落葉中。',48,'全唐诗/poet.song.143000.json','["古屋顛巖上，荒祠落葉中。", "乞靈無俗駕，垂世有高風。", "鳥語谷相答，魚游溪若空。", "徘徊欲忘去，船背夕陽紅。"]'),
('980eb91b-3892-4d98-b0fb-b01f2e31a288','雪','項寅賓','宋','宋诗','song-poetry','','[]','凍雲同色墜飛霙，送臘迎春一歲成。',64,'全唐诗/poet.song.143000.json','["凍雲同色墜飛霙，送臘迎春一歲成。", "但見紅花洗芳面，那聞黄竹度新聲。", "密移瓊室祥光滿，倒瀉銀河白浪平。", "已屬畫師圖此景，炎蒸相對卧桃笙。"]'),
('a8229249-180e-4675-949d-c37dc7a70215','和范至能元日','項寅賓','宋','宋诗','song-poetry','','[]','獻歲身留外，思家恨滿中。',48,'全唐诗/poet.song.143000.json','["獻歲身留外，思家恨滿中。", "桃符禳厲鬼，椒酒勸仙童。", "出謁憑羸馬，題書附去鴻。", "青春應時節，斗柄夜摇東。"]'),
('56b3caa8-a87d-4411-b4d5-3d4d11569a81','和鄭逢辰元宵韻','項寅賓','宋','宋诗','song-poetry','','[]','憶昔先皇賞露臺，鼇山半影落蓬萊。',64,'全唐诗/poet.song.143000.json','["憶昔先皇賞露臺，鼇山半影落蓬萊。", "羣芳欲識龍顔喜，雙闔時瞻雉扇開。", "十里仙香濛碧霧，六宮韶樂隠新雷。", "神仙舊事渾如夢，只有春風每歲催。"]'),
('206ba1e0-ec9d-4f6e-8988-f1319b8bde1a','又和酴醾韻','項寅賓','宋','宋诗','song-poetry','','[]','天遣司花寶笈開，鮫綃散翦碧雲堆。',64,'全唐诗/poet.song.143000.json','["天遣司花寶笈開，鮫綃散翦碧雲堆。", "芳根移自蠶叢遠，薰釀曾隨鳳詔來。", "祇恐飄風撼新竹，却驚殘雪觸蒼苔。", "水仙欲逞幽香壓，山谷似無詮品才。"]'),
('2ed76d56-c375-45c9-8434-87bc28429642','千里丈蓄酒尊形狀孛窣某酒後以短項翁目之不謂誤中遂成佳號彥平功成二兄皆有褒咏可使韓子蒼縮肩短項之句北面矣某不揆鄙拙勉强續貂幸諸丈斤斧之','鍾孝國','宋','宋诗','song-poetry','','[]','少陵先生時不偶，老瓦盆中醉林莽。',160,'全唐诗/poet.song.143000.json','["少陵先生時不偶，老瓦盆中醉林莽。", "江湖散人名益窮，魚殻傾尊不論斗。", "孤風異行同襟期，食鮭未必富三九。", "凌烟功名舉世事，不直兩公一杯酒。", "會稽夫子有古心，嗜好眇追千載友。", "陶尊中産同蒼筠，短項不肯鍾罍群。", "章綬黄篾差緇塵，肺腸桑落心崑崙。", "始知其中殊陋貌，一點不受泥沙渾。", "時從往古窮玄微，坐隅兀側長相隨。", "送余醉鄉謝膠擾，回頭轉覺人間小。"]'),
('a0fe0a59-189d-4d7e-8e93-5c30e460ad01','謹次功成短項翁佳篇之韻','鍾孝國','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君不見中山毛穎生，纂錄百氏編群經。',178,'全唐诗/poet.song.143000.json','["君不見中山毛穎生，纂錄百氏編群經。", "又不見革華祖都尉，殿上承恩舉足耳。", "二物名譽由韓公，無乃衮褒俱中理。", "君家酒罌依圖書，短項獨喜觴吾儒。", "我加翁名乃率爾，諸公過聽歡有餘。", "翁名稱意仰來前，再拜不願封酒泉。", "傾懷解賈吟筆勇，注想只愁客杯乾。", "主人冥心通與窮，從渠自引琉璃鍾。", "醉中琢句千古廢，醒後逢人四海空。", "林間日日吹春風，孛窣願卜重相逢。", "長江小艇新雨後，一杯相屬會稽翁。"]'),
('357e3d8f-17ff-41c1-9ae2-8a9d9a100398','絕句  其一','歐陽鈇','宋','宋诗','song-poetry','','[]','戀樹殘紅濕不飛，楊花雪落木生衣。',32,'全唐诗/poet.song.143000.json','["戀樹殘紅濕不飛，楊花雪落木生衣。", "年來百念成灰冷，無語送春春自歸。"]'),
('da996c99-4eee-4a1d-8a50-25384292eb37','絕句  其二','歐陽鈇','宋','宋诗','song-poetry','','[]','桑麻得雨更青葱，芍藥留春結晚紅。',32,'全唐诗/poet.song.143000.json','["桑麻得雨更青葱，芍藥留春結晚紅。", "怪得鳥聲如許好，此身還在亂山中。"]'),
('e8d6527a-c397-45b5-a21d-e19fc90f21b2','絕句  其三','歐陽鈇','宋','宋诗','song-poetry','','[]','爲憐紅杏亞枝斜，看到斜陽送亂鴉。',32,'全唐诗/poet.song.143000.json','["爲憐紅杏亞枝斜，看到斜陽送亂鴉。", "又是一春窮不死，天教留眼看鶑花。"]'),
('96bca2f1-de1d-4e63-a8e8-dcc4a3c7825d','絕句  其四','歐陽鈇','宋','宋诗','song-poetry','','[]','篷窗卧聽疎疎雨，却是芭蕉夜半聲。',32,'全唐诗/poet.song.143000.json','["篷窗卧聽疎疎雨，却是芭蕉夜半聲。", "煙浪蔽天天倚蓋，略容一點白鷗明。"]'),
('94971dac-ac5b-4a58-b52b-2639654ceb6d','示二子','歐陽鈇','宋','宋诗','song-poetry','','[]','先君以官貧，我仍遺以安。',36,'全唐诗/poet.song.143000.json','["先君以官貧，我仍遺以安。", "但願兩兒健，扶持一翁孱。", "何須待門生，悠然柴桑閒。"]'),
('536e0434-0036-4627-8d3c-48ecd7beb6fe','卜居','歐陽鈇','宋','宋诗','song-poetry','','[]','此生老矣益飄零，湯餠來年又何所。',56,'全唐诗/poet.song.143000.json','["此生老矣益飄零，湯餠來年又何所。", "是身如寓敢求安，更築小軒名以寓。", "憑誰叫閽與帝語，有客多艱乃如許。", "水花爲客啼紅雨。"]'),
('59afc21f-fba4-434f-a887-664db7ed6cdd','游愚堂','歐陽鈇','宋','宋诗','song-poetry','','[]','聞說名園尚修竹，花壓頹垣筍穿屋。',66,'全唐诗/poet.song.143000.json','["聞說名園尚修竹，花壓頹垣筍穿屋。", "雨痕半掩壁間題，饑鼠跳梁狐晝啼。", "前人已爲後人笑，後人更使誰人悼。", "嗚呼全盛幾時奈衰何，古人興廢何其多。"]'),
('72f3f25e-501b-4bef-849b-05b4b2e73565','和伍武仲','歐陽鈇','宋','宋诗','song-poetry','','[]','未知一歲於此水，幾回照影慚栖栖。',32,'全唐诗/poet.song.143000.json','["未知一歲於此水，幾回照影慚栖栖。", "失身竟墮管城計，錯路不爲田舍兒。"]'),
('72f86d51-22d0-4a57-87fe-e67371da4dfb','禾山秋興  其一','歐陽鈇','宋','宋诗','song-poetry','','[]','生計嗟烏有，誰人問子虛。',48,'全唐诗/poet.song.143000.json','["生計嗟烏有，誰人問子虛。", "西風五更雨，南雁數行書。", "衰朽兒童笑，飄流歲月餘。", "秋深新病起，吾志在吾廬。"]'),
('cb2fa364-5601-4809-80b4-45664cad113c','禾山秋興  其二','歐陽鈇','宋','宋诗','song-poetry','','[]','夜起集萬感，胡爲淹此留。',48,'全唐诗/poet.song.143000.json','["夜起集萬感，胡爲淹此留。", "詩成夔子國，人在仲宣樓。", "絡緯聲中淚，芭蕉雨裏愁。", "遥知屢門倚，應念有方游。"]'),
('e474b1bf-d87d-4084-8031-e8d1fd104371','句  其一','歐陽鈇','宋','宋诗','song-poetry','','[]','細雨雙飛鷺，寒蓑獨釣船。',12,'全唐诗/poet.song.143000.json','["細雨雙飛鷺，寒蓑獨釣船。"]'),
('4a1f4d28-cdd0-4bb4-a5f9-ead432d05ffb','句  其二','歐陽鈇','宋','宋诗','song-poetry','','[]','夢回千里外，燈轉一窗深。',12,'全唐诗/poet.song.143000.json','["夢回千里外，燈轉一窗深。"]'),
('49b20013-3d07-4582-8ac8-07fb69648616','句  其三','歐陽鈇','宋','宋诗','song-poetry','','[]','誰知花過半，纔與酒相尋。',12,'全唐诗/poet.song.143000.json','["誰知花過半，纔與酒相尋。"]'),
('42441d41-f8ca-4bee-b620-c19e048d0ac8','句  其四','歐陽鈇','宋','宋诗','song-poetry','','[]','故人驚會面，新恨說從頭。',12,'全唐诗/poet.song.143000.json','["故人驚會面，新恨說從頭。"]'),
('a8642471-cca2-4ff9-98cc-ab4743c9de87','句  其五','歐陽鈇','宋','宋诗','song-poetry','','[]','天上張公子，雲間陸士龍。',12,'全唐诗/poet.song.143000.json','["天上張公子，雲間陸士龍。"]'),
('30957554-caea-4c6b-81b8-98f1ecf7f854','句  其六','歐陽鈇','宋','宋诗','song-poetry','','[]','月白玄猿哭，更殘絡緯悲。',12,'全唐诗/poet.song.143000.json','["月白玄猿哭，更殘絡緯悲。"]'),
('1e4b1d75-ec86-4416-bd09-955ee64da197','句  其七','歐陽鈇','宋','宋诗','song-poetry','','[]','語離遽何許，話舊復何時。',12,'全唐诗/poet.song.143000.json','["語離遽何許，話舊復何時。"]'),
('1ff3483f-80c3-44d3-929b-4f6583983419','句  其八','歐陽鈇','宋','宋诗','song-poetry','','[]','巷南巷北人招飲，一雨一晴花耐看。',16,'全唐诗/poet.song.143000.json','["巷南巷北人招飲，一雨一晴花耐看。"]'),
('66c6cdb5-1966-4a24-8b24-ac8f1b30c943','句  其九','歐陽鈇','宋','宋诗','song-poetry','','[]','有客過門湖海士，隔籬呼酒咄嗟間。',16,'全唐诗/poet.song.143000.json','["有客過門湖海士，隔籬呼酒咄嗟間。"]'),
('7e6490a8-8893-4160-a234-e49ae268d95c','句  其一○','歐陽鈇','宋','宋诗','song-poetry','','[]','夢回金馬玉堂上，文在冰甌雪碗中。',16,'全唐诗/poet.song.143000.json','["夢回金馬玉堂上，文在冰甌雪碗中。"]'),
('9ad4158c-92a6-459c-9823-653cc9fffe8b','句  其一一','歐陽鈇','宋','宋诗','song-poetry','','[]','青山如故情非故，芳草喚愁詩遣愁。',16,'全唐诗/poet.song.143000.json','["青山如故情非故，芳草喚愁詩遣愁。"]'),
('953a4a97-318d-4486-bd71-6552b4373799','句  其一二','歐陽鈇','宋','宋诗','song-poetry','','[]','擾擾征人相顧語，蕭蕭落木不勝秋。',16,'全唐诗/poet.song.143000.json','["擾擾征人相顧語，蕭蕭落木不勝秋。"]'),
('186da11a-65fe-4d85-8dd6-d33c529ab74c','句  其一三','歐陽鈇','宋','宋诗','song-poetry','','[]','風色似傳花信到，夕陽微放柳梢晴。',16,'全唐诗/poet.song.143000.json','["風色似傳花信到，夕陽微放柳梢晴。"]'),
('cfd66e81-0b74-46f2-9e65-d87e50e59fde','句  其一四','歐陽鈇','宋','宋诗','song-poetry','','[]','千里歸來人事改，十年猶幸此身存。',16,'全唐诗/poet.song.143000.json','["千里歸來人事改，十年猶幸此身存。"]'),
('029060bd-2f69-48c4-b68f-d492ba7f2ef5','句  其一五','歐陽鈇','宋','宋诗','song-poetry','','[]','愛山如愛酒，畏暑如畏虎。',24,'全唐诗/poet.song.143000.json','["愛山如愛酒，畏暑如畏虎。", "出門尋舊遊，缺月四更吐。"]'),
('1b0ec232-6941-4ec8-8a95-ae503e03c1a5','句  其一六','歐陽鈇','宋','宋诗','song-poetry','','[]','更闌待月華，風露寒欲僵。',12,'全唐诗/poet.song.143000.json','["更闌待月華，風露寒欲僵。"]'),
('9d724598-4397-4649-93a9-5a898bb3d118','句  其一七','歐陽鈇','宋','宋诗','song-poetry','','[]','讀書豈爲官。',6,'全唐诗/poet.song.143000.json','["讀書豈爲官。"]'),
('50f77ea6-d303-4f8b-9ab0-324a6c83ecdf','句  其一八','歐陽鈇','宋','宋诗','song-poetry','','[]','心清時自暑。',6,'全唐诗/poet.song.143000.json','["心清時自暑。"]'),
('e6d6bfeb-0737-4c21-9c88-698b1f9693fa','子猷訪戴','來梓','宋','宋诗','song-poetry','','[]','四山摇玉夜光浮，一舸玻璃凝不流。',32,'全唐诗/poet.song.143000.json','["四山摇玉夜光浮，一舸玻璃凝不流。", "若使過門相見了，千年風致一時休。"]'),
('f0605c2c-4765-41b9-be61-cd9a6d879212','杜甫遊春','來梓','宋','宋诗','song-poetry','','[]','典盡春衣不肯歸，熊兒扶過瀼溪西。',32,'全唐诗/poet.song.143000.json','["典盡春衣不肯歸，熊兒扶過瀼溪西。", "傷時懷抱深於海，掠眼風光醉似泥。"]'),
('8857dc31-1cd8-4c5f-85a3-7479549ef74c','六言二首  其一','來梓','宋','宋诗','song-poetry','','[]','葉淅歷而爭墮，菊徘徊而尚開。',28,'全唐诗/poet.song.143000.json','["葉淅歷而爭墮，菊徘徊而尚開。", "流年逼人太甚，佳客折簡不來。"]'),
('075f820e-0dec-4bb9-8961-f6360932664a','六言二首  其二','來梓','宋','宋诗','song-poetry','','[]','行空月不著相，出岫雲無戀心。',28,'全唐诗/poet.song.143000.json','["行空月不著相，出岫雲無戀心。", "胸中一丘一壑，不磯城市山林。"]'),
('2b6e23ac-eefd-4262-9949-faac724e980d','句','王仲寧','宋','宋诗','song-poetry','','[]','妙曲撓周郎。',6,'全唐诗/poet.song.143000.json','["妙曲撓周郎。"]'),
('8b624d7e-61ea-484d-af53-cfac87f5a770','句','陳國材','宋','宋诗','song-poetry','','[]','紅日晚天三四雁，碧波春水一雙鷗。',16,'全唐诗/poet.song.143000.json','["紅日晚天三四雁，碧波春水一雙鷗。"]'),
('efbbc98f-ff9b-413b-93b6-b92ced34d57b','西湖雜咏','蕭彥毓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','花心亭上坐，滿眼是湖光。',48,'全唐诗/poet.song.143000.json','["花心亭上坐，滿眼是湖光。", "祇爲便幽趣，能來倚夕陽。", "水邊春寺靜，柳下小舟藏。", "不待清明近，鶑花已自忙。"]'),
('3dc80928-81ac-487c-acb0-685a61b25944','梁家渡','蕭彥毓','宋','宋诗','song-poetry','','[]','遠水環沙翠作灣，紅塵飛不入青山。',32,'全唐诗/poet.song.143000.json','["遠水環沙翠作灣，紅塵飛不入青山。", "凉風一枕秋宵夢，夢繞千巖萬壑間。"]'),
('14740f50-04e7-4047-a066-65f98cf11df7','清明日早出太平門','蕭彥毓','宋','宋诗','song-poetry','','[]','江頭楊柳暗藏鴉，江上鵝兒浴淺沙。',32,'全唐诗/poet.song.143000.json','["江頭楊柳暗藏鴉，江上鵝兒浴淺沙。", "早起一風如此惡，路旁落盡刺桐花。"]'),
('67defe54-1b1d-4ddb-affe-6b87c2a267d2','咏梅','吳居仁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嶺南十月春漸回，妍暖先到前村梅。',224,'全唐诗/poet.song.143000.json','["嶺南十月春漸回，妍暖先到前村梅。", "問君何處識此妙，一枝冷艷隨霜開。", "長江凜凜欲崩岸，乃見好事多牆隈。", "初疑滲漉入瘴霧，更恐寂寞埋煙煤。", "微風不動暗香遠，淡月入戶空徘徊。", "坐看粉黛化羶惡，豈但桃李成輿臺。", "我行萬里厭窮獨，疾病未已心先灰。", "對此不覺三歎息，恐是轉側同南來。", "異鄉久處少意緒，破壁相對無根荄。", "古來寒士每如此，一世埋沒隨蒿萊。", "遁光藏德老不耀，肯與世俗相追陪。", "輪囷離奇多見用，犧尊青黄木爲災。", "含毫吮墨去顔色，况自不必須穿裁。", "歲窮路遠莫惆悵，此去保無蜂蝶猜。"]'),
('d0a40a7c-4c54-4b68-abc5-cba8c0f90bbd','彈子巖題名','徐夢莘','宋','宋诗','song-poetry','','[]','吾儕生江南，遠近俱鄰鄉。',228,'全唐诗/poet.song.143000.json','["吾儕生江南，遠近俱鄰鄉。", "一官皆爲貧，餬口走四方。", "遇合良獨難，動如參與商。", "誰知自有時，朋盍聚炎荒。", "外臺參計畫，幕府佐紀綱。", "出宰得壯縣，分教涖郡庠。", "曹掾勝三語，簿領真仇香。", "不止似人喜，頓覺吾軍張。", "合坐尊序齒，避席敬行觴。", "巖酒縱登覽，杖屨陪徜徉。", "棋矢以相娛，嘯歌情意長。", "舉酒起祝規，愛我藥石良。", "古人尚植立，君子道其常。", "平生學忠孝，餘力從文章。", "臨節不可奪，當官有何强。", "窮乃見節義，老當志彌剛。", "鴻鵠在寥廓，騏驥終騰驤。", "願言各勉旃，事業要輝光。", "它日先上道，富貴無相忘。"]'),
('e1416407-9922-4f73-bf1d-7fff1a8c394f','題雙井堂','徐得之','宋','宋诗','song-poetry','','[]','鳳凰山畔永思堂，山谷先生有舊鄉。',32,'全唐诗/poet.song.143000.json','["鳳凰山畔永思堂，山谷先生有舊鄉。", "修水年年流不盡，斯文長與日爭光。"]'),
('07549ff8-97f0-4234-a8e2-0bf29ac7b8d5','玉笥山','徐得之','宋','宋诗','song-poetry','','[]','江作挼藍繞髻鬟，令君心事每相關。',32,'全唐诗/poet.song.144000.json','["江作挼藍繞髻鬟，令君心事每相關。", "要令白叟黄童輩，如在清江碧嶂間。"]'),
('9532f556-ffa5-4689-96a0-63c437b237c7','試雙井茶','徐得之','宋','宋诗','song-poetry','','[]','先生老作宜州鬼，誰與一甌注深湯。',32,'全唐诗/poet.song.144000.json','["先生老作宜州鬼，誰與一甌注深湯。", "至今捧看雙井碗，猶带是翁書傳香。"]'),
('7e99f360-4c03-4a7a-b308-6b513d5948c4','雙井圖','徐得之','宋','宋诗','song-poetry','','[]','異時生出鬼門關，及去宜州竟不還。',32,'全唐诗/poet.song.144000.json','["異時生出鬼門關，及去宜州竟不還。", "意者早知名是累，持鋤應只在家山。"]'),
('b803ffdc-cd20-4bc8-8126-81c94be37fbd','明妃曲','徐得之','宋','宋诗','song-poetry','','[]','妾生豈願爲胡婦，失信寧當累明主。',131,'全唐诗/poet.song.144000.json','["妾生豈願爲胡婦，失信寧當累明主。", "已傷畫史忍欺君，莫使君王更欺虜。", "琵琶却解將心語，一曲才終恨何數。", "朦朧胡霧染宮花，淚眼橫波時自雨。", "專房莫倚黄金賂，多少專房弃如土。", "寧從別去得深嚬，一步思君一回頭。", "胡山不隔思歸路，只把琵琶寫辛苦。", "君不見有言不食古高辛，生女無嫌嫁盤瓠。"]'),
('35c3c5f3-fb39-421a-8cb2-8987c21c0a7f','句','徐得之','宋','宋诗','song-poetry','','[]','迺翁畫灰教兒書，嬌兒赤骭玉雪膚。',32,'全唐诗/poet.song.144000.json','["迺翁畫灰教兒書，嬌兒赤骭玉雪膚。", "厥妻曝日補破襦，弊筐何有金十奴。"]'),
('378f0d07-0994-4071-b3ef-626fab01ce0d','白石山','宋晉之','宋','宋诗','song-poetry','','[]','日車未訪到仙宮，日脚將西又轉蓬。',64,'全唐诗/poet.song.144000.json','["日車未訪到仙宮，日脚將西又轉蓬。", "莫怪登山能草草，祗緣行李自匆匆。", "玉棺已去人何在，石鼎雖存味早空。", "休羨古來名與迹，幾多丘壑在胸中。"]'),
('7ddb5ee3-3d7a-4456-bd2a-3365e57616fd','題戴溪亭','林東','宋','宋诗','song-poetry','','[]','溪亭故事幾年華，來值秋霖眺望賒。',64,'全唐诗/poet.song.144000.json','["溪亭故事幾年華，來值秋霖眺望賒。", "雲障山巒多少處，雨埋煙火兩三家。", "水肥去馬行高阪，汀沒閒鷗上淺沙。", "誰是子猷誰是戴，小船杯酒興無涯。"]'),
('90369f3c-d32f-4931-8446-ca397995d41c','題佘山宣妙寺','劉孝韙','宋','宋诗','song-poetry','','[]','水定浮春岫，鴉盤落遠林。',24,'全唐诗/poet.song.144000.json','["水定浮春岫，鴉盤落遠林。", "上方鐘送夕，隠几興何深。"]'),
('68492fb8-c159-4c0b-b672-ad43756e104e','皇太后回鑾頌','吳𣓨','宋','宋诗','song-poetry','','[]','於皇睿明，運符中興。',240,'全唐诗/poet.song.144000.json','["於皇睿明，運符中興。", "綿宇肅清，乾夷坤寧。", "孝思兢兢，交三聖靈。", "惟我文母，遠征朔土。", "蒼旻眷顧，顯持陰護。", "爰居爰處，儲降祉祜。", "睿明紹休，匪豫匪遊。", "人謀鬼謀，迎親是求。", "夜靡安席，晝靡安几。", "宸心竊至，迎親是議。", "皇帝曰咨，命爾輔臣。", "朕有大計，儲思唯親。", "輔臣稽首，對揚聖志。", "惟斷乃成，願破群議。", "皇穹隆赫，鑒茲至德。", "風行萬國，聳動蠻貊。", "誕揚天聲，四征弗克。", "敵人震驚，稽顙尋盟。", "遣使旁午，願旋鑾輅。", "稽考曠古，且未曾睹。", "帝曰休哉，大慶鼎來。", "喧傳九垓，疾如驚雷。", "迺嚴法駕，迺飾次舍。", "千輿萬馬，出疆以迓。"]'),
('0fc45294-2034-4359-818c-b64979a885c0','溫泉','孫懋','宋','宋诗','song-poetry','','[]','喬林遠凝烟，怪石卧如虎。',168,'全唐诗/poet.song.144000.json','["喬林遠凝烟，怪石卧如虎。", "湯泉在其下，深廣數尺許。", "蒸蒸百鼎沸，衮衮驪珠吐。", "溫然可人意，了不變寒暑。", "我來一盥挹，和氣溢賓主。", "誰知山谷間，異物乃有取。", "又聞泉之功，萬頃浸禾黍。", "升騰或爲雲，定作傅巖雨。", "賢人抱氣節，瀟灑謹出處。", "平生澤物志，得時誰可御。", "奈何斗筲徒，名利每輕舉。", "一朝冰山碎，笑唾無足數。", "臨風祝斯泉，更請事斯語。", "回首驪山陰，淒然吊前古。"]'),
('6068efbc-03ac-4a2d-b5f2-37f252e82d37','龍巖寺','孫懋','宋','宋诗','song-poetry','','[]','蒼林翠碧龍巖寺，縣令三年兩度來。',32,'全唐诗/poet.song.144000.json','["蒼林翠碧龍巖寺，縣令三年兩度來。", "從此巖前花與草，只今時與夢徘徊。"]'),
('61310359-0e4b-4530-83ba-6a768f1e2e2d','青羊宮','何耕','宋','宋诗','song-poetry','','[]','一再官錦城，咫尺望琳宮。',144,'全唐诗/poet.song.144000.json','["一再官錦城，咫尺望琳宮。", "未始得得來，正望役役中。", "今朝弄晴雨，策蹇隨春風。", "頗愛意象古，停驂小從容。", "縹緲百尺臺，突起凌半空。", "憑欄俯修竹，决眥明孤鴻。", "信哉神仙宅，不受塵垢蒙。", "稽首五千言，衆妙一以通。", "靜觀萬物復，豈假九轉功。", "區區立訓詁，亦哂河上公。", "癡人慕羽化，心外求鴻濛。", "要附白鶴背，往訪青羊蹤。"]'),
('b3b375db-ada8-44be-96da-1efc2163f729','靈谿賦雙流郭信可隠居','何耕','宋','宋诗','song-poetry','','[]','幽居定何如，頗恨未見之。',144,'全唐诗/poet.song.144000.json','["幽居定何如，頗恨未見之。", "主人向我言，喜色融雙眉。", "修篁流翠陰，寒溪漾清漪。", "領略非一狀，幽妍發餘姿。", "空濛雨亦佳，瀲灧晴更奇。", "豈惟二江獨，意恐兩蜀稀。", "主人信妙士，得此固所宜。", "天公閟好景，授受各有時。", "豈無多田翁，偃蹇逝莫隨。", "素交懷老蒲，秀句紛珠璣。", "安得招歸來，爲君賦清詩。", "往者不可作，後生欲何爲。"]'),
('cb2057ba-56fc-4017-b021-3dace5d34fc0','龍淵','何耕','宋','宋诗','song-poetry','','[]','門前大江河渺漫，昔人飲牛水爲乾。',128,'全唐诗/poet.song.144000.json','["門前大江河渺漫，昔人飲牛水爲乾。", "水乾龍逝亦其理，近在咫尺聊泥蟠。", "魚暇玩侮娬獺笑，縱有靈怪誰當看。", "德人問舍壓我境，便爾築室相遮欄。", "坐令异類皆屏伏，恃有此耳差少安。", "却紆朱紱去監郡，遣我守舍良獨難。", "昨來過門恍如夢，龍致此語催歸鞍。", "先生不信反不笑，謂我饒舌狂豐干。"]'),
('645a634a-3317-4043-ba95-721b605289e6','虛舟','何耕','宋','宋诗','song-poetry','','[]','君不見江干車馬紛相送，巨艑峩峩船載重。',131,'全唐诗/poet.song.144000.json','["君不見江干車馬紛相送，巨艑峩峩船載重。", "西南使者解官歸，水淺著沙牽不動。", "如君材具豈多得，合侍明光參法從。", "何爲淺瀨著虛舟，頗笑胸中太空洞。", "問君此意竟安在，欲說向人誰與共。", "山林鐘鼎本同轍，繫岸截江隨所用。", "八窗窅窅凈無塵，一水泠泠清可弄。", "何當抱被過君眠，分破江天幽夜夢。"]'),
('4923e1fe-0173-4cd0-9934-c4b4a6bc5665','題龍華佛閣','何耕','宋','宋诗','song-poetry','','[]','西川鑿山三大像，突兀皆在江之湄。',192,'全唐诗/poet.song.144000.json','["西川鑿山三大像，突兀皆在江之湄。", "修覺九頂見略盡，獨此恨未瞻容儀。", "朅來勝地了疇昔，輕軒瘦馬相追隨。", "百尺金軀信雄傑，三乘寶閣何瑰奇。", "燃犀不用照幽鬼，擊鼓自合趨馮夷。", "前人開創願力廣，下與舟楫扶傾危。", "六月灘濤劇奔吼，一分性命爭毫釐。", "篙工落膽行者泣，彈指乞活天人師。", "人心狎水水多禍，佛力在人人不知。", "年來蜀産坐朘削，夜半有力真能移。", "軻峩大艑去不絕，綵鷁破浪風揚旗。", "慈悲但作布施相，江神雖怒將何爲。"]'),
('b1014cd4-4008-4ac6-acf9-41dab2f02a01','普通山距府東十數里青州禪師洪果道場也自龍華歸過之棟宇頹落僧徒鄙野良爲可惜是夜雨大作因書所聞所見爲長韻','何耕','宋','宋诗','song-poetry','','[]','錦城之東山培塿，突起伽藍壓山口。',272,'全唐诗/poet.song.144000.json','["錦城之東山培塿，突起伽藍壓山口。", "入門氣象頗不凡，在昔規模定非苟。", "黄絹碑詞著眼看，青州老衲知名久。", "自披榛逕結茅屋，不剪霜華散蓬首。", "市門有女捧巾盥，衣裓無花生穢垢。", "至今一轉鶺鴒語，散作諸方獅子吼。", "祖燈寂寞何人繼，窣堵岧嶤惟鬼守。", "法席草長深沒膝，僧榻屋穿光見斗。", "似聞占籍多衍沃，合選名緇振頹朽。", "我來不覺三歎息，眼底盡空諸所有。", "自開主席埽塵坌，聊寄閑眠憩奔走。", "夢回中夜雨鳴檐，卧聽東風寒入牖。", "明朝散步轉山脊，好語相呼聞野叟。", "抽芒已見麥翻浪，搗麨懸知香滿手。", "須臾日影散林樾，絢練春光被花柳。", "僕夫催歸屢不應，景物殊佳寧忍負。", "出山騎馬更躊躇，乘暇應須重載酒。"]'),
('c867af4f-b1f4-49b4-8663-2ed8b03888ff','忘機臺','何耕','宋','宋诗','song-poetry','','[]','太虛生微雲，機事日夕繁。',48,'全唐诗/poet.song.144000.json','["太虛生微雲，機事日夕繁。", "兼忘豈不佳，尚有忘者存。", "稽首老龐翁，妙處布一言。", "請觀臺上月，萬古無昭昏。"]'),
('6b8b1b67-7d89-4902-95ff-40458bff34ad','和光亭','何耕','宋','宋诗','song-poetry','','[]','枯木倚寒巖，三冬無暖氣。',48,'全唐诗/poet.song.144000.json','["枯木倚寒巖，三冬無暖氣。", "達人定汝笑，胸中太涇渭。", "不妨聲色海，徑造佛祖地。", "所以亦樂翁，花前時一醉。"]'),
('3452d09f-e4ec-404d-b0fa-b4cf1bbc2f36','自合江亭過渡觀趙穆仲園亭','何耕','宋','宋诗','song-poetry','','[]','喚舟芳草渡，繫馬綠楊陰。',48,'全唐诗/poet.song.144000.json','["喚舟芳草渡，繫馬綠楊陰。", "步入莓苔徑，門開花竹林。", "王孫隨牒遠，婺女隠雲深。", "想見西南望，悠悠空賞心。"]'),
('aff8de46-66ab-4817-be79-84c5eac44cfd','春日  其一','何耕','宋','宋诗','song-poetry','','[]','聞道西樓下，香風颺綺羅。',48,'全唐诗/poet.song.144000.json','["聞道西樓下，香風颺綺羅。", "無錢沽酒得，不醉奈愁何。", "老去春緣薄，慵來睡興多。", "閉門終一枕，亦不夢南柯。"]'),
('112d3990-80a0-476d-974a-99f2d78e4e8a','春日  其二','何耕','宋','宋诗','song-poetry','','[]','寂寞城南寺，三年寄索居。',48,'全唐诗/poet.song.144000.json','["寂寞城南寺，三年寄索居。", "折花修佛供，持缽乞僧餘。", "竟日無車騎，依時認鼓魚。", "九衢塵一尺，吾自有華胥。"]'),
('5fe50cec-81bf-4919-82c9-1425a2a24873','春日  其三','何耕','宋','宋诗','song-poetry','','[]','門前無俗物，城上亦奇觀。',48,'全唐诗/poet.song.144000.json','["門前無俗物，城上亦奇觀。", "花浪東流穩，雲山西望寒。", "身凌塵外遠，目極意中寬。", "最愛風標客，晴沙理青紈。"]'),
('35c030ab-9e1e-403e-a822-0e971a00d3db','春日  其四','何耕','宋','宋诗','song-poetry','','[]','萬里橋邊水，朝宗去入吳。',48,'全唐诗/poet.song.144000.json','["萬里橋邊水，朝宗去入吳。", "衮衣新歷數，神算舊規模。", "四澥從心正，諸公著力無。", "際天東望眼，淼淼但平蕪。"]'),
('81bb47ce-9c86-4a94-b251-50e41b2fbbb5','春日  其五','何耕','宋','宋诗','song-poetry','','[]','唇齒輔車勢，坤維井絡方。',48,'全唐诗/poet.song.144000.json','["唇齒輔車勢，坤維井絡方。", "只宜花柳盛，莫遣鳥魚忙。", "隴麥無由食，邊籌是可防。", "出言還有禁，忍淚下成行。"]'),
('88bbfb01-ad76-4516-904d-dcf0db00fc51','題龍華山寺','何耕','宋','宋诗','song-poetry','','[]','傑閣山爲佛，精廬地布金。',48,'全唐诗/poet.song.144000.json','["傑閣山爲佛，精廬地布金。", "水涵空闊凈，路繞翠微深。", "鳥下窺齋缽，龍歸識梵音。", "城中塵瞇目，那得此幽尋。"]'),
('14636b18-2b4d-45b6-84d4-856356951ffd','浮翠橋','何耕','宋','宋诗','song-poetry','','[]','隔溪蒼翠各西東，架竹爲梁路始通。',64,'全唐诗/poet.song.144000.json','["隔溪蒼翠各西東，架竹爲梁路始通。", "缺月罅林凝凈綠，斷霞明水抹殘紅。", "芒鞋步步幽深處，藜杖聲聲屈曲中。", "回首忽驚橋已遠，泠然身御圃田風。"]'),
('94bb005a-7142-4d59-ba83-b861740dd808','寒碧亭','何耕','宋','宋诗','song-poetry','','[]','凭欄日日俯清湍，洗竹年年斬惡竿。',64,'全唐诗/poet.song.144000.json','["凭欄日日俯清湍，洗竹年年斬惡竿。", "十頃玻璃秋色靜，一林竿籟曉聲寒。", "凉風有意生天末，明月無邊照水端。", "誰謂過清難久處，愚溪元自不相安。"]'),
('20b94f55-ce71-4009-a268-ee51d721fee5','遠色閣','何耕','宋','宋诗','song-poetry','','[]','小小樓居著散仙，淵明真趣本幽然。',47,'全唐诗/poet.song.144000.json','["小小樓居著散仙，淵明真趣本幽然。", "招呼雲月欄干曲，顧揖江山拄杖前。", "獨鳥倦歸翻落日，誰家晨爨起炊。"]'),
('5c2f5a76-2d37-42cd-bcef-e08b9c05925a','龍華大像蓋冀國夫人所作因成二絕  其一','何耕','宋','宋诗','song-poetry','','[]','慧性元從戒定薰，百花潭水洗僧裙。',32,'全唐诗/poet.song.144000.json','["慧性元從戒定薰，百花潭水洗僧裙。", "箇中力量真超絕，故老尚傳娘子軍。"]'),
('5f2f0172-96ad-4287-b2de-e9270df8edcc','龍華大像蓋冀國夫人所作因成二絕  其二','何耕','宋','宋诗','song-poetry','','[]','生男箇箇欲如狼，婦女軍中氣不揚。',32,'全唐诗/poet.song.144000.json','["生男箇箇欲如狼，婦女軍中氣不揚。", "試問爭功嗔目士，幾人能敵浣花娘。"]'),
('93a87de5-e5d6-4e26-b0f1-686ff7d7303e','假山','何耕','宋','宋诗','song-poetry','','[]','空庭幻出小嶙峋，假外應須別有真。',32,'全唐诗/poet.song.144000.json','["空庭幻出小嶙峋，假外應須別有真。", "只恐話頭成兩橛，若爲融攝主和賓。"]'),
('eae4e47e-26d2-4fc6-9b30-7ce046fa7318','蓮塘','何耕','宋','宋诗','song-poetry','','[]','色香無比出西方，何物妖狐號六郎。',32,'全唐诗/poet.song.144000.json','["色香無比出西方，何物妖狐號六郎。", "手折一枝聊供佛，前身定是老柴桑。"]'),
('3b0eb7f8-07b7-4ed8-9084-39a171c78989','蘭坡','何耕','宋','宋诗','song-poetry','','[]','蘭與高人臭味同，含薰聊復待清風。',32,'全唐诗/poet.song.144000.json','["蘭與高人臭味同，含薰聊復待清風。", "紛紛蕭艾無相笑，爾輩敷榮轉眼空。"]'),
('4027f76c-3238-4b21-86d4-99322f2c29f8','段文昌讀書臺  其一','何耕','宋','宋诗','song-poetry','','[]','段公曾此讀羣書，讀破應須萬卷餘。',32,'全唐诗/poet.song.144000.json','["段公曾此讀羣書，讀破應須萬卷餘。", "家禮一傳爲雜俎，稗官收拾附虞初。"]'),
('a847f6f7-a8f3-4149-8286-35ecc497f9f9','段文昌讀書臺  其二','何耕','宋','宋诗','song-poetry','','[]','隴麥漸漸滿意青，只憂春旱起蟊螟。',32,'全唐诗/poet.song.144000.json','["隴麥漸漸滿意青，只憂春旱起蟊螟。", "當年人誦禱而雨，合向茲山試乞靈。"]'),
('f309efcd-4d1c-4cd5-8846-843caf54bead','學射山相傳蜀後主劉禪習射於此因以得名有感二作  其一','何耕','宋','宋诗','song-poetry','','[]','苦無雄畧但兒嬉，尚想山頭學射時。',32,'全唐诗/poet.song.144000.json','["苦無雄畧但兒嬉，尚想山頭學射時。", "忽報陰平魚貫入，可憐一鏃不能施。"]'),
('33fc307a-5ecd-4c7b-92f5-1a7d019aad26','學射山相傳蜀後主劉禪習射於此因以得名有感二作  其二','何耕','宋','宋诗','song-poetry','','[]','修明國政保關山，豈在馳驅縱送間。',32,'全唐诗/poet.song.144000.json','["修明國政保關山，豈在馳驅縱送間。", "空使流人登劍閣，向風長喟笑庸孱。"]'),
('2a424a2d-d86a-402f-a214-80d3a4d2fd43','留隠庵老住碧蘆軒','何耕','宋','宋诗','song-poetry','','[]','庵中之人不見形，兩脚不住以隠名。',96,'全唐诗/poet.song.144000.json','["庵中之人不見形，兩脚不住以隠名。", "此行有似風過海，摸索不著聞其聲。", "浣花江頭萬僧市，抵掌笑談兒輩驚。", "一軒碧蘆佛手種，霜葉戚戚如詩鳴。", "此間謂是留鳳處，但恐還作冥鴻征。", "卷衣我亦逐師去，分取半庵栖月明。"]'),
('e58327a6-20f2-492f-87d7-21bf51190c4a','題長松二首  其一','何耕','宋','宋诗','song-poetry','','[]','老檜摇風萬壑聲，梨花著雨四山明。',32,'全唐诗/poet.song.144000.json','["老檜摇風萬壑聲，梨花著雨四山明。", "龕中大士好看客，排遣雲陰作晚晴。"]'),
('d36ce867-eeb8-4fb4-b2c7-ae259e838be0','題長松二首  其二','何耕','宋','宋诗','song-poetry','','[]','路窮山百轉，雲擁木千章。',48,'全唐诗/poet.song.144000.json','["路窮山百轉，雲擁木千章。", "蕞爾人間世，蕭然古道場。", "龍神森拱衛，旱魃走祈禳。", "地遠齋厨薄，重來剩裹糧。"]'),
('293e0f47-e3db-4c69-aa48-12c26e40929c','暇日與陳楚材游四天王寺見五髻文殊畫像于廡下剝落可惜遂以告羅宗約參議遷之正法禪院俾長老惠公龕而祠之爲詩十四韻書其事','何耕','宋','宋诗','song-poetry','','[]','陳侯招我古寺行，破椽老瓦煩支撐。',224,'全唐诗/poet.song.144000.json','["陳侯招我古寺行，破椽老瓦煩支撐。", "丹青巨壁置廡下，大士五髻彯華纓。", "旁風上雨塵土集，意象落莫無光晶。", "近前諦視乃名筆，妙處不減本與瓊。", "惜哉此地非所託，走卒嘈雜兒童輕。", "西鄰塔廟頗雄偉，彌天老惠新主盟。", "撞鐘擊鼓飯千指，分坐豈無三尺楹。", "何人堪作不請友，參謀行解俱圓明。", "從容試以語二士，曰此甚易非難成。", "便從游戲出三昧，各借一臂相扶擎。", "騰空似赴遠公約，散花如入維摩城。", "都人改觀香火肅，雨淚膜拜爭投誠。", "主人更在好看客，永爲道伴終生平。", "莫言有我不須你，留取眉毛遮眼睛。"]'),
('378b847d-e360-46d8-a347-73946b8d7e53','成都即事','何耕','宋','宋诗','song-poetry','','[]','零落紅成陣，扶疎綠結幃。',48,'全唐诗/poet.song.144000.json','["零落紅成陣，扶疎綠結幃。", "簡書留客住，風雨卷春歸。", "是處羈懷惡，浮生樂事希。", "錦江拚盡醉，欲典却無衣。"]'),
('91a5a326-0eeb-4b0c-8958-7c19b65c72f5','正月二十七日侍二老人出萬里橋游寶歷寺謁五丈天王至合江亭登小舟往來江中日晚出舟憩卧柳亭以歸記所見','何耕','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','城中少樂事，日日走塵土。',288,'全唐诗/poet.song.144000.json','["城中少樂事，日日走塵土。", "因循嘉節過，春物遽如許。", "駕言遊近郊，及此新過雨。", "梨花雪飄零，麥脚浪掀舞。", "傷心梅已葉，慰眼杏初吐。", "荒凉入古寺，迢遞行兩廡。", "耽耽巨入閣，擐甲碩且武。", "出門詣支徑，信馬踏江滸。", "小舟呼未至，危亭憩方午。", "長江渺無際，遠岫明可數。", "舟中更奇絕，一視隘天宇。", "深流風浩蕩，淺岸石齟齬。", "水鳬貞自適，修竹不知主。", "摇摇打魚艇，丁丁造船斧。", "林疎見官道，路轉失前浦。", "奇觀非一狀，四面皆可取。", "斗酒不妄傾，佳處輒自舉。", "杯盤漸狼藉，野䔩旋燒煮。", "夷猶興未盡，落日挂村塢。", "歸塗繞城隈，醉眼迷處所。", "卧柳久知名，敗屋費撐拄。", "輕盈楚宮樣，何事腰傴僂。", "臨風發浩歎，空響答人語。", "吾親俱老矣，君羹未嘗覩。"]'),
('8d881632-31c7-4c3c-968e-e3bc40045ff0','論俗詩四首  其一','何耕','宋','宋诗','song-poetry','','[]','時間忿怒便行拳，招引官司在眼前。',32,'全唐诗/poet.song.144000.json','["時間忿怒便行拳，招引官司在眼前。", "下獄戴枷遭責罰，更須枉費幾多錢。"]'),
('998ebd40-7cd9-4f4b-bc3d-0099ba301a37','論俗詩四首  其二','何耕','宋','宋诗','song-poetry','','[]','他侵我界是無良，我與他爭未是長。',32,'全唐诗/poet.song.144000.json','["他侵我界是無良，我與他爭未是長。", "布施與他三尺地，休誇誰弱又誰强。"]'),
('2b2cbad8-0b64-4ef3-89fa-2cf38e59ff64','論俗詩四首  其三','何耕','宋','宋诗','song-poetry','','[]','寫狀唆人去入官，入時容易出時難。',32,'全唐诗/poet.song.144000.json','["寫狀唆人去入官，入時容易出時難。", "引人平地破家産，他在傍邊冷眼看。"]'),
('346c053a-741e-4c9a-94ce-12edfb051c5b','論俗詩四首  其四','何耕','宋','宋诗','song-poetry','','[]','傷人利己事多端，唆訟尤爲第一般。',32,'全唐诗/poet.song.144000.json','["傷人利己事多端，唆訟尤爲第一般。", "二競力疲俱願息，中人未了又經官。"]'),
('69e01c2d-d607-4e62-b4da-114cae969902','君子堂','尤袤','宋','宋诗','song-poetry','','[]','堂堂文簡公，一世夔與臯。',48,'全唐诗/poet.song.144000.json','["堂堂文簡公，一世夔與臯。", "君子哉若人，此言聖所褒。", "遺愛在斯民，誰能薦牲牢。", "獨有坐嘯地，清風仰彌高。"]'),
('4b62d67d-f954-4bd7-8dcf-bf630c274123','節愛堂','尤袤','宋','宋诗','song-poetry','','[]','誰憐窮山民，糠籺不自贍。',48,'全唐诗/poet.song.144000.json','["誰憐窮山民，糠籺不自贍。", "紛紛死溝壑，往往困征歛。", "夫惟節與愛，是謂仁且儉。", "揭茲聖人言，聊用自鍼砭。"]'),
('e0eb5983-7f47-4e07-bcec-b339439a9686','凝思堂','尤袤','宋','宋诗','song-poetry','','[]','失脚墜塵網，牒訴裝吾懷。',48,'全唐诗/poet.song.144000.json','["失脚墜塵網，牒訴裝吾懷。", "公庭了官事，時來坐幽齋。", "天風肅泠泠，山鳥鳴喈喈。", "我思在何許，獨對蒼然崖。"]'),
('65f401b1-dbb0-492c-9caa-1a72ea1bb218','樂山堂','尤袤','宋','宋诗','song-poetry','','[]','草堂有遺基，榛莽歲月久。',48,'全唐诗/poet.song.144000.json','["草堂有遺基，榛莽歲月久。", "我來始經葺，挹翠開戶牖。", "羣山供嘯傲，萬象皆奔走。", "所以名樂山，欲企仁者壽。"]'),
('b4604b3f-dfb9-4fc4-b80d-0f5fa313a8a6','匿峰亭','尤袤','宋','宋诗','song-poetry','','[]','山亭在山背，不見山巍巍。',48,'全唐诗/poet.song.144000.json','["山亭在山背，不見山巍巍。", "但見四面風，輻湊朝宗之。", "深藏固甚智，自牧甘處卑。", "一謙受四益，是以能不危。"]'),
('649b6a41-f590-46be-be90-dab0d493e37b','駐目亭','尤袤','宋','宋诗','song-poetry','','[]','攀梯上甓級，小憩得危亭。',48,'全唐诗/poet.song.144000.json','["攀梯上甓級，小憩得危亭。", "一覽盡寥廓，四山聳寒青。", "浩若凌太虛，翩如逐遐征。", "昏花拭病目，望處增雙明。"]'),
('1471dbbc-9d8b-4f7c-a4b0-a5d54bdace44','台州郡齋雜詠十二首 參雲亭','尤袤','宋','宋诗','song-poetry','','[]','昔賢已跨鶴，故跡餘參雲。',48,'全唐诗/poet.song.144000.json','["昔賢已跨鶴，故跡餘參雲。", "舊德慨云遠，干霄氣仍存。", "青山宿霧捲，喬木蒼烟昏。", "尚想來遊處，笙簫中夜聞。"]'),
('9f3ea2b7-dae8-432d-a347-62632298aadd','台州郡齋雜詠十二首 雙巖堂','尤袤','宋','宋诗','song-poetry','','[]','兩巖鬰青蒼，中有堂突兀。',48,'全唐诗/poet.song.144000.json','["兩巖鬰青蒼，中有堂突兀。", "回廊外環遶，脩竹布行列。", "懸崖上幽徑，窺壁見遺碣。", "面牆誰所築，除去礙膺物。"]'),
('e6af878f-9afd-426b-8f55-90001d54aa0b','台州郡齋雜詠十二首 玉霄亭','尤袤','宋','宋诗','song-poetry','','[]','青山圍郡城，東望獨空遠。',48,'全唐诗/poet.song.144000.json','["青山圍郡城，東望獨空遠。", "蒼茫溟海近，相像蓬萊淺。", "朝光上遺堞，雲氣接虛巘。", "羨門與安期，鸞鶴若在眼。"]'),
('e8126ee8-d034-4612-a4f3-ab068fd86e1e','台州郡齋雜詠十二首 清平閣','尤袤','宋','宋诗','song-poetry','','[]','舉世溷濁中，誰當清見底。',48,'全唐诗/poet.song.144000.json','["舉世溷濁中，誰當清見底。", "崎嶇太行道，誰貴平如坻。", "安得□□美，如此一池水。", "悠悠小閣□，視水知此理。"]'),
('6af585ff-9fba-42f3-9262-d3cb362240a9','台州郡齋雜詠十二首 霞起堂','尤袤','宋','宋诗','song-poetry','','[]','□□赤城山，霞色起夜半。',48,'全唐诗/poet.song.144000.json','["□□赤城山，霞色起夜半。", "建標自古□，□□羨吟翫。", "僊人□□□，□手若可喚。", "彤光射胸臆，三嚥骨自換。"]'),
('8f99e96a-0c58-4552-b442-d4ee43afc79d','台州四詩  其一','尤袤','宋','宋诗','song-poetry','','[]','三日霪霖已渺漫，未晴三日又言乾。',32,'全唐诗/poet.song.144000.json','["三日霪霖已渺漫，未晴三日又言乾。", "自來說道天難做，天到台州分外難。"]'),
('6a8f2b70-757e-4429-a0fd-d97fe61227a8','台州四詩  其二','尤袤','宋','宋诗','song-poetry','','[]','百病瘡痍費撫摩，官供仍媿拙催科。',32,'全唐诗/poet.song.144000.json','["百病瘡痍費撫摩，官供仍媿拙催科。", "自憐鞅掌成何事，贏得霜毛一倍多。"]'),
('3880ce45-8886-4ede-b6c2-56997bd3aa55','台州四詩  其三','尤袤','宋','宋诗','song-poetry','','[]','多病多愁老使君，不憂風雨不憂貧。',32,'全唐诗/poet.song.144000.json','["多病多愁老使君，不憂風雨不憂貧。", "三年不識東湖面，枉與東湖作主人。"]'),
('c228a136-59f1-4681-93c3-e879dc6d2c48','台州四詩  其四','尤袤','宋','宋诗','song-poetry','','[]','兩載終更過七旬，今朝方始是閑身。',32,'全唐诗/poet.song.144000.json','["兩載終更過七旬，今朝方始是閑身。", "細看壁上題名記，六十年間只五人。"]'),
('614cc63c-52e1-4ba2-9876-e44ee858838c','寄林景思','尤袤','宋','宋诗','song-poetry','','[]','臨海睽離七度春，都城相見話悲辛。',64,'全唐诗/poet.song.144000.json','["臨海睽離七度春，都城相見話悲辛。", "蒼顔白髮渾非舊，短句長篇却有神。", "一第蹉跎真可歎，半生奔走坐長貧。", "老懷先自難爲別，相識如君更幾人。"]'),
('d9cd2a97-1ddc-4498-9e75-8fb9695934c7','青山寺','尤袤','宋','宋诗','song-poetry','','[]','崢嶸樓閣插天開，門外湖山翠作堆。',64,'全唐诗/poet.song.144000.json','["崢嶸樓閣插天開，門外湖山翠作堆。", "蕩漾煙波迷澤國，空濛雲氣認蓬萊。", "香銷龍象輝金碧，雨過麒麟剝翠苔。", "二十九年三到此，一生知有幾回來。"]'),
('2b6bbc57-65c0-4e75-aa2b-f119cb8c2f6d','聽鶑閣','尤袤','宋','宋诗','song-poetry','','[]','春催金谷曉，一望百花齊。',24,'全唐诗/poet.song.144000.json','["春催金谷曉，一望百花齊。", "不作遼西夢，從渠著意啼。"]'),
('894a38a5-d64d-4307-91b2-6fef47753208','游閤皂山','尤袤','宋','宋诗','song-poetry','','[]','春山靈草百花香，誰識仙家日月長。',32,'全唐诗/poet.song.144000.json','["春山靈草百花香，誰識仙家日月長。", "滿院莓苔綠陰匝，棋聲何處隔宮牆。"]'),
('d3025403-d341-4770-903c-cf998524acc0','易帥守','尤袤','宋','宋诗','song-poetry','','[]','維揚五易帥，山陽四易守。',120,'全唐诗/poet.song.144000.json','["維揚五易帥，山陽四易守。", "我來七八月，月月常奔走。", "帑藏憂煎熬，官民困馳驟。", "世態競趨新，人情蓋詣舊。", "如其數移易，是使政紛糅。", "彼席不得溫，設施亦何有。", "淮南重彫瘵，十室空八九。", "况復苦將迎，不忍更回首。", "嘗聞古爲治，必假歲月久。", "安得如弈棋，易置翻覆手。"]'),
('05d54f68-4ce5-462c-a57c-d3020749f4e2','淮民謠','尤袤','宋','宋诗','song-poetry','','[]','東府買舟船，西府買器械。',240,'全唐诗/poet.song.144000.json','["東府買舟船，西府買器械。", "問儂欲何爲，團結山水寨。", "寨長過我廬，意氣甚雄粗。", "青衫兩承局，暮夜連勾呼。", "勾呼且未已，椎剝到雞豕。", "供應稍不如，向前受笞箠。", "驅東復驅西，棄却鋤與犁。", "無錢買刀劍，典盡渾家衣。", "去年江南荒，趁熟過江北。", "江北不可往，江南歸未得。", "父母生我時，教我學耕桑。", "不識官府嚴，安能事戎行。", "執槍不解刺，執弓不能射。", "團結我何爲，徒勞定無益。", "流離重流離，忍凍復忍饑。", "誰謂天地寬，一身無所依。", "淮南喪亂後，安集亦未久。", "死者積如麻，生者能幾口。", "荒村日西斜，破屋兩三家。", "撫摩力不足，將奈此擾何。"]'),
('86c62503-f368-4bca-ae65-5bebdb018f59','蒙楊廷秀送西歸朝天二集贈以七言','尤袤','宋','宋诗','song-poetry','','[]','西歸累歲却朝天，添得囊中六百篇。',64,'全唐诗/poet.song.144000.json','["西歸累歲却朝天，添得囊中六百篇。", "垂棘連城三倍價，夜光明月十分圓。", "競誇鳳沼詩仙樣，當有鷄林賈客傳。", "我似岑參與高適，姓名得入少陵編。"]'),
('186c56ae-b1d2-4fa8-ae8e-01491bbb9495','題雲海亭','尤袤','宋','宋诗','song-poetry','','[]','亭前山色繞危欄，亭下波濤直浸山。',32,'全唐诗/poet.song.144000.json','["亭前山色繞危欄，亭下波濤直浸山。", "波上漁舟亭上客，相看渾在畫圖間。"]'),
('3cd0f3c0-03ca-4bf0-a9f0-37c998dc600a','張公洞','尤袤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吾聞荆溪南，有地僊所宅。',288,'全唐诗/poet.song.144000.json','["吾聞荆溪南，有地僊所宅。", "十年勞夢想，今日著脚歷。", "扁舟下湖㳇，水漲沒砂磧。", "結纜小橋傍，杖藜從所適。", "平岡面坡陁，疊嶂堆襞積。", "行行三兩里，夾道喬木植。", "其末幾合抱，其高乃千尺。", "風生萬壑響，日照四山赤。", "時摇樹林抄，忽見屋宇脊。", "宮門何崢嶸，南路頗脩直。", "長廊景曀曀，崩殿人寂寂。", "寥落昔賢題，摩挲壁間墨。", "捫蘿上層嶺，俯瞰得深窟。", "危梯交枝撐，鳥道穿詰屈。", "投身乍寬縱，跼步仍逼窄。", "攀援愁顛躋，傲睨驚險僻。", "懸崖朵頦頷，亂石拱劍戟。", "白雲何時橫，乳溢或自滴。", "中空正澒洞，了不見天隙。", "冥行迷近遠，傴僂猶擿埴。", "巉巖豈人工，隠軫入地脈。", "窮幽或篝火，俯跪僅容席。", "仙壇尚故處，丹竈儼遺跡。", "山蟲鳴咿嚘，野鼠聲嘖唶。"]'),
('2881c3b4-27be-4079-a4fd-ef5fa8e531ac','己亥元日','尤袤','宋','宋诗','song-poetry','','[]','玉曆均調歲啟端，東風又逐斗杓還。',64,'全唐诗/poet.song.144000.json','["玉曆均調歲啟端，東風又逐斗杓還。", "蕭條門巷經過少，老病腰支拜起難。", "白髮但能欺槁項，青春不解駐朱顔。", "餘齡有幾仍多幸，占得山林一味閒。"]'),
('4a1f3b57-1bba-4fbe-9cdf-7828b8069d22','次韻德翁苦雨','尤袤','宋','宋诗','song-poetry','','[]','十年江國水如淫，怕見三秋雨作霖。',64,'全唐诗/poet.song.144000.json','["十年江國水如淫，怕見三秋雨作霖。", "可念田家妨卒歲，須煩風伯蕩層陰。", "禾頭昨夜憂生耳，木德何時却守心。", "兀坐書窗詩作祟，寒蟲嗚咽伴愁吟。"]'),
('21078993-102d-49f2-9ade-dda5bf1d5e78','梅','尤袤','宋','宋诗','song-poetry','','[]','不奈雪埋照，可堪風漏香。',48,'全唐诗/poet.song.144000.json','["不奈雪埋照，可堪風漏香。", "天寒無疹粟，日暮有嚴粧。", "桃李真肥婢，松筠共老蒼。", "合教居第一，獨自占年芳。"]'),
('566c5ddf-5318-4c93-9b6c-2b155c610119','和渭叟梅花','尤袤','宋','宋诗','song-poetry','','[]','不避風霜苦，自甘丘壑潛。',48,'全唐诗/poet.song.144000.json','["不避風霜苦，自甘丘壑潛。", "未禁沾額角，信好插梳尖。", "春意已張本，寒威今解嚴。", "殷勤留客意，尚許隔牆覘。"]'),
('b99bdc52-5ea9-47f2-9179-73f834374dc5','梅花','尤袤','宋','宋诗','song-poetry','','[]','冷豔天然白，寒香分外清。',48,'全唐诗/poet.song.144000.json','["冷豔天然白，寒香分外清。", "稍驚春色早，又喚客愁生。", "待索巡簷笑，嫌聞出塞聲。", "園林多少樹，見爾眼偏明。"]'),
('cfe919cb-2113-43c8-be1a-466c5bc3742e','蠟梅','尤袤','宋','宋诗','song-poetry','','[]','破臘驚春意，凌寒試曉粧。',48,'全唐诗/poet.song.144000.json','["破臘驚春意，凌寒試曉粧。", "應嫌脂粉白，故染麴塵黄。", "綴樹蜂懸室，排箏雁著行。", "團酥與凝蠟，難學是生香。"]'),
('f72c7966-a4b3-4526-9740-c9a08b6df6fb','次韻尹朋梅花','尤袤','宋','宋诗','song-poetry','','[]','江北江南天未春，陽和先已到孤根。',64,'全唐诗/poet.song.144000.json','["江北江南天未春，陽和先已到孤根。", "斜枝冷落溪頭路，瘦影扶疏竹外村。", "水部未妨時遣興，玉妃誰復與招魂。", "天寒好伴羅浮醉，明月清風許重論。"]'),
('03babc6e-da8e-46d3-b44f-8b6009fc2ea6','梅花二首  其一','尤袤','宋','宋诗','song-poetry','','[]','竹外籬邊一樹斜，可憐芳意自萌芽。',64,'全唐诗/poet.song.144000.json','["竹外籬邊一樹斜，可憐芳意自萌芽。", "也知春到先舒蕊，又被寒欺不放花。", "索笑幾回驚歲晚，相思一夜繞天涯。", "直須待得垂垂發，踏月相携過酒家。"]'),
('7bca2aaf-a555-46d2-9eb0-efba84e7ceeb','梅花二首  其二','尤袤','宋','宋诗','song-poetry','','[]','冷蕊疏枝半不禁，眼看芳信日駸駸。',64,'全唐诗/poet.song.144000.json','["冷蕊疏枝半不禁，眼看芳信日駸駸。", "雪霜不管朝天面，風月能知匪石心。", "望遠可無南北使，客愁空費短長吟。", "年年准擬花排恨，不道看花恨更深。"]'),
('ca33bd8e-3b4e-4ac3-8ebd-d6d4c65d4bda','落梅','尤袤','宋','宋诗','song-poetry','','[]','清溪西畔小橋東，落月紛紛水映紅。',64,'全唐诗/poet.song.144000.json','["清溪西畔小橋東，落月紛紛水映紅。", "五夜客愁花片裏，一年春事角聲中。", "歌殘玉樹人何在，舞破山香曲未終。", "却憶孤山醉歸路，馬蹄香雪襯東風。"]'),
('13545233-a41a-43c3-b37b-a05db3e0905f','入春半月未有梅花','尤袤','宋','宋诗','song-poetry','','[]','枯樹扶疏水滿池，攀翻未見玉團枝。',64,'全唐诗/poet.song.144000.json','["枯樹扶疏水滿池，攀翻未見玉團枝。", "應羞無雪教誰伴，未肯先春獨探支。", "幾度杖藜貪看早，一年芳信恨開遲。", "留連東閣空愁絕，只誤何郎作好詩。"]'),
('1fa39788-030a-4de7-9485-f177821292bb','德翁有詩再用前韻三首  其一','尤袤','宋','宋诗','song-poetry','','[]','文章仙伯記仇池，每想橫斜竹外枝。',64,'全唐诗/poet.song.144000.json','["文章仙伯記仇池，每想橫斜竹外枝。", "未放柔柯攢玉雪，稍看紅蒂染燕支。", "別來望遠憑誰寄，老去尋春只恐遲。", "把酒問花花解語，定應催促要新詩。"]'),
('f7fd00c2-e7af-4b5d-9822-07e7b32c50fb','德翁有詩再用前韻三首  其二','尤袤','宋','宋诗','song-poetry','','[]','立馬黄昏遶曲池，幾回踏雪問南枝。',64,'全唐诗/poet.song.144000.json','["立馬黄昏遶曲池，幾回踏雪問南枝。", "不應春到花猶未，定恐寒侵力不支。", "隴上已驚傳信晚，樽前只想弄粧遲。", "臨風不語空歸去，獨立無憀自詠詩。"]'),
('610bae95-7eb5-4796-983a-1e4f34a4ff15','德翁有詩再用前韻三首  其三','尤袤','宋','宋诗','song-poetry','','[]','嘗記尋芳到習池，攀條頻認去年枝。',64,'全唐诗/poet.song.144000.json','["嘗記尋芳到習池，攀條頻認去年枝。", "曉穿曲徑千林去，晚度危橋一木支。", "不避春寒來得得，只緣人望故遲遲。", "無錢可辦羅浮醉，報答春光只有詩。"]'),
('172fd1d1-10af-4c32-9aef-04b228439774','次韻渭叟蠟梅','尤袤','宋','宋诗','song-poetry','','[]','快瀉鵝黄若下春，要將香色鬭清珍。',64,'全唐诗/poet.song.144000.json','["快瀉鵝黄若下春，要將香色鬭清珍。", "蠟丸暗拆東君信，梔貌寧欺我輩人。", "光價未輸何遜早，詩篇重見豫章新。", "渾金璞玉爭多少，要與江梅作近親。"]'),
('d1228ef3-5aea-4623-9328-76d89bc3250b','雪','尤袤','宋','宋诗','song-poetry','','[]','睡覺不知雪，但驚窗戶明。',48,'全唐诗/poet.song.144000.json','["睡覺不知雪，但驚窗戶明。", "飛花厚一尺，和月照三更。", "草木淺深白，丘堘高下平。", "饑民莫咨怨，第一念邊兵。"]'),
('b9bbee8a-ad48-4124-af2d-3a62caf6c6b0','甲午春前得雪  其一','尤袤','宋','宋诗','song-poetry','','[]','寒聲昨夜響蕭蕭，逗曉堦庭亦已消。',64,'全唐诗/poet.song.144000.json','["寒聲昨夜響蕭蕭，逗曉堦庭亦已消。", "殘臘距春無幾日，一年飛雪只今朝。", "微陽欲動梅驚萼，餘潤纔沾麥放苗。", "天意未能違物意，漫留殘白占山腰。"]'),
('f95541d0-8094-4da2-9fbe-94fe1c589bec','甲午春前得雪  其二','尤袤','宋','宋诗','song-poetry','','[]','飛英回旋逐風飄，爽氣令人意欲消。',64,'全唐诗/poet.song.144000.json','["飛英回旋逐風飄，爽氣令人意欲消。", "荏苒流年春送臘，殷勤密雪暮連朝。", "冬回庾嶺花無數，煙煖藍田玉有苗。", "一飽自今真可望，更看南畝麥齊腰。"]'),
('0def5f8b-a5b1-44bb-bb84-dde8f6075cd7','甲午春前得雪  其三','尤袤','宋','宋诗','song-poetry','','[]','凍雲排陣擁山椒，待伴還應不肯消。',64,'全唐诗/poet.song.144000.json','["凍雲排陣擁山椒，待伴還應不肯消。", "皎月冰壺千頃夜，冷烟茅屋幾家朝。", "梅枝堆亞難尋萼，萱草侵凌不辨苗。", "殘甲敗鱗隨處是，被誰敲折玉龍腰。"]'),
('625b4834-f3f6-45e5-9241-7d0d995735f1','正月二十八日夜大雪','尤袤','宋','宋诗','song-poetry','','[]','一冬無雪潤田疇，渴井泉源凍不流。',64,'全唐诗/poet.song.144000.json','["一冬無雪潤田疇，渴井泉源凍不流。", "昨夜忽飛三尺雪，今年須兆十分秋。", "占時父老應先喜，忍凍饑民莫漫愁。", "晴色已回春氣候，晚風摇綠看來牟。"]'),
('c30f762e-22d7-4505-86bb-1c40d36b7a1a','別李德翁','尤袤','宋','宋诗','song-poetry','','[]','長恨古人少，斯人今古人。',48,'全唐诗/poet.song.144000.json','["長恨古人少，斯人今古人。", "二難俱益友，兩載覺情親。", "世態深難測，心期久益真。", "相看俱半百，此別倍酸辛。"]'),
('b137b782-2907-458e-a5f0-1df41ec5b33c','別林景思','尤袤','宋','宋诗','song-poetry','','[]','二年無德及斯民，獨喜從游得此君。',64,'全唐诗/poet.song.144000.json','["二年無德及斯民，獨喜從游得此君。", "囊乏一錢窮到骨，胸蟠千古氣凌雲。", "論交却恨相逢晚，別袂真成不忍分。", "後夜相思眇空闊，尺書應許雁知聞。"]'),
('44b8f87f-ed38-4017-9913-a721b82fbb11','送晦菴南歸','尤袤','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','二年摩手撫瘡痍，恩與廬山五老齊。',64,'全唐诗/poet.song.144000.json','["二年摩手撫瘡痍，恩與廬山五老齊。", "合侍玉皇香案側，却持華節大江西。", "鼎新白鹿諸生學，築就長虹萬丈堤。", "待哺饑民偏戀德，老翁猶作小兒啼。"]'),
('85bd03e4-c687-4ae5-9327-bcb2aefa4c15','送提舉楊大監解組西歸','尤袤','宋','宋诗','song-poetry','','[]','征轅已動不容攀，回首棠陰蔽芾間。',64,'全唐诗/poet.song.144000.json','["征轅已動不容攀，回首棠陰蔽芾間。", "爲郡不知歌舞樂，憂民贏得鬢毛斑。", "澄清未展須持節，注想方深便賜環。", "從此相思隔烟水，夢魂飛不到螺山。"]'),
('4d0b673e-8f4f-4067-b705-79421da45b3a','送吳待制帥襄陽二首  其一','尤袤','宋','宋诗','song-poetry','','[]','方持紫橐侍西清，忽領雄藩向暑行。',64,'全唐诗/poet.song.144000.json','["方持紫橐侍西清，忽領雄藩向暑行。", "誰謂風流貴公子，甘爲辛苦一書生。", "詞源筆下三千牘，武庫胸中十萬兵。", "從此君王寬北顧，山南東道得長城。"]'),
('77ed1957-1216-4525-8405-610f6691e2f3','送吳待制帥襄陽二首  其二','尤袤','宋','宋诗','song-poetry','','[]','欲將盤錯試餘鋒，故擁旗麾訖外庸。',64,'全唐诗/poet.song.144000.json','["欲將盤錯試餘鋒，故擁旗麾訖外庸。", "南峴北津形勝地，前羊後杜昔賢蹤。", "不妨倒載同民樂，自有輕裘折虜衝。", "努力功名歸報國，莫思山月與林鐘。"]'),
('06fea692-57b5-4a4c-bd9f-958f7fa44635','送趙子直帥蜀得須字二首  其一','尤袤','宋','宋诗','song-poetry','','[]','射策當年首漢儒，去登雲路只斯須。',64,'全唐诗/poet.song.144000.json','["射策當年首漢儒，去登雲路只斯須。", "飽聞治最誇閩部，已有先聲到益都。", "壯略定羌元自許，宗英帥蜀舊來無。", "前驅叱馭休辭遠，看取東歸上政塗。"]'),
('8a66c438-41cd-4fe3-aa23-85222d045023','送趙子直帥蜀得須字二首  其二','尤袤','宋','宋诗','song-poetry','','[]','帝念西南在一隅，簡求才德應時須。',64,'全唐诗/poet.song.144000.json','["帝念西南在一隅，簡求才德應時須。", "羌夷種落誇威令，秦隴關河聽指呼。", "自古功名多少壯，及今談笑定規模。", "玉山舊政人誰記，應掃棠陰看畫圖。"]'),
('bfc3d806-37d7-4b50-9441-25c62b7706f0','海棠盛開','尤袤','宋','宋诗','song-poetry','','[]','兩株芳蕊傍池陰，一笑嫣然抵萬金。',64,'全唐诗/poet.song.144000.json','["兩株芳蕊傍池陰，一笑嫣然抵萬金。", "火齊照林光灼灼，彤霞射水影沉沉。", "曉粧無力燕支重，春醉方酣酒暈深。", "定自格高難著句，不應工部總無心。"]'),
('d8f4c3f6-7e5a-4661-9090-c11a38d7d79f','玉簪花一名鷺鷥','尤袤','宋','宋诗','song-poetry','','[]','一種幽花迥出塵，孤高恥逐豔陽辰。',64,'全唐诗/poet.song.144000.json','["一種幽花迥出塵，孤高恥逐豔陽辰。", "瑶枝巧插青鸞扇，玉蕊斜欹白鷺巾。", "難與松筠爭歲晚，也同葵藿趁時新。", "西風昨夜驚庭綠，滿院清香惱殺人。"]'),
('53e57987-d8e6-4eb3-a055-12608256cd76','劉屯田墓壯節亭','尤袤','宋','宋诗','song-poetry','','[]','西澗當年卜考槃，便於神武掛衣冠。',64,'全唐诗/poet.song.144000.json','["西澗當年卜考槃，便於神武掛衣冠。", "後生無復知前輩，故老猶能說長官。", "三尺荒墳埋玉冷，百年壯節倚天寒。", "表章頼有羣賢力，誰把生芻奠酒盤。"]'),
('11e4a90a-2dea-4136-8ab2-c1a694729a3a','庚子歲除前一日游茅山','尤袤','宋','宋诗','song-poetry','','[]','犯寒出行遇，值此歲云除。',228,'全唐诗/poet.song.144000.json','["犯寒出行遇，值此歲云除。", "剛風駕飈輪，送我游清都。", "華陽第八天，仙聖之所居。", "洞門劣容人，中寬如室廬。", "橫前大溪水，於焉限塵區。", "其右萬石林，錯落空翠圖。", "茅菴著深秀，細路緣崎嶇。", "幽泉見客喜，頗亦類逃虛。", "山深日易曛，捷徑趨元符。", "琳宮照金碧，天籟鳴笙竽。", "側睨白雲峰，前瞻赤沙湖。", "金壇聳百丈，陰洞通七途。", "俯視人間世，擾擾真蟲蛆。", "蚤以凡陋質，忝分赤城符。", "豈悟夙昔緣，復造神靈墟。", "平生夢寐處，恍若登華胥。", "歸來拜綠章，足力尚有餘。", "珍館十六所，安能徧遨娛。", "窮探恨不盡，大息仍踟躇。"]'),
('d7ce767b-3c8a-43f1-bec8-f03a41353069','大暑留召伯埭','尤袤','宋','宋诗','song-poetry','','[]','清風不肯來，烈日不肯暮。',84,'全唐诗/poet.song.144000.json','["清風不肯來，烈日不肯暮。", "平生山林下，散髮頗箕踞。", "一官走王事，三伏在道途。", "我非褦襶兒，亦爾困馳騖。", "居然戀俎豆，安得免羈馽。", "區區竟何營，汩汩此飄寓。", "淵明應笑人，有底不歸去。"]'),
('a10d354b-2c0d-4a6d-98dd-05070e8b54bb','題米元暉瀟湘圖二首  其一','尤袤','宋','宋诗','song-poetry','','[]','萬里江天杳靄，一村煙樹微茫。',28,'全唐诗/poet.song.144000.json','["萬里江天杳靄，一村煙樹微茫。", "只欠孤篷聽雨，恍如身在瀟湘。"]'),
('3d395d45-42aa-4717-87f8-6efb62a2a703','題米元暉瀟湘圖二首  其二','尤袤','宋','宋诗','song-poetry','','[]','淡淡晴山橫霧，茫茫遠水平沙。',28,'全唐诗/poet.song.144000.json','["淡淡晴山橫霧，茫茫遠水平沙。", "安得綠蓑青笠，往來泛宅浮家。"]'),
('b58a1c95-0e23-4027-af35-a03b16ed5f24','題秋霜閣後山泉','尤袤','宋','宋诗','song-poetry','','[]','誰把機關引石泉，穿崖一溜響濺濺。',32,'全唐诗/poet.song.144000.json','["誰把機關引石泉，穿崖一溜響濺濺。", "爭如廬阜香爐頂，坐看銀河落九天。"]'),
('8fd66b3c-3918-49f3-895e-24378941e574','重登斗野亭二首  其一','尤袤','宋','宋诗','song-poetry','','[]','野色涵空闊，平蕪接渺瀰。',48,'全唐诗/poet.song.144000.json','["野色涵空闊，平蕪接渺瀰。", "江淮天設險，星斗地分維。", "喬木千年意，滄波萬古悲。", "老僧尤好事，見在索題詩。"]'),
('1d19f1d5-48f3-4a14-ab4b-21cc10c39129','重登斗野亭二首  其二','尤袤','宋','宋诗','song-poetry','','[]','豪傑舊游處，此亭名亦俱。',48,'全唐诗/poet.song.144000.json','["豪傑舊游處，此亭名亦俱。", "淒涼謝公堰，浩蕩董家湖。", "陳迹成興廢，遺篇今有無。", "登臨何限恨，搔首獨長吁。"]'),
('8cdb8690-9b2d-4cf3-89f3-ebde08862443','浮遠堂二首  其一','尤袤','宋','宋诗','song-poetry','','[]','杖藜同上最高峰，脚力雖窮興未窮。',32,'全唐诗/poet.song.144000.json','["杖藜同上最高峰，脚力雖窮興未窮。", "領略江山歸眼界，盡吞淮海入胸中。"]'),
('ac2e827d-badb-497a-ade4-d699cd4afc16','浮遠堂二首  其二','尤袤','宋','宋诗','song-poetry','','[]','我生家住浙江西，不見江山自是癡。',32,'全唐诗/poet.song.144000.json','["我生家住浙江西，不見江山自是癡。", "浮遠堂前今日望，畫圖待我看潮時。"]'),
('6dda982a-5dd9-4023-afa5-fb9a4c9bad33','句  其一','尤袤','宋','宋诗','song-poetry','','[]','胸中襞積千般事，到得相逢一語無。',16,'全唐诗/poet.song.144000.json','["胸中襞積千般事，到得相逢一語無。"]'),
('179f3c89-f2d6-4a87-ab07-60a04aa1c2f3','句  其二','尤袤','宋','宋诗','song-poetry','','[]','送客漸稀城漸遠，歸途應減兩三程。',16,'全唐诗/poet.song.144000.json','["送客漸稀城漸遠，歸途應減兩三程。"]'),
('1c45273e-410e-42af-9881-a082543ab4e8','句  其三','尤袤','宋','宋诗','song-poetry','','[]','金馬玉堂慚我輩，青衫白髮念君遲。',16,'全唐诗/poet.song.144000.json','["金馬玉堂慚我輩，青衫白髮念君遲。"]'),
('fdfe0086-d13a-476f-8a10-9f4d058b7447','句  其四','尤袤','宋','宋诗','song-poetry','','[]','强學瞿曇金作面，只應恁怪老禪親。',16,'全唐诗/poet.song.144000.json','["强學瞿曇金作面，只應恁怪老禪親。"]'),
('a5390e2a-267f-4e34-8cb6-c99094e861e6','句  其五','尤袤','宋','宋诗','song-poetry','','[]','千尺龍鱗蟠檜頂，一番蜩甲長蔬苗。',16,'全唐诗/poet.song.144000.json','["千尺龍鱗蟠檜頂，一番蜩甲長蔬苗。"]'),
('755cfa16-f05f-4681-a1f0-214af9798f5f','句  其六','尤袤','宋','宋诗','song-poetry','','[]','剩對風花吟柳絮，更將冰水瀹芎苗。',16,'全唐诗/poet.song.144000.json','["剩對風花吟柳絮，更將冰水瀹芎苗。"]'),
('0f901598-1928-4739-9fff-501912828096','句  其七','尤袤','宋','宋诗','song-poetry','','[]','萬室歡呼忘凍餒，一犁酥潤到根苗。',16,'全唐诗/poet.song.144000.json','["萬室歡呼忘凍餒，一犁酥潤到根苗。"]'),
('4d341db6-7ebc-4e73-be43-66fe01153c2a','句  其八','尤袤','宋','宋诗','song-poetry','','[]','寄語高人來問法，莫辭門外立齊腰。',16,'全唐诗/poet.song.144000.json','["寄語高人來問法，莫辭門外立齊腰。"]'),
('e8136ab2-c12b-44fc-9a99-7653626208c8','句  其九','尤袤','宋','宋诗','song-poetry','','[]','前村酒美無錢換，怪底金龜不繫腰。',16,'全唐诗/poet.song.144000.json','["前村酒美無錢換，怪底金龜不繫腰。"]'),
('fc2967a1-0ae1-4985-bf48-22dbf8cc0f46','句  其一○','尤袤','宋','宋诗','song-poetry','','[]','寒窗莫怪吟聲苦，舉室長懸似細腰。',16,'全唐诗/poet.song.144000.json','["寒窗莫怪吟聲苦，舉室長懸似細腰。"]'),
('a19cedbb-0c02-4303-b1bc-dcb4a3f5d519','句  其一一','尤袤','宋','宋诗','song-poetry','','[]','歸裝見說渾無物，添得新詩數百篇。',16,'全唐诗/poet.song.144000.json','["歸裝見說渾無物，添得新詩數百篇。"]'),
('239f66f7-d4e6-40ac-b5a5-df012bea63e8','句  其一二','尤袤','宋','宋诗','song-poetry','','[]','飽看七寶山頭月，慣聽三茅觀裏鐘。',16,'全唐诗/poet.song.144000.json','["飽看七寶山頭月，慣聽三茅觀裏鐘。"]'),
('ee182ce5-e83f-43bc-ac6e-972bb7349ee7','存目  其一','尤袤','宋','宋诗','song-poetry','','[]','詩題：拄杖首句：久矣相隨苦弟昆。',16,'全唐诗/poet.song.144000.json','["詩題：拄杖首句：久矣相隨苦弟昆。"]'),
('8494abcb-b9c4-4de3-854f-fd61ff45cf5a','存目  其二','尤袤','宋','宋诗','song-poetry','','[]','詩題：送趙成都二首首句：蜀道當謀帥，不但元戎貴。',24,'全唐诗/poet.song.144000.json','["詩題：送趙成都二首首句：蜀道當謀帥，不但元戎貴。"]'),
('3d2e2ccd-32b0-49f5-8128-05851458b2af','九月二十二日晚秋曲宴','宋孝宗','宋','宋诗','song-poetry','','[]','昊穹垂祐福群生，凉德惟知監守成。',64,'全唐诗/poet.song.144000.json','["昊穹垂祐福群生，凉德惟知監守成。", "禾黍三登占叶氣，簫韶九奏播歡聲。", "未央秋晚林塘靜，太液波閒殿閣明。", "嘉與臣鄰同燕樂，益修庶政答丕平。"]'),
('10174af9-a115-4517-b316-bb5c7301cca5','題金山','宋孝宗','宋','宋诗','song-poetry','','[]','屹然山立枕中流，彈壓東南二百州。',32,'全唐诗/poet.song.144000.json','["屹然山立枕中流，彈壓東南二百州。", "狂虜來臨須破膽，何勞平地戰貔貅。"]'),
('1bf1e9bf-8f7d-4470-859d-4bd2e8fca758','新晴有感','宋孝宗','宋','宋诗','song-poetry','','[]','春風歸草木，曉日麗山河。',36,'全唐诗/poet.song.144000.json','["春風歸草木，曉日麗山河。", "物滯欣逢泰，時豐自此多。", "神州應未遠，當繼沛中歌。"]'),
('f2bd7a9e-f609-46d6-a95e-9808b41e10bf','新秋雨過述懷','宋孝宗','宋','宋诗','song-poetry','','[]','雨聲亂秋聲，驅暑逾南海。',72,'全唐诗/poet.song.144000.json','["雨聲亂秋聲，驅暑逾南海。", "凉月倍清輝，細雲變文彩。", "長空肅無限，遠山青不改。", "沉吟感素商，凄清鳴萬籟。", "平生雄武心，覽鏡朱顔在。", "豈惜常憂勤，規恢須廣大。"]'),
('8df14c0f-1f79-4fd9-8360-db59a0f34749','高宗皇帝挽詞  其一','宋孝宗','宋','宋诗','song-poetry','','[]','草昧千齡旦，飈回九縣塵。',48,'全唐诗/poet.song.144000.json','["草昧千齡旦，飈回九縣塵。", "皇天開我宋，丹極下真人。", "指顧山河定，歡呼曆數新。", "斷鼇重立極，更與物爲春。"]'),
('d97c4e5c-9105-40d4-af5c-2256aa4fdf3c','高宗皇帝挽詞  其二','宋孝宗','宋','宋诗','song-poetry','','[]','赤伏興王業，巍巍四十年。',48,'全唐诗/poet.song.144000.json','["赤伏興王業，巍巍四十年。", "佛狸方送死，天馬合爭先。", "自厭兵車會，親提造化權。", "此疆并爾界，恩德到淵泉。"]'),
('84f04246-b6df-4b28-8ff6-311e17c4a59b','高宗皇帝挽詞  其三','宋孝宗','宋','宋诗','song-poetry','','[]','揖遜光堯德，重華愧有虞。',49,'全唐诗/poet.song.144000.json','["揖遜光堯德，重華愧有虞。", "居然將菲質，正爾紹皇圖。", "履燾兼君父，文明炤典印謨。", "大恩渾未報，血泪一時俱。"]'),
('fad58511-8b36-4263-8f8a-aa52f37f3a7e','高宗皇帝挽詞  其四','宋孝宗','宋','宋诗','song-poetry','','[]','不謂神仙窟，今時異昔時。',48,'全唐诗/poet.song.144000.json','["不謂神仙窟，今時異昔時。", "鼎湖龍去遠，社首鳳來遲。", "顧畢三年制，驚聞七月期。", "痛心思繼代，不忘有聲詩。"]'),
('5ca0e18f-63a2-4802-b335-e1919d23f33b','高宗皇帝挽詞  其五','宋孝宗','宋','宋诗','song-poetry','','[]','夢斷堯千歲，神遊漢五陵。',48,'全唐诗/poet.song.144000.json','["夢斷堯千歲，神遊漢五陵。", "洛京元在望，禹穴且相仍。", "仗衛凄烟合，笳簫凍雨凝。", "漫磨千丈石，未是頌中興。"]'),
('173dedc6-9544-4f4e-b0d3-ea1d4f85e012','和史浩曲宴澄碧殿詩','宋孝宗','宋','宋诗','song-poetry','','[]','揖遜荷帝堯，寅恭五元禩。',288,'全唐诗/poet.song.144000.json','["揖遜荷帝堯，寅恭五元禩。", "治道貴清靜，聖言有深旨。", "誰歌元首明，自得股肱喜。", "躋民期仁壽，距肯中道止。", "力農樂彼田，坐賈安於市。", "歲行閲豐登，國論銷委靡。", "予力初何能，濟濟頼多士。", "矧予有元老，中立而不倚。", "居東逾三年，不遠來千里。", "未遂赤松遊，輟誦青琅蘂。", "皓首持六經，日侍明光裏。", "翼乎鴻遇風，縱矣魚在水。", "儒行絕瑕疵，道心無塵滓。", "挺挺松柏姿，巉巉山岳峙。", "予惟日萬幾，至仁同一視。", "西成錫小宴，促坐才尺咫。", "湛露愧歌周，置酒非封齒。", "歸美見新詩，如卿能有幾。", "眷言澄碧行，勝賞得迂趾。", "亦屢引公卿，對此談政理。", "虛心欲受人，忠言資逆耳。", "朕瘠天下肥，至樂無易此。", "頗念文武疆，六合尚殊軌。", "東都會諸侯，宣王昔於是。"]'),
('1bb08bf7-59a8-4a12-99d8-3a2f5c474af8','比幸玉津園縱觀春事適霽色可喜待制洪邁有詩因同其韻','宋孝宗','宋','宋诗','song-poetry','','[]','春郊柔綠遍桑麻，小駐芳園覽物華。',64,'全唐诗/poet.song.144000.json','["春郊柔綠遍桑麻，小駐芳園覽物華。", "應信吾心非暇逸，頓回晴意絕咨嗟。", "每思富庶將同樂，敢務游畋漫自誇。", "不似華清當日事，五家車騎爛如花。"]'),
('751eb23f-461f-494d-8c72-885bb34dfa94','送虞丞相撫蜀','宋孝宗','宋','宋诗','song-poetry','','[]','一德如公豈合閑，聊分西面欲憂寬。',64,'全唐诗/poet.song.144000.json','["一德如公豈合閑，聊分西面欲憂寬。", "不辭論道虛台席，暫假宣威築將壇。", "風教已興三蜀靜，干戈載戢萬方安。", "歸來尚想終霖雨，未許鄉人衣錦看。"]'),
('5e55674d-a078-4960-b9a8-2408e0a5da3c','賜趙士忠二首  其一','宋孝宗','宋','宋诗','song-poetry','','[]','職事煩填委，文墨分消散。',72,'全唐诗/poet.song.144000.json','["職事煩填委，文墨分消散。", "馳翰未暇食，日昃不知晏。", "沈迷簿書領，回回自昏亂。", "釋此出西城，登高且遊觀。", "方塘含白水，中有鳬與雁。", "安得肅肅羽，從爾游波瀾。"]'),
('7314c0f0-8a46-44ab-96f3-e3cc51cc77e7','賜趙士忠二首  其二','宋孝宗','宋','宋诗','song-poetry','','[]','志士惜日短，愁人知夜長。',120,'全唐诗/poet.song.144000.json','["志士惜日短，愁人知夜長。", "攝衣步前庭，仰觀南雁翔。", "淳景隨形運，流響歸空房。", "清風何飄飄，微月出西方。", "繁星依青天，列宿自成行。", "蟬鳴高樹間，野鳥號東廂。", "纖雲時髣髴，渥露沾我裳。", "良時無停景，北斗忽低昂。", "常恐寒節至，凝氣結爲霜。", "落葉隨風摧，一絕如流光。"]'),
('1526da28-123f-4209-a3e9-be2185c61a38','柑橘','宋孝宗','宋','宋诗','song-poetry','','[]','碧玉枝柯柑橘林，開花結子未成金。',32,'全唐诗/poet.song.144000.json','["碧玉枝柯柑橘林，開花結子未成金。", "何當爛熟經霜露，更約提壺一訪尋。"]'),
('681932c9-2427-417b-9809-b68d8009b501','潛邸恭和御製凈明院梅巖詩','宋孝宗','宋','宋诗','song-poetry','','[]','秀色環亭擁霽霞，修筠冰艷數枝斜。',32,'全唐诗/poet.song.144000.json','["秀色環亭擁霽霞，修筠冰艷數枝斜。", "東君欲奉天顔喜，故遣融和放早花。"]'),
('16dbc101-bf06-4357-ab64-49936544501e','賜靈隠住持德光','宋孝宗','宋','宋诗','song-poetry','','[]','大暑流金石，寒風結凍雲。',24,'全唐诗/poet.song.144000.json','["大暑流金石，寒風結凍雲。", "梅花香度遠，自有一枝春。"]'),
('ee8d713b-07b6-4598-8665-7b9a379aa8c1','又賜頌','宋孝宗','宋','宋诗','song-poetry','','[]','欲言心佛難分別，俱是精微無礙通。',32,'全唐诗/poet.song.144000.json','["欲言心佛難分別，俱是精微無礙通。", "跳出千重縛不住，天涯海角任西風。"]'),
('d384b685-d546-474a-ab7f-8e32495541ad','賜圓覺寺僧德信  其一','宋孝宗','宋','宋诗','song-poetry','','[]','古寺春山青更妍，長松修竹翠含煙。',32,'全唐诗/poet.song.144000.json','["古寺春山青更妍，長松修竹翠含煙。", "汲泉擬欲增茶興，暫就僧房借榻眠。"]'),
('876b0097-1d54-40fa-9acb-6d71a6e63ce8','賜圓覺寺僧德信  其二','宋孝宗','宋','宋诗','song-poetry','','[]','坐久方知春晝長，靜中心地自清凉。',32,'全唐诗/poet.song.144000.json','["坐久方知春晝長，靜中心地自清凉。", "人人圓覺何曾覺，但見塵勞盡日狂。"]'),
('f0df51a0-466b-40a3-97a3-ebee47b3f6c6','冷泉堂','宋孝宗','宋','宋诗','song-poetry','','[]','山中秀色何佳哉，一峯獨立名飛來。',196,'全唐诗/poet.song.144000.json','["山中秀色何佳哉，一峯獨立名飛來。", "參差翠麓儼如畫，石骨蒼潤神所開。", "忽開彷像來宮囿，指顧已驚成列岫。", "規模絕似靈隠前，面勢恍疑天竺後。", "孰云人力非自然，千巖萬壑藏雲烟。", "上有崢嶸倚空之翠嶺，下有潺湲漱玉之飛泉。", "一堂虛敞臨清沼，密蔭交加森羽葆。", "山頭草木四時春，閲盡歲寒人不老。", "聖心仁智情幽閒，壺中天地非人間。", "蓬萊方丈渺空闊，豈若坐對三神山。", "日長雅趣超塵俗，散步逍遥快心目。", "山光水色無盡時，長將挹向杯中淥。"]'),
('9a6af763-afee-4db5-9dfb-d5b0277515de','西太乙宮陳朝檜','宋孝宗','宋','宋诗','song-poetry','','[]','道人手種幾生前，鶴骨龍姿尚宛然。',64,'全唐诗/poet.song.144000.json','["道人手種幾生前，鶴骨龍姿尚宛然。", "雙榦一先神物化，九朝三見太平年。", "忽驚華構依岩出，乞與佳名到處傳。", "此柏未枯君記取，灰心聊伴小乘禪。"]'),
('eb27209d-b1c5-42f5-a2fa-443ab1806de0','遊玉津園賜皇太子以下官','宋孝宗','宋','宋诗','song-poetry','','[]','一天秋色破寒煙，別籞連隄壓巨川。',64,'全唐诗/poet.song.144000.json','["一天秋色破寒煙，別籞連隄壓巨川。", "欣見歲功成萬寶，因行射禮命群賢。", "騰騰喜氣隨飛羽，嫋嫋凄風入控弦。", "文武從來資並用，酒餘端有侍臣篇。"]'),
('7ed616b1-7bfc-41c7-925b-122d547ea04d','俞延禧進古澗松以詩賜之','宋孝宗','宋','宋诗','song-poetry','','[]','犖确奔流瀉玉虹，凜然雲幹擬蟠空。',32,'全唐诗/poet.song.144000.json','["犖确奔流瀉玉虹，凜然雲幹擬蟠空。", "紅塵車馬稠如織，夢入蒼煙萬壑風。"]'),
('e9b4c1fb-3405-4cc3-81a8-bd31c96e955e','秋日臨幸祕書省因成近體詩一首賜丞相史浩以下','宋孝宗','宋','宋诗','song-poetry','','[]','玉軸牙籤煥寶章，簪紳侍列映秋光。',64,'全唐诗/poet.song.144000.json','["玉軸牙籤煥寶章，簪紳侍列映秋光。", "宴開芳閣儒風盛，坐對蓬山逸興長。", "稽古右文慚菲德，禮賢下士法前王。", "欲臻至治觀熙洽，更罄嘉謀爲贊襄。"]'),
('80ab7692-cadc-4b9f-9abc-120b8bf199ec','題周文矩合樂士女圖','宋孝宗','宋','宋诗','song-poetry','','[]','今夜調琴忽有情，欲彈惆悵憶崔卿。',32,'全唐诗/poet.song.144000.json','["今夜調琴忽有情，欲彈惆悵憶崔卿。", "何人解愛中徽上，秋思頭邊八九聲。"]'),
('212886bf-930a-408d-9c58-8a18cfcd65a1','題刁光胤畫冊 雙飛蛺蝶圖','宋孝宗','宋','宋诗','song-poetry','','[]','融融風日雜花開，一雨凋殘滿綠苔。',32,'全唐诗/poet.song.144000.json','["融融風日雜花開，一雨凋殘滿綠苔。", "倘有紅粧來拾翠，無端蝴蝶鬭飛來。"]'),
('88854d81-61a6-41d4-b0d8-37224bb5ee80','題刁光胤畫冊 五羊圖','宋孝宗','宋','宋诗','song-poetry','','[]','霜風不動節毛塵，同沐中原水草春。',32,'全唐诗/poet.song.144000.json','["霜風不動節毛塵，同沐中原水草春。", "蘇武還朝典屬國，一時高爵豈庸人。"]'),
('b6512c76-cb42-4b8b-aecf-914f91f74186','題刁光胤畫冊 葵石圖','宋孝宗','宋','宋诗','song-poetry','','[]','中央正色殊堪重，况復丹心向太陽。',32,'全唐诗/poet.song.144000.json','["中央正色殊堪重，况復丹心向太陽。", "可信化工深意在，只教此本染宮黄。"]'),
('1c52109e-b869-4b2b-84c5-de7c16069c0e','題刁光胤畫冊 雪松圖','宋孝宗','宋','宋诗','song-poetry','','[]','夢中衣褐定何祥，明眎由來世澤長。',32,'全唐诗/poet.song.144000.json','["夢中衣褐定何祥，明眎由來世澤長。", "誰擬前身是韓子，爲他毛穎著文章。"]'),
('4982c1e2-8cd7-43d4-9ffe-cfea69cad98a','題刁光胤畫冊 竹菊圖','宋孝宗','宋','宋诗','song-poetry','','[]','賦得閒情思獨工，想携巵酒對芳叢。',32,'全唐诗/poet.song.144000.json','["賦得閒情思獨工，想携巵酒對芳叢。", "鉛華不爲春爭艷，留得先生醉頰紅。"]'),
('13e77998-aaaf-4ee5-bae5-7bc1a5038a5b','題刁光胤畫冊 蜂蝶戲貓圖','宋孝宗','宋','宋诗','song-poetry','','[]','白澤形容玉兔毛，紛紛鼠輩命難逃。',32,'全唐诗/poet.song.144000.json','["白澤形容玉兔毛，紛紛鼠輩命難逃。", "後村詩與涪翁詠，未及崔公一議高。"]'),
('01c359b9-6525-44eb-93d1-c3a1d04c77b7','題刁光胤畫冊 雪裏山茶圖','宋孝宗','宋','宋诗','song-poetry','','[]','一枝殘雪照山城，春意原非復後生。',32,'全唐诗/poet.song.144000.json','["一枝殘雪照山城，春意原非復後生。", "羞把紅顔媚兒女，梅兄知我歲寒情。"]'),
('22b5649c-66ae-4463-8cf3-595516f129e1','題刁光胤畫冊 江南風景圖','宋孝宗','宋','宋诗','song-poetry','','[]','秋雨池塘透晚凉，蜻蜓飛處白蘋香。',32,'全唐诗/poet.song.144000.json','["秋雨池塘透晚凉，蜻蜓飛處白蘋香。", "江南風景堪圖畫，怪得先生一□長。"]'),
('55450454-9b25-4f7e-a20c-311811b9f79f','題刁光胤畫冊 雪景水仙圖','宋孝宗','宋','宋诗','song-poetry','','[]','黄冠翠帔玉爲姿，何處春風一見之。',32,'全唐诗/poet.song.144000.json','["黄冠翠帔玉爲姿，何處春風一見之。", "未到湘江清絕地，試看山谷老人詩。"]'),
('edc55a55-8b3c-48fd-87c1-e0e8427be33b','題刁光胤畫冊 芙蓉泉石圖','宋孝宗','宋','宋诗','song-poetry','','[]','託根不與鞠爲雙，歷盡霜風未肯降。',32,'全唐诗/poet.song.144000.json','["託根不與鞠爲雙，歷盡霜風未肯降。", "本自無心那有怨，年年清艷照秋江。"]'),
('26da87bc-a79e-420d-a110-2d6129e7902a','題皇雩山圖','宋孝宗','宋','宋诗','song-poetry','','[]','仙鵝飛去是何年，靈蹟猶存古嶺邊。',64,'全唐诗/poet.song.144000.json','["仙鵝飛去是何年，靈蹟猶存古嶺邊。", "藤老龍蟠疑護法，山幽禽語是逃禪。", "手攀古木身忘倦，口吸香泉骨欲仙。", "鄰叟不知唐世遠，猶言謝母舊因緣。"]'),
('be3c73f1-b285-4a36-bb8b-76884c785fdf','題張曲江像','宋孝宗','宋','宋诗','song-poetry','','[]','鹿入深宮花解愁，牛登高鼎餗傷休。',32,'全唐诗/poet.song.144000.json','["鹿入深宮花解愁，牛登高鼎餗傷休。", "當時若聽履霜語，豈到峩嵋山盡頭。"]'),
('a675badc-b0e6-4931-a0d0-10db0b15fb22','句  其一','宋孝宗','宋','宋诗','song-poetry','','[]','閭閻多勃鬰，有愧此閒身。',12,'全唐诗/poet.song.144000.json','["閭閻多勃鬰，有愧此閒身。"]'),
('8c897b17-9054-472c-86e4-0261b48f5083','句  其二','宋孝宗','宋','宋诗','song-poetry','','[]','稱此一天風月好，橘香酒熟待君來。',16,'全唐诗/poet.song.144000.json','["稱此一天風月好，橘香酒熟待君來。"]'),
('70cc3bda-dd34-452c-ba32-6b27c769b761','句  其三','宋孝宗','宋','宋诗','song-poetry','','[]','富貴必從勤苦得，男兒須讀五車書。',16,'全唐诗/poet.song.144000.json','["富貴必從勤苦得，男兒須讀五車書。"]'),
('04c28cb4-21b2-4421-9e2d-ded17a3a5109','句','鹿何','宋','宋诗','song-poetry','','[]','雞渡已符當日讖，龍溪仍見此時祥。',16,'全唐诗/poet.song.144000.json','["雞渡已符當日讖，龍溪仍見此時祥。"]'),
('acd8bacd-d2b8-47b4-9db6-9885c4a997f7','臨終頌','朱道人','宋','宋诗','song-poetry','','[]','我是殺心漢，從來無侶伴。',24,'全唐诗/poet.song.144000.json','["我是殺心漢，從來無侶伴。", "塵土不沾身，坐地教人看。"]'),
('ac9760cd-0b59-44be-b5cd-b4d13cbbd046','吳江懷古','胡元質','宋','宋诗','song-poetry','','[]','子胥今日委東流，吳國明朝亦古丘。',32,'全唐诗/poet.song.144000.json','["子胥今日委東流，吳國明朝亦古丘。", "大笑夫差諸將相，更無人解守蘇州。"]'),
('d8689c51-735a-4119-899d-053f1d54871d','紹興乙卯張安國爲右史明清與仲信兄梁舉善郭世禎李大正李泳多館於安國家春日諸友同遊西湖至普安寺於窗間得玉釵半股青蚨半文想是遊人歡洽所分偶遺之者各賦詩以紀其事','王明清','宋','宋诗','song-poetry','','["\u897f\u6e56"]','凄凉寶鈿初分際，愁絕清光欲破時。',32,'全唐诗/poet.song.144000.json','["凄凉寶鈿初分際，愁絕清光欲破時。", "留與人間作佳話，綠窗瓊戶老蛛絲。"]'),
('0519db79-845c-4824-b189-5a0572ab9889','武夷山','黄遹','宋','宋诗','song-poetry','','[]','閑將綠綺弄清音，招得青山作故人。',32,'全唐诗/poet.song.144000.json','["閑將綠綺弄清音，招得青山作故人。", "烟靄謾呈千樣巧，松篁長貢四時新。"]'),
('27a78a93-473c-44b9-a9f0-5e7172da97e1','南山堂','黄遹','宋','宋诗','song-poetry','','[]','幸然閉閣文書靜，何必銜杯笑語頻。',32,'全唐诗/poet.song.144000.json','["幸然閉閣文書靜，何必銜杯笑語頻。", "只把悠然無限意，散爲和氣萬家春。"]'),
('93d3a846-2884-42a0-9794-3a3e04c91853','深靜堂','葉抑','宋','宋诗','song-poetry','','[]','亂山蒼蒼溪曲盤，烟林漠漠風生寒。',128,'全唐诗/poet.song.144000.json','["亂山蒼蒼溪曲盤，烟林漠漠風生寒。", "地幽景絕豈易到，中隠蕭寺環峯巒。", "山僧淳樸寺亦古，築室爲堂蔽風雨。", "深靜豈與衆緣同，萬法不傳歸妙處。", "堂前流水自涓涓，屋外松篁不計年。", "衲子一念俱已盡，不數歲月明晦遷。", "我來茲堂息塵慮，終日忘形得深趣。", "明朝韁鎖西復東，謾寫微言題所寓。"]'),
('75eefcb6-0c0a-402e-bbbf-c17eb9cd1332','綠筠軒','葉抑','宋','宋诗','song-poetry','','[]','蕭蕭籜龍蒼且綠，直節凌雲長叢玉。',32,'全唐诗/poet.song.144000.json','["蕭蕭籜龍蒼且綠，直節凌雲長叢玉。", "高標自是絕塵埃，便使人間無點俗。"]'),
('37bcc519-9648-495b-a132-37895c5bbab2','昌州  其一','陳伯强','宋','宋诗','song-poetry','','[]','昌國古要區，人物屹相望。',24,'全唐诗/poet.song.144000.json','["昌國古要區，人物屹相望。", "功名刻高崖，粟帛賜滿箱。"]'),
('0ad78dbd-6ae3-48ff-b00d-d2b805c2461a','昌州  其二','陳伯强','宋','宋诗','song-poetry','','[]','東郊地軟橋路平，留得皇祐詩家名。',32,'全唐诗/poet.song.144000.json','["東郊地軟橋路平，留得皇祐詩家名。", "粟帛之賜豈數有，花柳向人空復情。"]'),
('d8853f35-b446-426d-95bb-79065f438e4c','句','陳伯强','宋','宋诗','song-poetry','','[]','丈人論行輩，高出五嶽列。',12,'全唐诗/poet.song.144000.json','["丈人論行輩，高出五嶽列。"]'),
('f8fb0149-c942-4223-9568-ea9cf68d09da','第一山','閻蒼舒','宋','宋诗','song-poetry','','[]','極目平淮渺莽間，翠巒特地起煙鬟。',32,'全唐诗/poet.song.144000.json','["極目平淮渺莽間，翠巒特地起煙鬟。", "要渠天下無雙手，題作東南第一山。"]'),
('bdc878b2-50db-48ba-be27-3b70e87853ef','興元','閻蒼舒','宋','宋诗','song-poetry','','[]','褒城之山劃天罅，中有深谷春水生。',32,'全唐诗/poet.song.144000.json','["褒城之山劃天罅，中有深谷春水生。", "漢家興王啟鴻業，蕭相治國留英聲。"]'),
('7f1be1a6-7e31-4a2d-aab7-67e9988fe3bb','海觀','閻蒼舒','宋','宋诗','song-poetry','','[]','雲南之陰大江東，二水奔騰如海衝。',32,'全唐诗/poet.song.144000.json','["雲南之陰大江東，二水奔騰如海衝。", "誰能具此壯觀眼，南定樓中今卧龍。"]'),
('ede46775-0676-4ad7-ad44-47533f62e677','登制勝樓次韻','閻蒼舒','宋','宋诗','song-poetry','','[]','百牢關下幾夔州，坐鎮休餘只倚樓。',64,'全唐诗/poet.song.144000.json','["百牢關下幾夔州，坐鎮休餘只倚樓。", "赤甲白鹽齊意氣，綸巾羽扇獨風流。", "夜間警柝拋金鎖，春樂熙臺醉玉舟。", "化國舒長公事少，眼中萬象固神搜。"]'),
('3a0355ae-b805-4de4-ad5b-fdd21d5603c1','贈郡帥郭侯','閻蒼舒','宋','宋诗','song-poetry','','[]','東南形勝惟揚州，介江負淮作襟喉。',224,'全唐诗/poet.song.144000.json','["東南形勝惟揚州，介江負淮作襟喉。", "有國以來幾百戰，弔古千載空悠悠。", "哀哉荒主與蕩子，鈍盡鐵劍崇倡優。", "迷樓九曲爛如畫，珠簾十里半上鉤。", "當年二十四橋月，曾照三十六宮秋。", "平山堂上一長嘆，但有衰草埋荒丘。", "歐仙蘇仙不可喚，江南江北無風流。", "何人復誦廣陵散，黯然悲恨不可收。", "只今英主正用武，增五萬竈屯貔貅。", "金城堅築壯營壘，綺段細錯良田疇。", "神謨廟算萬全舉，天時既至須人謀。", "將軍山西名將種，家聲直到青海頭。", "男兒有死必報國，正當爲上分此憂。", "勉旃速辦古人事，貂蟬本自出兜鍪。"]'),
('4def7a6d-feb4-4b5d-9a59-852bc9630bf5','梅林分韵賦詩得下字','施晉卿','宋','宋诗','song-poetry','','[]','郊原宿雨餘，雪重雲垂野。',216,'全唐诗/poet.song.144000.json','["郊原宿雨餘，雪重雲垂野。", "春信初動摇，欲往豈無駕。", "使君早著鞭，問路逢耕者。", "深尋烟雨村，共作詩酒社。", "庭荒六老樹，氣象自儼雅。", "一笑呼酒來，大盆注老瓦。", "最後看枯株，何意當大厦。", "夭矯待風雲，有年天寶假。", "須知羹鼎調，嘉寶係用舍。", "我欲壽使君，罇罍更傾瀉。", "明朝得楚騷，健甚無屈賈。", "君今有錫環，詔落九天下。", "蜀江雪浪來，棹趁船人把。", "留滯以諸生，斯文要陶冶。", "惟應郢中歌，倡絕和自寡。", "更聞督熊兒，夜賦燭餘灺。", "它年看無雙，聲譽出江夏。", "却笑昌黎公，阿買字能寫。"]'),
('00fe019b-80ce-436c-895a-8a070778b749','舫齋','鄧朴','宋','宋诗','song-poetry','','[]','悶悶之暑不可耐，走馬來尋靈跡怪。',144,'全唐诗/poet.song.144000.json','["悶悶之暑不可耐，走馬來尋靈跡怪。", "山深樹老龍屈蟠，洞闊雲寒鼠飛敗。", "嶄然角立九關鎖，勢鑠晴空生險隘。", "流泉奔蕩一聲雷，倒擘懸崖舞澎湃。", "上巖拖下水晶簾，下巖擊碎瑠瓈派。", "天風吹作六月寒，辟易精神心膽快。", "宜搜得此天下奇，恍然坐我神仙界。", "雖與金樽映翠杓，亦有山肴供晚嘬。", "解衣磅礴舞翠閣，筆端寫作詩中畫。"]'),
('7a5acefb-7445-4d75-ae01-401422fbbdc1','靈谷山','王益','宋','宋诗','song-poetry','','[]','靈谷神仙宅，言歸肆目新。',48,'全唐诗/poet.song.144000.json','["靈谷神仙宅，言歸肆目新。", "山光遠如畫，秋色老於人。", "世俗棋爭劫，人心海變塵。", "功成思范蠡，湖上一閑身。"]'),
('8cfe0a86-769c-481c-b35a-f0f099341474','題康濟泉','顔度','宋','宋诗','song-poetry','','[]','三年官事渾無補，一片丹心徹底真。',32,'全唐诗/poet.song.144000.json','["三年官事渾無補，一片丹心徹底真。", "更有靈康是知己，新泉爲我現津津。"]'),
('48fbeec8-352a-4a12-ae41-14e5eeac8f0c','冬至','顔度','宋','宋诗','song-poetry','','[]','至節家家講物儀，迎來送去費心機。',32,'全唐诗/poet.song.144000.json','["至節家家講物儀，迎來送去費心機。", "脚錢盡處渾閒事，原物多時却再歸。"]'),
('466a4b38-dda5-4402-9dde-dd8ed13f75a8','呈左律師','顔度','宋','宋诗','song-poetry','','[]','前輩高標說與誰，孤峯頂上路途迷。',32,'全唐诗/poet.song.144000.json','["前輩高標說與誰，孤峯頂上路途迷。", "如今一向隨流去，逐隊成羣步步低。"]'),
('8f88c86c-05b8-4335-bd62-f4e3a32c70c7','題盱眙第一山','鄭汝諧','宋','宋诗','song-poetry','','[]','忍恥包羞事北庭，奚奴得意管逢迎。',32,'全唐诗/poet.song.144000.json','["忍恥包羞事北庭，奚奴得意管逢迎。", "燕山有石無人勒，却向都梁記姓名。"]'),
('cf775c92-3aca-43da-adaa-aab1ac04987e','水南寺','鄭汝諧','宋','宋诗','song-poetry','','[]','徜徉水南寺，青山在指顧。',36,'全唐诗/poet.song.144000.json','["徜徉水南寺，青山在指顧。", "山中八洞列，天巧于此覷。", "誰謂寶方小，方是洞天數。"]'),
('be4716a0-cb1a-47b6-b1b8-56d3fbf0c110','題石門洞','鄭汝諧','宋','宋诗','song-poetry','','[]','每移征棹並雲根，便覺幽懷謝世喧。',64,'全唐诗/poet.song.144000.json','["每移征棹並雲根，便覺幽懷謝世喧。", "皓色飛來天際雪，紅塵不到水邊門。", "破荒康樂名猶在，紀勝元章字不存。", "但有好山容老子，何須更訪武陵源。"]'),
('5e5cc177-5e13-412d-8cd4-0a3f279f2930','憶羅浮寄曾元功二首  其一','張宋卿','宋','宋诗','song-poetry','','[]','當年南澗弄泉流，妄起功名分外求。',32,'全唐诗/poet.song.144000.json','["當年南澗弄泉流，妄起功名分外求。", "羣玉峯頭今倦立，却煩清夢到羅浮。"]'),
('77cc55f6-a249-4d89-b268-559732f8d4c5','憶羅浮寄曾元功二首  其二','張宋卿','宋','宋诗','song-poetry','','[]','春樹江雲我所思，平生臭味不差池。',32,'全唐诗/poet.song.144000.json','["春樹江雲我所思，平生臭味不差池。", "如何驛使行千里，不把梅花寄一枝。"]'),
('0f24ede7-15a7-4fd5-9a40-46750a658b23','天漢橋','張宋卿','宋','宋诗','song-poetry','','[]','一派銀河木杪飛，碧雲飛處彩虹垂。',32,'全唐诗/poet.song.144000.json','["一派銀河木杪飛，碧雲飛處彩虹垂。", "免教靈鵲長填石，來看天孫出嫁時。"]'),
('441fde98-d8d9-4d39-9b12-385563874927','句','吳己正','宋','宋诗','song-poetry','','[]','舉頭不忍看王十，回首猶欣見李三。',16,'全唐诗/poet.song.144000.json','["舉頭不忍看王十，回首猶欣見李三。"]');
